CREATE PROCEDURE `buat_dhkp_baru`(IN NOP VARCHAR (18), IN RT VARCHAR(3), IN RW VARCHAR(2), IN MIN_PAJAK BIGINT(20), IN MAX_PAJAK BIGINT(20), IN STATUS_BAYAR VARCHAR(3), IN TAHUN YEAR)
BEGIN
  DELETE FROM dhkp_baru_report;
  INSERT IGNORE INTO `dhkp_baru_report` (
    `KD_PROPINSI`,
    `KD_DATI2`,
    `KD_KECAMATAN`,
    `KD_KELURAHAN`,
    `KD_BLOK`,
    `NO_URUT`,
    `KD_JNS_OP`,
    `THN_PAJAK_SPPT`,
    `NM_WP_SPPT`,
    `LUAS_BUMI_SPPT`,
    `LUAS_BNG_SPPT`,
    `NJOP_BUMI_SPPT`,
    `NJOP_BNG_SPPT`,
    `NJOPTKP_SPPT`,
    `ALAMAT_WP_SPPT`,
    `ALAMAT_OP_SPPT`,
    `PBB_TERHUTANG`,
    ADA
  ) 
  SELECT 
    `KD_PROPINSI`,
    `KD_DATI2`,
    `KD_KECAMATAN`,
    `KD_KELURAHAN`,
    `KD_BLOK`,
    `NO_URUT`,
    `KD_JNS_OP`,
    `THN_PAJAK_SPPT`,
    `NM_WP_SPPT`,
    `LUAS_BUMI_SPPT`,
    `LUAS_BNG_SPPT`,
    `NJOP_BUMI_SPPT`,
    `NJOP_BNG_SPPT`,
    `NJOPTKP_SPPT`,
    CONCAT(
      IFNULL(`JLN_WP_SPPT`, ""),
      " ",
      IFNULL(sppt.`BLOK_KAV_NO_WP_SPPT`, ""),
      " RT ",
      IFNULL(sppt.`RT_WP_SPPT`, ""),
      " RW ",
      IFNULL(sppt.`RW_WP_SPPT`, "")
    ),
    CONCAT(
      IFNULL(spop.`JALAN_OP`, ""),
      " ",
      IFNULL(spop.`BLOK_KAV_NO_OP`, ""),
      " RT ",
      IFNULL(spop.`RT_OP`, ""),
      " RW ",
      IFNULL(spop.`RW_OP`, "")
    ),
    PBB_YG_HARUS_DIBAYAR_SPPT,
    0 
  FROM
    sppt 
    LEFT JOIN spop USING (
        `KD_PROPINSI`,
        `KD_DATI2`,
        `KD_KECAMATAN`,
        `KD_KELURAHAN`,
        `KD_BLOK`,
        `NO_URUT`,
        `KD_JNS_OP`
      ) 
  WHERE (
      sppt.KD_PROPINSI LIKE CONCAT('%', SUBSTRING(NOP, 1, 2), '%')
    ) 
    AND (
      sppt.KD_DATI2 LIKE CONCAT('%', SUBSTRING(NOP, 3, 2), '%')
    ) 
    AND (
      sppt.KD_KECAMATAN LIKE CONCAT('%', SUBSTRING(NOP, 5, 3), '%')
    ) 
    AND (
      sppt.KD_KELURAHAN LIKE CONCAT('%', SUBSTRING(NOP, 8, 3), '%')
    ) 
    AND (
      sppt.KD_BLOK LIKE CONCAT('%', SUBSTRING(NOP, 11, 3), '%')
    ) 
    AND (
      sppt.NO_URUT LIKE CONCAT('%', SUBSTRING(NOP, 14, 4), '%')
    ) 
    AND (
      sppt.KD_JNS_OP LIKE CONCAT('%', SUBSTRING(NOP, 18, 1), '%')
    ) 
    AND IFNULL(sppt.`RT_WP_SPPT`,"") LIKE CONCAT('%',RT,'%')
    AND IFNULL(sppt.`RW_WP_SPPT`,"") LIKE CONCAT('%',RW,'%')
    AND sppt.`PBB_YG_HARUS_DIBAYAR_SPPT` BETWEEN MIN_PAJAK AND MAX_PAJAK    
    AND sppt.`THN_PAJAK_SPPT` = TAHUN 
    AND sppt.`STATUS_PEMBAYARAN_SPPT` LIKE STATUS_BAYAR;
  UPDATE 
    dhkp_baru_report 
    INNER JOIN dhkp USING (
        `KD_PROPINSI`,
        `KD_DATI2`,
        `KD_KECAMATAN`,
        `KD_KELURAHAN`,
        `KD_BLOK`,
        `NO_URUT`,
        `KD_JNS_OP`,
        `THN_PAJAK_SPPT`
      ) SET ADA = 1 ;
END;
