CREATE PROCEDURE `buat_dhkp_perubahan`(IN TAHUN YEAR, IN PER_TANGGAL DATE)
BEGIN
  CALL buat_dhkp_baru ('', '', '', 0, 999999999999, '%%', TAHUN) ;
  DELETE 
  FROM
    dhkp_perubahan ;
  INSERT INTO dhkp_perubahan 
  SELECT 
    a.`KD_PROPINSI`,
    a.`KD_DATI2`,
    a.`KD_KECAMATAN`,
    a.`KD_KELURAHAN`,
    a.`KD_BLOK`,
    a.`NO_URUT`,
    a.`KD_JNS_OP`,
    a.`THN_PAJAK_SPPT`,
    'baru',
    a.`NM_WP_SPPT`,
    0,
    c.`PBB_YG_HARUS_DIBAYAR_SPPT`,
    c.`TGL_JATUH_TEMPO_SPPT`,
    SUM(
      IFNULL(b.`JML_SPPT_YG_DIBAYAR`, 0) - IFNULL(b.`DENDA_SPPT`, 0)
    ) AS POKOK_BAYAR,
    SUM(IFNULL(b.`DENDA_SPPT`, 0)) AS DENDA_BAYAR,
    SUM(
      IFNULL(b.`JML_SPPT_YG_DIBAYAR`, 0)
    ) AS TOTAL_BAYAR,
    DATE(b.TGL_PEMBAYARAN_SPPT) AS TANGGAL_BAYAR,
    `hitungDendaTanggal` (
      c.`PBB_YG_HARUS_DIBAYAR_SPPT`,
      PER_TANGGAL,
      c.TGL_JATUH_TEMPO_SPPT
    ) AS TOTAL_DENDA 
  FROM
    dhkp_baru_report a 
    LEFT JOIN pembayaran_sppt b 
      ON a.KD_PROPINSI = b.`KD_PROPINSI` 
      AND a.`KD_DATI2` = b.`KD_DATI2` 
      AND a.`KD_KECAMATAN` = b.`KD_KECAMATAN` 
      AND a.`KD_KELURAHAN` = b.`KD_KELURAHAN` 
      AND a.`KD_BLOK` = b.`KD_BLOK` 
      AND a.`NO_URUT` = b.`NO_URUT` 
      AND a.`KD_JNS_OP` = b.`KD_JNS_OP` 
      AND a.`THN_PAJAK_SPPT` = b.`THN_PAJAK_SPPT` 
      AND b.`TGL_PEMBAYARAN_SPPT` < PER_TANGGAL 
    JOIN sppt c 
      ON a.`KD_PROPINSI` = c.`KD_PROPINSI` 
      AND a.`KD_DATI2` = c.`KD_DATI2` 
      AND a.`KD_KECAMATAN` = c.`KD_KECAMATAN` 
      AND a.`KD_KELURAHAN` = c.`KD_KELURAHAN` 
      AND a.`KD_BLOK` = c.`KD_BLOK` 
      AND a.`NO_URUT` = c.`NO_URUT` 
      AND a.`KD_JNS_OP` = c.`KD_JNS_OP` 
      AND a.`THN_PAJAK_SPPT` = c.`THN_PAJAK_SPPT` 
  WHERE a.`THN_PAJAK_SPPT` = TAHUN 
    AND ADA = 0 
  GROUP BY a.`KD_PROPINSI`,
    a.`KD_DATI2`,
    a.`KD_KECAMATAN`,
    a.`KD_KELURAHAN`,
    a.`KD_BLOK`,
    a.`NO_URUT`,
    a.`KD_JNS_OP`,
    a.`THN_PAJAK_SPPT` ;
  INSERT INTO dhkp_perubahan 
  SELECT 
    a.`KD_PROPINSI`,
    a.`KD_DATI2`,
    a.`KD_KECAMATAN`,
    a.`KD_KELURAHAN`,
    a.`KD_BLOK`,
    a.`NO_URUT`,
    a.`KD_JNS_OP`,
    a.`THN_PAJAK_SPPT`,
    'perubahan',
    a.`NM_WP_SPPT`,
    a.`PBB_TERHUTANG`,
    b.`PBB_YG_HARUS_DIBAYAR_SPPT`,
    b.`TGL_JATUH_TEMPO_SPPT`,
    SUM(
      IFNULL(c.`JML_SPPT_YG_DIBAYAR`, 0) - IFNULL(c.`DENDA_SPPT`, 0)
    ) AS POKOK_BAYAR,
    SUM(IFNULL(c.`DENDA_SPPT`, 0)) AS DENDA_BAYAR,
    SUM(
      IFNULL(c.`JML_SPPT_YG_DIBAYAR`, 0)
    ) AS TOTAL_BAYAR,
    GROUP_CONCAT(c.TGL_PEMBAYARAN_SPPT) AS TANGGAL_BAYAR,
    `hitungDendaTanggal` (
      b.`PBB_YG_HARUS_DIBAYAR_SPPT`,
      PER_TANGGAL,
      b.TGL_JATUH_TEMPO_SPPT
    ) AS TOTAL_DENDA 
  FROM
    dhkp a 
    JOIN sppt b 
      ON a.KD_PROPINSI = b.`KD_PROPINSI` 
      AND a.`KD_DATI2` = b.`KD_DATI2` 
      AND a.`KD_KECAMATAN` = b.`KD_KECAMATAN` 
      AND a.`KD_KELURAHAN` = b.`KD_KELURAHAN` 
      AND a.`KD_BLOK` = b.`KD_BLOK` 
      AND a.`NO_URUT` = b.`NO_URUT` 
      AND a.`KD_JNS_OP` = b.`KD_JNS_OP` 
      AND a.`THN_PAJAK_SPPT` = b.`THN_PAJAK_SPPT` 
      AND a.`PBB_TERHUTANG` <> b.`PBB_YG_HARUS_DIBAYAR_SPPT` 
    LEFT JOIN pembayaran_sppt c 
      ON a.KD_PROPINSI = c.`KD_PROPINSI` 
      AND a.`KD_DATI2` = c.`KD_DATI2` 
      AND a.`KD_KECAMATAN` = c.`KD_KECAMATAN` 
      AND a.`KD_KELURAHAN` = c.`KD_KELURAHAN` 
      AND a.`KD_BLOK` = c.`KD_BLOK` 
      AND a.`NO_URUT` = c.`NO_URUT` 
      AND a.`KD_JNS_OP` = c.`KD_JNS_OP` 
      AND a.`THN_PAJAK_SPPT` = c.`THN_PAJAK_SPPT` 
      AND c.`TGL_PEMBAYARAN_SPPT` < PER_TANGGAL 
  WHERE a.`THN_PAJAK_SPPT` = TAHUN 
  GROUP BY a.`KD_PROPINSI`,
    a.`KD_DATI2`,
    a.`KD_KECAMATAN`,
    a.`KD_KELURAHAN`,
    a.`KD_BLOK`,
    a.`NO_URUT`,
    a.`KD_JNS_OP`,
    a.`THN_PAJAK_SPPT` ;
  UPDATE dhkp_perubahan SET TANGGAL_BAYAR = NULL WHERE TANGGAL_BAYAR = '0000-00-00';
END;
