CREATE PROCEDURE `buat_dhr`(IN NOP VARCHAR (18))
BEGIN
  DELETE 
  FROM
    dhr ;
  INSERT INTO `dhr` (
    `KD_PROPINSI`,
    `KD_DATI2`,
    `KD_KECAMATAN`,
    `KD_KELURAHAN`,
    `KD_BLOK`,
    `NO_URUT`,
    `KD_JNS_OP`,
    `NO_BNG`,
    KD_JPB,
    `NM_WP`,
    `ALAMAT_WP`,
    `ALAMAT_OP`,
    `LUAS_BUMI`,
    `LUAS_BNG`,
    `KD_ZNT`,
    `KELAS_BUMI`,
    `KELAS_BNG`,
    `JNS_BUMI`,
    `JNS_TRANSAKSI`,
    `LSPOP_THN_BNG`,
    `LSPOP_JML_LT`,
    `LSPOP_THN_RENOV`,
    `LSPOP_KONDISI`,
    `LSPOP_KONSTRUKSI`,
    `LSPOP_ATAP`,
    `LSPOP_DINDING`,
    `LSPOP_LANTAI`,
    `LSPOP_LANGIT`,
    `JML_PAJAK`
  ) 
  SELECT 
    spop.`KD_PROPINSI`,
    spop.`KD_DATI2`,
    spop.`KD_KECAMATAN`,
    spop.`KD_KELURAHAN`,
    spop.`KD_BLOK`,
    spop.`NO_URUT`,
    spop.`KD_JNS_OP`,
    lspop.`NO_BNG`,
    lspop.`KD_JPB`,
    dat_subjek_pajak.`NM_WP`,
    CONCAT(
      IFNULL(dat_subjek_pajak.`JALAN_WP`, ""),
      " ",
      IFNULL(
        dat_subjek_pajak.`BLOK_KAV_NO_WP`,
        ""
      ),
      " RT ",
      IFNULL(dat_subjek_pajak.`RT_WP`, ""),
      " RW ",
      IFNULL(dat_subjek_pajak.`RW_WP`, "")
    ) AS ALAMAT_WP,
    CONCAT(
      IFNULL(spop.`JALAN_OP`, ""),
      " ",
      IFNULL(spop.`BLOK_KAV_NO_OP`, ""),
      " RT ",
      IFNULL(spop.`RT_OP`, ""),
      " RW ",
      IFNULL(spop.`RW_OP`, "")
    ) AS ALAMAT_OP,
    spop.`LUAS_BUMI`,
    lspop.`LUAS_BNG`,
    spop.`KD_ZNT`,
    sppt.`KD_KLS_TANAH`,
    sppt.`KD_KLS_BNG`,
    spop.`JNS_BUMI`,
    spop.`JNS_TRANSAKSI_OP`,
    lspop.`THN_DIBANGUN_BNG`,
    lspop.`JML_LANTAI_BNG`,
    lspop.`THN_RENOVASI_BNG`,
    lspop.`KONDISI_BNG`,
    lspop.`JNS_KONSTRUKSI_BNG`,
    lspop.`JNS_ATAP_BNG`,
    lspop.`KD_DINDING`,
    lspop.`KD_LANTAI`,
    lspop.`KD_LANGIT_LANGIT`,
    sppt.`PBB_YG_HARUS_DIBAYAR_SPPT` 
  FROM
    spop 
    LEFT JOIN lspop USING (
        KD_PROPINSI,
        KD_DATI2,
        KD_KECAMATAN,
        KD_KELURAHAN,
        KD_BLOK,
        NO_URUT,
        KD_JNS_OP
      ) 
    LEFT JOIN dat_subjek_pajak USING (SUBJEK_PAJAK_ID) 
    LEFT JOIN sppt USING (
        KD_PROPINSI,
        KD_DATI2,
        KD_KECAMATAN,
        KD_KELURAHAN,
        KD_BLOK,
        NO_URUT,
        KD_JNS_OP
      ) 
  WHERE (
      spop.KD_PROPINSI LIKE CONCAT('%', SUBSTRING(NOP, 1, 2), '%')
    ) 
    AND (
      spop.KD_DATI2 LIKE CONCAT('%', SUBSTRING(NOP, 3, 2), '%')
    ) 
    AND (
      spop.KD_KECAMATAN LIKE CONCAT('%', SUBSTRING(NOP, 5, 3), '%')
    ) 
    AND (
      spop.KD_KELURAHAN LIKE CONCAT('%', SUBSTRING(NOP, 8, 3), '%')
    ) 
    AND (
      spop.KD_BLOK LIKE CONCAT('%', SUBSTRING(NOP, 11, 3), '%')
    ) 
    AND (
      spop.NO_URUT LIKE CONCAT('%', SUBSTRING(NOP, 14, 4), '%')
    ) 
    AND (
      spop.KD_JNS_OP LIKE CONCAT('%', SUBSTRING(NOP, 18, 1), '%')
    ) 
    AND sppt.`THN_PAJAK_SPPT` = YEAR(NOW()) 
  ORDER BY KD_PROPINSI,
    KD_DATI2,
    KD_KECAMATAN,
    KD_KELURAHAN,
    KD_BLOK,
    NO_URUT,
    KD_JNS_OP ;
  UPDATE 
    dhr 
    LEFT JOIN dat_fasilitas_bangunan USING (
        KD_PROPINSI,
        KD_DATI2,
        KD_KECAMATAN,
        KD_KELURAHAN,
        KD_BLOK,
        NO_URUT,
        KD_JNS_OP,
        NO_BNG
      ) SET dhr.`LSPOP_LISTRIK` = dat_fasilitas_bangunan.`JML_SATUAN` 
  WHERE dat_fasilitas_bangunan.`KD_FASILITAS` = '44' ;
  UPDATE 
    dhr 
    LEFT JOIN dat_fasilitas_bangunan USING (
        KD_PROPINSI,
        KD_DATI2,
        KD_KECAMATAN,
        KD_KELURAHAN,
        KD_BLOK,
        NO_URUT,
        KD_JNS_OP,
        NO_BNG
      ) SET dhr.`LSPOP_AC_SPLIT` = dat_fasilitas_bangunan.`JML_SATUAN` 
  WHERE dat_fasilitas_bangunan.`KD_FASILITAS` = '01' ;
  UPDATE 
    dhr 
    LEFT JOIN dat_fasilitas_bangunan USING (
        KD_PROPINSI,
        KD_DATI2,
        KD_KECAMATAN,
        KD_KELURAHAN,
        KD_BLOK,
        NO_URUT,
        KD_JNS_OP,
        NO_BNG
      ) SET dhr.`LSPOP_AC_WINDOW` = dat_fasilitas_bangunan.`JML_SATUAN` 
  WHERE dat_fasilitas_bangunan.`KD_FASILITAS` = '02' ;
  UPDATE 
    dhr 
    LEFT JOIN dat_fasilitas_bangunan USING (
        KD_PROPINSI,
        KD_DATI2,
        KD_KECAMATAN,
        KD_KELURAHAN,
        KD_BLOK,
        NO_URUT,
        KD_JNS_OP,
        NO_BNG
      ) SET dhr.`LSPOP_AC_SENTRAL` = dat_fasilitas_bangunan.`JML_SATUAN` 
  WHERE dat_fasilitas_bangunan.`KD_FASILITAS` = '03' ;
  UPDATE 
    dhr 
    LEFT JOIN dat_fasilitas_bangunan USING (
        KD_PROPINSI,
        KD_DATI2,
        KD_KECAMATAN,
        KD_KELURAHAN,
        KD_BLOK,
        NO_URUT,
        KD_JNS_OP,
        NO_BNG
      ) SET dhr.`LSPOP_POOL_PLASTER` = dat_fasilitas_bangunan.`JML_SATUAN` 
  WHERE dat_fasilitas_bangunan.`KD_FASILITAS` = '12' ;
  UPDATE 
    dhr 
    LEFT JOIN dat_fasilitas_bangunan USING (
        KD_PROPINSI,
        KD_DATI2,
        KD_KECAMATAN,
        KD_KELURAHAN,
        KD_BLOK,
        NO_URUT,
        KD_JNS_OP,
        NO_BNG
      ) SET dhr.`LSPOP_POOL_PELAPIS` = dat_fasilitas_bangunan.`JML_SATUAN` 
  WHERE dat_fasilitas_bangunan.`KD_FASILITAS` = '13' ;
  UPDATE 
    dhr 
    LEFT JOIN dat_fasilitas_bangunan USING (
        KD_PROPINSI,
        KD_DATI2,
        KD_KECAMATAN,
        KD_KELURAHAN,
        KD_BLOK,
        NO_URUT,
        KD_JNS_OP,
        NO_BNG
      ) SET dhr.`LSPOP_PAGAR_BAJA` = dat_fasilitas_bangunan.`JML_SATUAN` 
  WHERE dat_fasilitas_bangunan.`KD_FASILITAS` = '35' ;
  UPDATE 
    dhr 
    LEFT JOIN dat_fasilitas_bangunan USING (
        KD_PROPINSI,
        KD_DATI2,
        KD_KECAMATAN,
        KD_KELURAHAN,
        KD_BLOK,
        NO_URUT,
        KD_JNS_OP,
        NO_BNG
      ) SET dhr.`LSPOP_PAGAR_BATA` = dat_fasilitas_bangunan.`JML_SATUAN` 
  WHERE dat_fasilitas_bangunan.`KD_FASILITAS` = '36' ;
  UPDATE 
    dhr 
    LEFT JOIN dat_fasilitas_bangunan USING (
        KD_PROPINSI,
        KD_DATI2,
        KD_KECAMATAN,
        KD_KELURAHAN,
        KD_BLOK,
        NO_URUT,
        KD_JNS_OP,
        NO_BNG
      ) SET dhr.`LSPOP_SUMUR` = dat_fasilitas_bangunan.`JML_SATUAN` 
  WHERE dat_fasilitas_bangunan.`KD_FASILITAS` = '42' ;
END;
