DROP PROCEDURE IF EXISTS `cari_data`;
--> statement-breakpoint
CREATE PROCEDURE `cari_data`(IN `valKD_PROPINSI` VARCHAR(2), IN `valKD_DATI2` VARCHAR(2), IN `valKD_KECAMATAN` VARCHAR(3), IN `valKD_KELURAHAN` VARCHAR(3), IN `valKD_BLOK` VARCHAR(3), IN `valNO_URUT` VARCHAR(4), IN `valKD_JNS_OP` VARCHAR(1), IN `valNAMA_WP` VARCHAR(50), IN `valJALAN_OP` VARCHAR(50))
BEGIN
SELECT
CONCAT(KD_PROPINSI, '.', KD_DATI2, '.', KD_KECAMATAN, '.', KD_KELURAHAN, '.', KD_BLOK, '.', NO_URUT, '.', KD_JNS_OP) AS NOP,
NM_WP, 
JALAN_OP,
COUNT(NO_BNG) AS JML_BNG,
IF(JNS_TRANSAKSI_OP='1', 'Baru', IF(JNS_TRANSAKSI_OP='2', 'Pemutakhiran', 'Terhapus')) AS STATUS
FROM  
spop LEFT JOIN 
lspop USING(KD_PROPINSI, KD_DATI2, KD_KECAMATAN, KD_KELURAHAN, KD_BLOK, NO_URUT, KD_JNS_OP) LEFT JOIN 
dat_subjek_pajak USING(SUBJEK_PAJAK_ID)
WHERE
(KD_PROPINSI = valKD_PROPINSI) AND
(KD_DATI2 = valKD_DATI2) AND 
(KD_KECAMATAN = valKD_KECAMATAN) AND 
(KD_KELURAHAN = valKD_KELURAHAN) AND 
(KD_BLOK LIKE valKD_BLOK) AND 
(NO_URUT LIKE valNO_URUT) AND 
(KD_JNS_OP LIKE valKD_JNS_OP) AND
(NM_WP LIKE valNAMA_WP) AND
(JALAN_OP LIKE valJALAN_OP)
GROUP BY KD_PROPINSI, KD_DATI2, KD_KECAMATAN, KD_KELURAHAN, KD_BLOK, NO_URUT, KD_JNS_OP;
END;
--> statement-breakpoint

DROP PROCEDURE IF EXISTS `cari_pelayanan_nama`;
--> statement-breakpoint
CREATE PROCEDURE `cari_pelayanan_nama`(IN valNAMA VARCHAR(20))
BEGIN
	SELECT 
	  pelayanan.NO_PELAYANAN,
	  pelayanan.KD_PROPINSI,
	  pelayanan.KD_DATI2,
	  pelayanan.KD_KECAMATAN,
	  pelayanan.KD_KELURAHAN,
	  pelayanan.KD_BLOK,
	  pelayanan.NO_URUT,
	  pelayanan.KD_JNS_OP,
	  pelayanan.NAMA_PEMOHON,
	  ref_jns_pelayanan.NM_JENIS_PELAYANAN 
	FROM
	  pelayanan 
	  LEFT JOIN pelayanan_lampiran_kolektif 
	    ON pelayanan_lampiran_kolektif.NO_PELAYANAN = pelayanan.NO_PELAYANAN 
	  LEFT JOIN ref_jns_pelayanan
	    ON ref_jns_pelayanan.KD_JNS_PELAYANAN = pelayanan.KD_JNS_PELAYANAN
	WHERE pelayanan.NAMA_PEMOHON like CONCAT('%', valNAMA , '%')
	GROUP BY pelayanan.NO_PELAYANAN;
END;
