CREATE PROCEDURE `cari_pelayanan_nop`(IN `valKD_PROPINSI` VARCHAR(2), IN `valKD_DATI2` VARCHAR(2), IN `valKD_KECAMATAN` VARCHAR(3), IN `valKD_KELURAHAN` VARCHAR(3), IN `valKD_BLOK` VARCHAR(3), IN `valNO_URUT` VARCHAR(4), IN `valKD_JNS_OP` VARCHAR(1))
BEGIN
	SELECT 
	  pelayanan.NO_PELAYANAN,
	  pelayanan.KD_PROPINSI,
	  pelayanan.KD_DATI2,
	  pelayanan.KD_KECAMATAN,
	  pelayanan.KD_KELURAHAN,
	  pelayanan.KD_BLOK,
	  pelayanan.NO_URUT,
	  pelayanan.KD_JNS_OP,
	  pelayanan.NAMA_PEMOHON,
	  ref_jns_pelayanan.NM_JENIS_PELAYANAN 
	FROM
	  pelayanan 
	  LEFT JOIN pelayanan_lampiran_kolektif 
	    ON pelayanan_lampiran_kolektif.NO_PELAYANAN = pelayanan.NO_PELAYANAN 
	  LEFT JOIN ref_jns_pelayanan
	    ON ref_jns_pelayanan.KD_JNS_PELAYANAN = pelayanan.KD_JNS_PELAYANAN
	WHERE pelayanan.KD_PROPINSI = valKD_PROPINSI
	AND pelayanan.KD_DATI2 = valKD_DATI2
	AND pelayanan.KD_KECAMATAN = valKD_KECAMATAN
	AND pelayanan.KD_KELURAHAN = valKD_KELURAHAN
	AND pelayanan.KD_BLOK = valKD_BLOK
	AND pelayanan.NO_URUT = valNO_URUT
	AND pelayanan.KD_JNS_OP = valKD_JNS_OP
	GROUP BY pelayanan.NO_PELAYANAN;
END;
