DROP PROCEDURE IF EXISTS `CreatePiutang`;
--> statement-breakpoint
CREATE PROCEDURE `CreatePiutang`(IN `TAHUN` YEAR)
BEGIN
UPDATE 
  t_piutang 
  INNER JOIN sppt USING (
      KD_PROPINSI,
      KD_DATI2,
      KD_KECAMATAN,
      KD_KELURAHAN,
      KD_BLOK,
      NO_URUT,
      KD_JNS_OP
    ) SET t_piutang.`KETETAPAN` = sppt.`PBB_YG_HARUS_DIBAYAR_SPPT` 
WHERE sppt.`THN_PAJAK_SPPT` = TAHUN ;
DELETE FROM t_pembayaran;
INSERT INTO t_pembayaran 
SELECT 
  KD_PROPINSI,
  KD_DATI2,
  KD_KECAMATAN,
  KD_KELURAHAN,
  KD_BLOK,
  NO_URUT,
  KD_JNS_OP,
  TAHUN,
  SUM(
    pembayaran_sppt.`JML_SPPT_YG_DIBAYAR`
  ) 
FROM
  pembayaran_sppt 
WHERE THN_PAJAK_SPPT = TAHUN 
GROUP BY KD_PROPINSI,
  KD_DATI2,
  KD_KECAMATAN,
  KD_KELURAHAN,
  KD_BLOK,
  NO_URUT,
  KD_JNS_OP ;
  
  
UPDATE 
  t_piutang 
  INNER JOIN t_pembayaran USING (
      KD_PROPINSI,
      KD_DATI2,
      KD_KECAMATAN,
      KD_KELURAHAN,
      KD_BLOK,
      NO_URUT,
      KD_JNS_OP
    ) SET t_piutang.`PELUNASAN` = t_pembayaran.`PEMBAYARAN` ;
UPDATE 
  t_piutang 
  INNER JOIN 
    (SELECT 
      KD_PROPINSI,
      KD_DATI2,
      KD_KECAMATAN,
      KD_KELURAHAN,
      KD_BLOK,
      NO_URUT,
      KD_JNS_OP,
      SUM(t_penyesuaian.`PENYESUAIAN`) AS tot_penyesuaian 
    FROM
      t_penyesuaian 
    GROUP BY KD_PROPINSI,
      KD_DATI2,
      KD_KECAMATAN,
      KD_KELURAHAN,
      KD_BLOK,
      NO_URUT,
      KD_JNS_OP) AS a 
    ON t_piutang.`KD_PROPINSI` = a.`KD_PROPINSI` 
    AND t_piutang.`KD_DATI2` = a.`KD_DATI2` 
    AND t_piutang.`KD_KECAMATAN` = a.`KD_KECAMATAN` 
    AND t_piutang.`KD_KELURAHAN` = a.`KD_KELURAHAN` 
    AND t_piutang.`KD_BLOK` = a.`KD_BLOK` 
    AND t_piutang.`NO_URUT` = a.`NO_URUT` 
    AND t_piutang.`KD_JNS_OP` = a.`KD_JNS_OP` SET t_piutang.`PENYESUAIAN` = a.tot_penyesuaian ;
UPDATE 
  t_piutang 
SET
  KETETAPAN = 0 
WHERE KETETAPAN IS NULL ;
UPDATE 
  t_piutang 
SET
  JUMLAH = 0 
WHERE JUMLAH IS NULL ;
UPDATE 
  t_piutang 
SET
  PELUNASAN = 0 
WHERE PELUNASAN IS NULL ;
UPDATE 
  t_piutang 
SET
  PIUTANG_BERJALAN = 0 
WHERE PIUTANG_BERJALAN IS NULL ;
UPDATE 
  t_piutang 
SET
  LEBIH_BAYAR = 0 
WHERE LEBIH_BAYAR IS NULL ;
    
UPDATE 
  t_piutang 
SET
  t_piutang.`SALDO_PENYESUAIAN` = t_piutang.`PIUTANG_TERAKHIR` - PENYESUAIAN ;
UPDATE 
  t_piutang 
SET
  t_piutang.`JUMLAH` = t_piutang.`SALDO_PENYESUAIAN` + t_piutang.`KETETAPAN` ;
UPDATE 
  t_piutang 
SET
  t_piutang.`PIUTANG_BERJALAN` = t_piutang.`JUMLAH` - t_piutang.`PELUNASAN` ;
UPDATE 
  t_piutang 
SET
  t_piutang.`LEBIH_BAYAR` = IF(
    t_piutang.`PELUNASAN` - t_piutang.`KETETAPAN` < 0,
    0,
    t_piutang.`PELUNASAN` - t_piutang.`KETETAPAN`
  );
    END;
