DROP PROCEDURE IF EXISTS `FASILITAS_SUSUT`;
--> statement-breakpoint
CREATE PROCEDURE `FASILITAS_SUSUT`(IN  vlc_kd_propinsi     CHAR(2),
IN  vlc_kd_dati2        CHAR(2),
IN  vlc_kd_kecamatan    CHAR(3),
IN  vlc_kd_kelurahan    CHAR(3),
IN  vlc_kd_blok         CHAR(3),
IN  vlc_no_urut         CHAR(4),
IN  vlc_kd_jns_op       CHAR(1),
IN  vln_no_bng          SMALLINT,
IN  vln_jml_lantai_bng  SMALLINT,
IN  vlc_tahun           VARCHAR(4000),
OUT vln_nilai_fasilitas INT)
BEGIN
   DECLARE vln_jml_satuan INT DEFAULT 0;
   DECLARE vlc_kd_fasilitas CHAR(2);
   DECLARE vlc_ketergantungan CHAR(1);
   DECLARE vln_nilai_satuan DECIMAL(10,2) DEFAULT 0;
   DECLARE NO_DATA INT DEFAULT 0;
   DECLARE curbiayafasilitas CURSOR FOR SELECT kd_fasilitas, ketergantungan
   FROM   fasilitas
   WHERE  status_fasilitas = '4';
   DECLARE CONTINUE HANDLER FOR NOT FOUND SET NO_DATA = -1;
/*OLEH : TEGUH
TANGGAL     :
REVISI KE   : 1
DIREVISI    : TEGUH - RACHMAT
TGL. REVISI : 05-10-2000
*/-- ------------------
   SET vln_nilai_fasilitas = 0;
   OPEN curbiayafasilitas;
   SWL_Label:
   LOOP
      SET NO_DATA = 0;
      FETCH curbiayafasilitas INTO vlc_kd_fasilitas,vlc_ketergantungan;
      IF NO_DATA <> 0 THEN
         LEAVE SWL_Label;
      END IF;
      BEGIN
         DECLARE EXIT HANDLER FOR NOT FOUND
         begin
            SET vln_jml_satuan = 0;
         end;
         SELECT IFNULL(jml_satuan,0) INTO vln_jml_satuan
         FROM   dat_fasilitas_bangunan
         WHERE  kd_propinsi  = vlc_kd_propinsi  AND
         kd_dati2     = vlc_kd_dati2	  	AND
         kd_kecamatan = vlc_kd_kecamatan AND
         kd_kelurahan = vlc_kd_kelurahan AND
         kd_blok      = vlc_kd_blok      AND
         no_urut      = vlc_no_urut  	  AND
         kd_jns_op    = vlc_kd_jns_op    AND
         no_bng       = vln_no_bng       AND
         kd_fasilitas = vlc_kd_fasilitas;
      END;
      IF vlc_ketergantungan = '0' THEN
         BEGIN
            DECLARE EXIT HANDLER FOR NOT FOUND
            begin
               SET vln_nilai_satuan = 0;
            end;
            SELECT IFNULL(nilai_non_dep,0) INTO vln_nilai_satuan
            FROM   fas_non_dep
            WHERE  kd_propinsi  = vlc_kd_propinsi  AND
            kd_dati2     = vlc_kd_dati2     AND
            thn_non_dep  = vlc_tahun        AND
            kd_fasilitas = vlc_kd_fasilitas;
         END;
      ELSEIF vlc_ketergantungan = '1' THEN
         IF vlc_kd_fasilitas IN('30','31','32') THEN
            BEGIN
               DECLARE EXIT HANDLER FOR NOT FOUND
               begin
                  SET vln_nilai_satuan = 0;
               end;
               SELECT IFNULL(nilai_dep_min_max,0) INTO vln_nilai_satuan
               FROM   fas_dep_min_max
               WHERE  kd_propinsi     = vlc_kd_propinsi           AND
               kd_dati2        = vlc_kd_dati2              AND
               thn_dep_min_max = vlc_tahun                 AND
               kd_fasilitas    = vlc_kd_fasilitas          AND
               kls_dep_min    <= IFNULL(vln_jml_lantai_bng,0) AND
               kls_dep_max    >= IFNULL(vln_jml_lantai_bng,0);
            END;
      ELSE
            BEGIN
               DECLARE EXIT HANDLER FOR NOT FOUND
               begin
                  SET vln_nilai_satuan = 0;
               end;
               SELECT IFNULL(nilai_dep_min_max,0) INTO vln_nilai_satuan
               FROM   fas_dep_min_max
               WHERE  kd_propinsi     = vlc_kd_propinsi   AND
               kd_dati2        = vlc_kd_dati2      AND
               thn_dep_min_max = vlc_tahun         AND
               kd_fasilitas    = vlc_kd_fasilitas  AND
               kls_dep_min    <= vln_jml_satuan    AND
               kls_dep_max    >= vln_jml_satuan;
            END;
         END IF;
      ELSE 
         SET vln_nilai_satuan = 0;
      END IF;
      SET vln_nilai_fasilitas = vln_nilai_fasilitas+(vln_nilai_satuan*vln_jml_satuan);
   END LOOP;
   CLOSE curbiayafasilitas;
END;
--> statement-breakpoint

DROP PROCEDURE IF EXISTS `FASILITAS_SUSUT_X_LUAS`;
--> statement-breakpoint
CREATE PROCEDURE `FASILITAS_SUSUT_X_LUAS`(IN  vlc_kd_prop 	   CHAR(2),
IN  vlc_kd_dati2    CHAR(2),
IN  vlc_kd_kec 	   CHAR(3),
IN  vlc_kd_kel 	   CHAR(3),
IN  vlc_kd_blok 	   CHAR(3),
IN  vlc_no_urut 	   CHAR(4),
IN  vlc_kd_jns_op   CHAR(1),
IN  vlc_no_bng 	   SMALLINT,
IN  vlc_kd_jpb      CHAR(2),
IN  vlc_kls_bintang CHAR(4),
IN  vlc_tahun 	   CHAR(4),
OUT vln_fasilitas   BIGINT)
BEGIN
   DECLARE vlc_kd_fasilitas CHAR(2);
   DECLARE vln_jml_satuan INT;
   DECLARE vlc_kd_status CHAR(1);
   DECLARE vlc_ketergantungan CHAR(1);
   DECLARE vln_nilai DECIMAL(10,2);
   DECLARE vln_nilai_fas BIGINT;
   DECLARE NO_DATA INT DEFAULT 0;
   DECLARE SWV_c_fas1_kd_fasilitas VARCHAR(255);
   DECLARE SWV_c_fas1_jml_satuan VARCHAR(255);
   DECLARE SWV_c_fas1_status_fasilitas VARCHAR(255);
   DECLARE SWV_c_fas1_ketergantungan VARCHAR(255);
   DECLARE c_fas1 CURSOR FOR select a.kd_fasilitas     kd_fasilitas,
a.jml_satuan 		jml_satuan,
b.status_fasilitas status_fasilitas,
b.ketergantungan 	ketergantungan
   from 	 dat_fasilitas_bangunan a,
fasilitas b
   where  a.kd_propinsi   = vlc_kd_prop    AND
   a.kd_dati2 	 = vlc_kd_dati2   AND
   a.kd_kecamatan  = vlc_kd_kec  	  AND
   a.kd_kelurahan  = vlc_kd_kel  	  AND
   a.kd_blok 		 = vlc_kd_blok    AND
   a.no_urut 		 = vlc_no_urut    AND
   a.kd_jns_op  	 = vlc_kd_jns_op  AND
   a.no_bng 		 = vlc_no_bng  	  AND
   b.kd_fasilitas  = a.kd_fasilitas AND
   b.status_fasilitas  = '0';
   DECLARE CONTINUE HANDLER FOR NOT FOUND SET NO_DATA = -1;
/*OLEH : SUNARYO
TANGGAL     :
REVISI KE   : 1
DIREVISI    : TEGUH - RACHMAT
TGL. REVISI : 05-10-2000
*/-- ------------------
   SET vln_nilai_fas = 0;
   OPEN c_fas1;
   SET NO_DATA = 0;
   FETCH c_fas1 INTO SWV_c_fas1_kd_fasilitas,SWV_c_fas1_jml_satuan,SWV_c_fas1_status_fasilitas,
   SWV_c_fas1_ketergantungan;
   WHILE NO_DATA = 0 DO
      IF SWV_c_fas1_ketergantungan = '0' THEN
         BEGIN
            DECLARE EXIT HANDLER FOR NOT FOUND
            begin
               SET vln_nilai_fas = vln_nilai_fas;
            end;
            SELECT nilai_non_dep
            INTO 	vln_nilai
            FROM 	fas_non_dep
            WHERE  kd_propinsi  = vlc_kd_prop  AND
            kd_dati2 	 = vlc_kd_dati2 AND
            thn_non_dep  = vlc_tahun    AND
            kd_fasilitas = SWV_c_fas1_kd_fasilitas;
            SET vln_nilai_fas = vln_nilai_fas+(vln_nilai*SWV_c_fas1_jml_satuan);
         END;
      ELSEIF SWV_c_fas1_ketergantungan = '1' THEN
         BEGIN
            DECLARE EXIT HANDLER FOR NOT FOUND
            begin
               SET vln_nilai_fas = vln_nilai_fas;
            end;
            SELECT nilai_dep_min_max
            INTO 	vln_nilai
            FROM 	fas_dep_min_max
            WHERE  kd_propinsi     = vlc_kd_prop  	   	      AND
            kd_dati2  	    = vlc_kd_dati2 		      AND
            thn_dep_min_max = vlc_tahun       	      AND
            kd_fasilitas    = SWV_c_fas1_kd_fasilitas AND
            kls_dep_min    <= SWV_c_fas1_jml_satuan   AND
            kls_dep_max    >= SWV_c_fas1_jml_satuan;
            SET vln_nilai_fas = vln_nilai_fas+(vln_nilai*SWV_c_fas1_jml_satuan);
         END;
      ELSEIF SWV_c_fas1_ketergantungan = '2' THEN
         BEGIN
            DECLARE EXIT HANDLER FOR NOT FOUND
            begin
               SET vln_nilai_fas = vln_nilai_fas;
            end;
            SELECT nilai_fasilitas_kls_bintang
            INTO 	vln_nilai
            FROM 	fas_dep_jpb_kls_bintang
            WHERE  kd_propinsi             = vlc_kd_prop  	   	      AND
            kd_dati2  	            = vlc_kd_dati2 		      AND
            thn_dep_jpb_kls_bintang = vlc_tahun       	      AND
            kd_fasilitas            = SWV_c_fas1_kd_fasilitas AND
            kd_jpb                  = vlc_kd_jpb   			  AND
            kls_bintang             = vlc_kls_bintang;
            SET vln_nilai_fas = vln_nilai_fas+(vln_nilai*SWV_c_fas1_jml_satuan);
         END;
      END IF;
      SET NO_DATA = 0;
      FETCH c_fas1 INTO SWV_c_fas1_kd_fasilitas,SWV_c_fas1_jml_satuan,SWV_c_fas1_status_fasilitas,
      SWV_c_fas1_ketergantungan;
   END WHILE;
   SET NO_DATA = 0;
   CLOSE c_fas1;
   SET vln_fasilitas = vln_nilai_fas;
END;
