DROP PROCEDURE IF EXISTS `FASILITAS_TDK_SUSUT`;
--> statement-breakpoint
CREATE PROCEDURE `FASILITAS_TDK_SUSUT`(IN  vlc_kd_propinsi     CHAR(2),
IN  vlc_kd_dati2        CHAR(2),
IN  vlc_kd_kecamatan    CHAR(3),
IN  vlc_kd_kelurahan    CHAR(3),
IN  vlc_kd_blok         CHAR(3),
IN  vlc_no_urut         CHAR(4),
IN  vlc_kd_jns_op       CHAR(1),
IN  vln_no_bng          SMALLINT,
IN  vlc_tahun           VARCHAR(4000),
OUT vln_nilai_fasilitas INT)
BEGIN
   DECLARE vln_jml_satuan INT DEFAULT 0;
   DECLARE vlc_kd_fasilitas CHAR(2);
   DECLARE vlc_ketergantungan CHAR(1);
   DECLARE vln_nilai_satuan DECIMAL(10,2) DEFAULT 0;
   DECLARE NO_DATA INT DEFAULT 0;
   DECLARE cur_fas_tdk_susut CURSOR FOR SELECT kd_fasilitas, ketergantungan
   FROM   fasilitas
   WHERE  status_fasilitas = '5';
   DECLARE CONTINUE HANDLER FOR NOT FOUND SET NO_DATA = -1;
/*OLEH : TEGUH
TANGGAL     :
REVISI KE   : 1
DIREVISI    : TEGUH - RACHMAT
TGL. REVISI : 05-10-2000
*/-- ------------------
   SET vln_nilai_fasilitas = 0;
   OPEN cur_fas_tdk_susut;
   SWL_Label3:
   LOOP
      SET NO_DATA = 0;
      FETCH cur_fas_tdk_susut INTO vlc_kd_fasilitas,vlc_ketergantungan;
      IF NO_DATA <> 0 THEN
         LEAVE SWL_Label3;
      END IF;
      BEGIN
         DECLARE EXIT HANDLER FOR NOT FOUND
         begin
            SET vln_nilai_satuan = 0;
         end;
         SELECT IFNULL(nilai_non_dep,0) INTO vln_nilai_satuan
         FROM   fas_non_dep
         WHERE  kd_propinsi  = vlc_kd_propinsi  AND
         kd_dati2     = vlc_kd_dati2     AND
         thn_non_dep  = vlc_tahun        AND
         kd_fasilitas = vlc_kd_fasilitas;
      END;
      BEGIN
         DECLARE EXIT HANDLER FOR NOT FOUND
         begin
            SET vln_jml_satuan = 0;
         end;
         SELECT IFNULL(jml_satuan,0) INTO vln_jml_satuan
         FROM   dat_fasilitas_bangunan
         WHERE  kd_propinsi  = vlc_kd_propinsi  AND
         kd_dati2     = vlc_kd_dati2  	 AND
         kd_kecamatan = vlc_kd_kecamatan AND
         kd_kelurahan = vlc_kd_kelurahan AND
         kd_blok      = vlc_kd_blok      AND
         no_urut      = vlc_no_urut    	 AND
         kd_jns_op    = vlc_kd_jns_op    AND
         no_bng       = vln_no_bng       AND
         kd_fasilitas = vlc_kd_fasilitas;
      END;
      IF vlc_kd_fasilitas = '44' THEN
         SET vln_nilai_fasilitas = vln_nilai_fasilitas+((vln_nilai_satuan*vln_jml_satuan)/1000);
   ELSE
         SET vln_nilai_fasilitas = vln_nilai_fasilitas+(vln_nilai_satuan*vln_jml_satuan);
      END IF;
   END LOOP;
   CLOSE cur_fas_tdk_susut;
END;
