DROP PROCEDURE IF EXISTS `fixing_pembayaran_ke`;
--> statement-breakpoint
CREATE PROCEDURE `fixing_pembayaran_ke`()
BEGIN
  DECLARE v_finished INTEGER DEFAULT 0 ;
  DECLARE v_nop CHAR (18) ;
  DECLARE v_thn CHAR (4) ;
  DECLARE v_jml_bayar INT ;
  DECLARE v_jml_ke INT ;
  -- query untuk nge cek yang (pembayaran_ke nya lebih dari 1) atau (yang jml pembayaran 1 tapi pembayaran ke nya tidak 1) 
  DECLARE nop_cursor CURSOR FOR 
  SELECT 
    CONCAT(
      KD_PROPINSI,
      KD_DATI2,
      KD_KECAMATAN,
      KD_KELURAHAN,
      KD_BLOK,
      NO_URUT,
      KD_JNS_OP
    ) AS nop,
    THN_PAJAK_SPPT,
    COUNT(1) AS JML_BAYAR,
    SUM(`PEMBAYARAN_SPPT_KE`) AS JML_KE 
  FROM
    pembayaran_sppt 
  GROUP BY KD_PROPINSI,
    KD_DATI2,
    KD_KECAMATAN,
    KD_KELURAHAN,
    KD_BLOK,
    NO_URUT,
    KD_JNS_OP,
    THN_PAJAK_SPPT 
  HAVING (JML_BAYAR = 1 
      AND JML_KE <> 1) 
    OR JML_BAYAR > 1 ;
  DECLARE CONTINUE HANDLER FOR NOT FOUND SET v_finished = 1 ;
  OPEN nop_cursor ;
  fixing_ke :
  LOOP
    FETCH nop_cursor INTO v_nop,
    v_thn,
    v_jml_bayar,
    v_jml_ke ;
    IF v_finished = 1 
    THEN LEAVE fixing_ke ;
    END IF ;
    IF v_jml_bayar = 1 
    THEN 
    UPDATE 
      pembayaran_sppt AS a 
    SET
      a.PEMBAYARAN_SPPT_KE = 1 
    WHERE KD_PROPINSI = SUBSTR(v_nop, 1, 2) 
      AND KD_DATI2 = SUBSTR(v_nop, 3, 2) 
      AND KD_KECAMATAN = SUBSTR(v_nop, 5, 3) 
      AND KD_KELURAHAN = SUBSTR(v_nop, 8, 3) 
      AND KD_BLOK = SUBSTR(v_nop, 11, 3) 
      AND NO_URUT = SUBSTR(v_nop, 14, 4) 
      AND KD_JNS_OP = SUBSTR(v_nop, 18, 1) 
      AND THN_PAJAK_SPPT = v_thn ;
    ELSE CALL fixing_pembayaran_ke_nop (v_nop, v_thn) ;
    END IF ;
  END LOOP fixing_ke ;
  CLOSE nop_cursor ;
END;
--> statement-breakpoint

DROP PROCEDURE IF EXISTS `fixing_pembayaran_ke_nop`;
--> statement-breakpoint
CREATE PROCEDURE `fixing_pembayaran_ke_nop`(IN NOP CHAR(18), IN THN CHAR(4))
BEGIN
  DECLARE v_finished_d INTEGER DEFAULT 0 ;
  DECLARE v_nop_d CHAR (18) ;
  DECLARE v_thn_d CHAR (4) ;
  DECLARE v_ke_d INTEGER ;
  DECLARE v_ke_current INTEGER DEFAULT 1 ;
  DECLARE detail_cursor CURSOR FOR 
  SELECT 
    CONCAT(
      KD_PROPINSI,
      KD_DATI2,
      KD_KECAMATAN,
      KD_KELURAHAN,
      KD_BLOK,
      NO_URUT,
      KD_JNS_OP
    ) AS nop,
    PEMBAYARAN_SPPT_KE,
    THN_PAJAK_SPPT 
  FROM
    pembayaran_sppt 
  WHERE KD_PROPINSI = SUBSTR(NOP, 1, 2) 
    AND KD_DATI2 = SUBSTR(NOP, 3, 2) 
    AND KD_KECAMATAN = SUBSTR(NOP, 5, 3) 
    AND KD_KELURAHAN = SUBSTR(NOP, 8, 3) 
    AND KD_BLOK = SUBSTR(NOP, 11, 3) 
    AND NO_URUT = SUBSTR(NOP, 14, 4) 
    AND KD_JNS_OP = SUBSTR(NOP, 18, 1) 
    AND THN_PAJAK_SPPT = THN 
  ORDER BY TGL_PEMBAYARAN_SPPT ASC ;
  DECLARE CONTINUE HANDLER FOR NOT FOUND SET v_finished_d = 1 ;
  -- UPDATE KE +100 SEMUA DULU MENGHINDARI KEMUNGKINAN DUPLICATE KEY PAS UPDATE
  UPDATE 
    pembayaran_sppt 
  SET
    PEMBAYARAN_SPPT_KE = PEMBAYARAN_SPPT_KE + 100 
  WHERE KD_PROPINSI = SUBSTR(NOP, 1, 2) 
    AND KD_DATI2 = SUBSTR(NOP, 3, 2) 
    AND KD_KECAMATAN = SUBSTR(NOP, 5, 3) 
    AND KD_KELURAHAN = SUBSTR(NOP, 8, 3) 
    AND KD_BLOK = SUBSTR(NOP, 11, 3) 
    AND NO_URUT = SUBSTR(NOP, 14, 4) 
    AND KD_JNS_OP = SUBSTR(NOP, 18, 1) 
    AND THN_PAJAK_SPPT = THN ;
  OPEN detail_cursor ;
  fixing_ke_nop :
  LOOP
    FETCH detail_cursor INTO v_nop_d,
    v_ke_d,
    v_thn_d ;
    IF v_finished_d = 1 
    THEN LEAVE fixing_ke_nop ;
    END IF ;
    UPDATE 
      pembayaran_sppt 
    SET
      PEMBAYARAN_SPPT_KE = v_ke_current 
    WHERE KD_PROPINSI = SUBSTR(v_nop_d, 1, 2) 
      AND KD_DATI2 = SUBSTR(v_nop_d, 3, 2) 
      AND KD_KECAMATAN = SUBSTR(v_nop_d, 5, 3) 
      AND KD_KELURAHAN = SUBSTR(v_nop_d, 8, 3) 
      AND KD_BLOK = SUBSTR(v_nop_d, 11, 3) 
      AND NO_URUT = SUBSTR(v_nop_d, 14, 4) 
      AND KD_JNS_OP = SUBSTR(v_nop_d, 18, 1) 
      AND THN_PAJAK_SPPT = v_thn_d 
      AND PEMBAYARAN_SPPT_KE = v_ke_d ;
    SET v_ke_current = v_ke_current + 1 ;
  END LOOP fixing_ke_nop ;
  CLOSE detail_cursor ;
END;
--> statement-breakpoint

DROP PROCEDURE IF EXISTS `getSppt`;
--> statement-breakpoint
CREATE PROCEDURE `getSppt`(
  IN THN_PAJAK YEAR,
  IN OFFS INT,
  IN LIM INT
)
BEGIN
  SELECT 
    CONCAT(
      KD_PROPINSI,
      KD_DATI2,
      KD_KECAMATAN,
      KD_KELURAHAN,
      KD_BLOK,
      NO_URUT,
      KD_JNS_OP
    ) AS NOP,
    NM_WP_SPPT AS NAMA_WP,
    THN_PAJAK_SPPT AS THN_PAJAK,
    JALAN_OP AS ALAMAT_OP,
    TGL_JATUH_TEMPO_SPPT AS TGL_TEMPO,
    TGL_TERBIT_SPPT AS TGL_PENETAPAN,
    PBB_YG_HARUS_DIBAYAR_SPPT AS POKOK 
  FROM
    sppt 
    JOIN spop USING (
        KD_PROPINSI,
        KD_DATI2,
        KD_KECAMATAN,
        KD_KELURAHAN,
        KD_BLOK,
        NO_URUT,
        KD_JNS_OP
      ) 
  WHERE THN_PAJAK_SPPT = THN_PAJAK 
  LIMIT LIM OFFSET OFFS ;
  END;
--> statement-breakpoint

DROP PROCEDURE IF EXISTS `getSpptTanggal`;
--> statement-breakpoint
CREATE PROCEDURE `getSpptTanggal`(
  IN THN_PAJAK YEAR,
  IN TANGGAL_TERBIT DATE,
  IN OFFS INT,
  IN LIM INT
)
BEGIN
  SELECT 
    CONCAT(
      KD_PROPINSI,
      KD_DATI2,
      KD_KECAMATAN,
      KD_KELURAHAN,
      KD_BLOK,
      NO_URUT,
      KD_JNS_OP
    ) AS NOP,
    NM_WP_SPPT AS NAMA_WP,
    THN_PAJAK_SPPT AS THN_PAJAK,
    JALAN_OP AS ALAMAT_OP,
    TGL_JATUH_TEMPO_SPPT AS TGL_TEMPO,
    PBB_YG_HARUS_DIBAYAR_SPPT AS POKOK 
  FROM
    sppt 
    JOIN spop USING (
        KD_PROPINSI,
        KD_DATI2,
        KD_KECAMATAN,
        KD_KELURAHAN,
        KD_BLOK,
        NO_URUT,
        KD_JNS_OP
      ) 
  WHERE THN_PAJAK_SPPT = THN_PAJAK AND DATE(TGL_TERBIT_SPPT) = TANGGAL_TERBIT
  LIMIT LIM OFFSET OFFS ;
  END;
--> statement-breakpoint

DROP PROCEDURE IF EXISTS `getTotalSppt`;
--> statement-breakpoint
CREATE PROCEDURE `getTotalSppt`(
  IN THN YEAR,
  IN TGL_PENETAPAN DATE
)
BEGIN
	SELECT 
	  TGL_PENETAPAN AS "TGL_PENETAPAN",
	  SUM(PBB_YG_HARUS_DIBAYAR_SPPT) AS "KETETAPAN",
	  "PBB" AS "KETERANGAN" 
	FROM
	  sppt 
	WHERE 
	  THN_PAJAK_SPPT = THN AND 
	  TGL_TERBIT_SPPT BETWEEN CONCAT(YEAR(TGL_PENETAPAN),'-01-01') AND DATE(TGL_PENETAPAN);
END;
