DROP PROCEDURE IF EXISTS `KOMP_MATERIAL`;
--> statement-breakpoint
CREATE PROCEDURE `KOMP_MATERIAL`(IN  vlc_kd_prop       CHAR(2),
IN  vlc_kd_dati2      CHAR(2),
IN  vlc_kd_kec        CHAR(3),
IN  vlc_kd_kel        CHAR(3),
IN  vlc_kd_blok       CHAR(3),
IN  vlc_no_urut       CHAR(4),
IN  vlc_kd_jns_op     CHAR(1),
IN  vlc_no_bng        SMALLINT,
IN  vlc_tahun         CHAR(4),
OUT vln_komp_material INT)
BEGIN
   DECLARE vlc_jns_konstruksi CHAR(1);
   DECLARE vlc_jns_atap CHAR(1);
   DECLARE vlc_kd_dinding CHAR(1);
   DECLARE vlc_kd_lantai CHAR(1);
   DECLARE vln_jml_lantai_bng CHAR(1);
   DECLARE vlc_kd_langit CHAR(1);
   DECLARE vln_atap DECIMAL(12,2);
   DECLARE vln_nilai_atap DECIMAL(15,2) DEFAULT 0;
   DECLARE vln_dinding DECIMAL(15,2) DEFAULT 0;
   DECLARE vln_lantai DECIMAL(15,2) DEFAULT 0;
   DECLARE vln_langit DECIMAL(15,2) DEFAULT 0;
   DECLARE EXIT HANDLER FOR NOT FOUND,SQLEXCEPTION
   begin
      SET vln_komp_material = 0;
   end;
/*OLEH : SUNARYO
TANGGAL     :
REVISI KE   : 1
DIREVISI    : TEGUH, RACHMAT
TGL. REVISI : 06-10-2000
*/-- ------------------
   SELECT  jns_konstruksi_bng,
jns_atap_bng,
kd_dinding,
kd_lantai,
kd_langit_langit,
jml_lantai_bng
   INTO    vlc_jns_konstruksi,vlc_jns_atap,vlc_kd_dinding,vlc_kd_lantai,vlc_kd_langit,
   vln_jml_lantai_bng
   FROM	dat_op_bangunan
   WHERE  	kd_propinsi  = vlc_kd_prop  	AND
   kd_dati2     = vlc_kd_dati2 	AND
   kd_kecamatan = vlc_kd_kec 		AND
   kd_kelurahan = vlc_kd_kel 		AND
   kd_blok      = vlc_kd_blok  	AND
   no_urut      = vlc_no_urut  	AND
   kd_jns_op    = vlc_kd_jns_op	AND
   no_bng       = vlc_no_bng;
   IF ROW_COUNT() <> 0 THEN
      IF (vlc_jns_atap IS NOT NULL) OR (vlc_jns_atap = '0') THEN
         BEGIN
            DECLARE EXIT HANDLER FOR NOT FOUND
            begin
               SET vln_atap = 0;
            end;
            SELECT nilai_dbkb_material
            INTO   vln_atap
            FROM   dbkb_material m
            WHERE  kd_propinsi             = vlc_kd_prop  AND
            kd_dati2       		   = vlc_kd_dati2 AND
            thn_dbkb_material       = vlc_tahun    AND
            kd_pekerjaan            = '23'         AND
            SUBSTRING(kd_kegiatan,2,1) = vlc_jns_atap;
            SET vln_nilai_atap =(vln_atap/vln_jml_lantai_bng);
         END;
      END IF;
      IF (vlc_kd_dinding IS NOT NULL) OR (vlc_kd_dinding = '0') THEN
         IF vlc_kd_dinding = '1' THEN 
            SET vlc_kd_dinding = '1';
         ELSEIF vlc_kd_dinding = '2' THEN 
            SET vlc_kd_dinding = '2';
         ELSEIF vlc_kd_dinding = '3' THEN 
            SET vlc_kd_dinding = '3';
         ELSEIF vlc_kd_dinding = '4' THEN 
            SET vlc_kd_dinding = '7';
         ELSEIF vlc_kd_dinding = '5' THEN 
            SET vlc_kd_dinding = '8';
         ELSEIF vlc_kd_dinding = '6' THEN 
            SET vlc_kd_dinding = null;
         END IF;
         BEGIN
            DECLARE EXIT HANDLER FOR NOT FOUND
            begin
               SET vln_dinding = 0;
            end;
            SELECT nilai_dbkb_material
            INTO   vln_dinding
            FROM   dbkb_material
            WHERE  kd_propinsi              = vlc_kd_prop  AND
            kd_dati2          		= vlc_kd_dati2 AND
            thn_dbkb_material 		= vlc_tahun    AND
            kd_pekerjaan       		= '21' 		   AND
            SUBSTRING(kd_kegiatan,2,1)  = vlc_kd_dinding;
         END;
      END IF;
      IF (vlc_kd_lantai IS NOT NULL) OR (vlc_kd_lantai = '0') THEN
         BEGIN
            DECLARE EXIT HANDLER FOR NOT FOUND
            begin
               SET vln_lantai = 0;
            end;
            SELECT nilai_dbkb_material
            INTO   vln_lantai
            FROM   dbkb_material
            WHERE  kd_propinsi              = vlc_kd_prop  AND
            kd_dati2          		= vlc_kd_dati2 AND
            thn_dbkb_material 		= vlc_tahun    AND
            kd_pekerjaan      		= '22'         AND
            SUBSTRING(kd_kegiatan,2,1)  = vlc_kd_lantai;
         END;
      END IF;
      IF (vlc_kd_langit IS NOT NULL) OR (vlc_kd_langit = '0') THEN
         BEGIN
            DECLARE EXIT HANDLER FOR NOT FOUND
            begin
               SET vln_langit = 0;
            end;
            SELECT nilai_dbkb_material
            INTO   vln_langit
            FROM   dbkb_material
            WHERE  kd_propinsi              = vlc_kd_prop  AND
            kd_dati2          		= vlc_kd_dati2 AND
            thn_dbkb_material 		= vlc_tahun    AND
            kd_pekerjaan      		= '24' 		   AND
            SUBSTRING(kd_kegiatan,2,1)  = vlc_kd_langit;
         END;
      END IF;
      SET vln_komp_material =(IFNULL(vln_nilai_atap,0)+IFNULL(vln_dinding,0)+IFNULL(vln_lantai,0)+IFNULL(vln_langit,0));
ELSE
      SET vln_komp_material = 0;
   END IF;
END;
--> statement-breakpoint

DROP PROCEDURE IF EXISTS `KOMP_UTAMA_STD`;
--> statement-breakpoint
CREATE PROCEDURE `KOMP_UTAMA_STD`(IN  vlc_kd_prop    			CHAR(2),
IN  vlc_kd_dati2   			CHAR(2),
IN  vlc_kd_kec     			CHAR(3),
IN  vlc_kd_kel     			CHAR(3),
IN  vlc_kd_blok    			CHAR(3),
IN  vlc_no_urut    			CHAR(4),
IN  vlc_kd_jns_op  			CHAR(1),
IN  vlc_no_bng     			SMALLINT,
IN  vlc_tahun      			CHAR(4),
IN  vlc_kd_jpb				CHAR(2),
IN  vln_luas_bng 			BIGINT,
IN  vln_jml_lantai_bng 		SMALLINT,
IN  vlc_jns_konstruksi_bng  CHAR(1),
OUT vln_komp_utama 			INT)
BEGIN
   DECLARE vlc_kayu_ulin TINYINT;
   DECLARE vln_nilai_dbkb DECIMAL(11,4);
   DECLARE vlc_jpb CHAR(2);
   DECLARE NO_DATA INT DEFAULT 0;
   DECLARE CONTINUE HANDLER FOR NOT FOUND SET NO_DATA = -1;
/*OLEH : SUNARYO
TANGGAL     :
REVISI KE   : 1
DIREVISI    : TEGUH , RACHMAT
TGL. REVISI : 05-10-2000
*/-- ------------------
   BEGIN
      DECLARE EXIT HANDLER FOR SQLEXCEPTION
      begin
         SET vlc_kayu_ulin = '0';
      end;
      SELECT status_kayu_ulin
      INTO   vlc_kayu_ulin
      FROM   kayu_ulin
      WHERE  kd_propinsi		    = vlc_kd_prop   AND
      kd_dati2      	    = vlc_kd_dati2  AND
      thn_status_kayu_ulin = vlc_tahun;
   END;
   SET vln_komp_utama = 0;
   IF vlc_kd_jpb IN('04','09') THEN
      SET vlc_jpb = '02';
ELSE
      SET vlc_jpb = vlc_kd_jpb;
   END IF;
   BEGIN
      DECLARE vlc_tipe_bng CHAR(5);
      DECLARE vlc_kd_bng_lantai CHAR(8);
      DECLARE c_tipe_bng CURSOR FOR SELECT a.tipe_bng,
a.kd_bng_lantai
      FROM   bangunan_lantai a, tipe_bangunan b
      WHERE  a.kd_jpb 	    		   = vlc_jpb            AND
      a.lantai_min_bng_lantai <= vln_jml_lantai_bng AND
      a.lantai_max_bng_lantai >= vln_jml_lantai_bng AND
      b.luas_min_tipe_bng     <= vln_luas_bng       AND
      b.luas_max_tipe_bng     >= vln_luas_bng		AND
      b.tipe_bng			   = a.tipe_bng;
      OPEN  c_tipe_bng;
      SET NO_DATA = 0;
      FETCH c_tipe_bng
      INTO  vlc_tipe_bng,vlc_kd_bng_lantai;
      IF NO_DATA = 0 THEN
         BEGIN
            DECLARE EXIT HANDLER FOR NOT FOUND
            begin
               SET vln_nilai_dbkb = 0;
            end;
            SELECT nilai_dbkb_standard
            INTO   vln_nilai_dbkb
            FROM   dbkb_standard
            WHERE  kd_propinsi       = vlc_kd_prop  AND
            kd_dati2          = vlc_kd_dati2 AND
            thn_dbkb_standard = vlc_tahun    AND
            kd_jpb            = vlc_jpb      AND
            tipe_bng     	   = vlc_tipe_bng AND
            kd_bng_lantai     = vlc_kd_bng_lantai;
         END;
/*= '4') AND (vlc_kayu_ulin = '1') THEN
vln_komp_utama := vln_nilai_dbkb;
ELSE
vln_komp_utama := (vln_nilai_dbkb * 7/10);
END IF;*/
         IF (vlc_jns_konstruksi_bng = '4') AND (vlc_kayu_ulin = '0') THEN
            SET vln_komp_utama =(vln_nilai_dbkb*7/10);
      ELSE
            SET vln_komp_utama = vln_nilai_dbkb;
         END IF;
      END IF;
      CLOSE c_tipe_bng;
   END;
END;
