DROP PROCEDURE IF EXISTS `pemekaranById`;
--> statement-breakpoint
CREATE PROCEDURE `pemekaranById`(IN ID_PEMEKARAN INT)
BEGIN
  UPDATE 
    spop AS a 
    INNER JOIN pemekaran_detail AS b 
      ON a.`KD_PROPINSI` = b.`KD_PROPINSI_LAMA` 
      AND a.`KD_DATI2` = b.`KD_DATI2_LAMA` 
      AND a.`KD_KECAMATAN` = b.`KD_KECAMATAN_LAMA` 
      AND a.`KD_KELURAHAN` = b.`KD_KELURAHAN_LAMA` 
      AND a.`KD_BLOK` = b.`KD_BLOK_LAMA` 
      AND a.`NO_URUT` = b.`NO_URUT_LAMA` 
      AND a.`KD_JNS_OP` = b.`KD_JNS_OP_LAMA` SET a.`KD_PROPINSI` = b.`KD_PROPINSI_BARU`,
    a.`KD_DATI2` = b.`KD_DATI2_BARU`,
    a.`KD_KECAMATAN` = b.`KD_KECAMATAN_BARU`,
    a.`KD_KELURAHAN` = b.`KD_KELURAHAN_BARU`,
    a.`KD_BLOK` = b.`KD_BLOK_BARU`,
    a.`NO_URUT` = b.`NO_URUT_BARU`,
    a.`KD_JNS_OP` = b.`KD_JNS_OP_BARU` 
  WHERE b.`PEMEKARAN_ID` = ID_PEMEKARAN ;
  UPDATE 
    lspop AS a 
    INNER JOIN pemekaran_detail AS b 
      ON a.`KD_PROPINSI` = b.`KD_PROPINSI_LAMA` 
      AND a.`KD_DATI2` = b.`KD_DATI2_LAMA` 
      AND a.`KD_KECAMATAN` = b.`KD_KECAMATAN_LAMA` 
      AND a.`KD_KELURAHAN` = b.`KD_KELURAHAN_LAMA` 
      AND a.`KD_BLOK` = b.`KD_BLOK_LAMA` 
      AND a.`NO_URUT` = b.`NO_URUT_LAMA` 
      AND a.`KD_JNS_OP` = b.`KD_JNS_OP_LAMA` SET a.`KD_PROPINSI` = b.`KD_PROPINSI_BARU`,
    a.`KD_DATI2` = b.`KD_DATI2_BARU`,
    a.`KD_KECAMATAN` = b.`KD_KECAMATAN_BARU`,
    a.`KD_KELURAHAN` = b.`KD_KELURAHAN_BARU`,
    a.`KD_BLOK` = b.`KD_BLOK_BARU`,
    a.`NO_URUT` = b.`NO_URUT_BARU`,
    a.`KD_JNS_OP` = b.`KD_JNS_OP_BARU` 
  WHERE b.`PEMEKARAN_ID` = ID_PEMEKARAN ;
  UPDATE 
    sppt AS a 
    INNER JOIN pemekaran_detail AS b 
      ON a.`KD_PROPINSI` = b.`KD_PROPINSI_LAMA` 
      AND a.`KD_DATI2` = b.`KD_DATI2_LAMA` 
      AND a.`KD_KECAMATAN` = b.`KD_KECAMATAN_LAMA` 
      AND a.`KD_KELURAHAN` = b.`KD_KELURAHAN_LAMA` 
      AND a.`KD_BLOK` = b.`KD_BLOK_LAMA` 
      AND a.`NO_URUT` = b.`NO_URUT_LAMA` 
      AND a.`KD_JNS_OP` = b.`KD_JNS_OP_LAMA` SET a.`KD_PROPINSI` = b.`KD_PROPINSI_BARU`,
    a.`KD_DATI2` = b.`KD_DATI2_BARU`,
    a.`KD_KECAMATAN` = b.`KD_KECAMATAN_BARU`,
    a.`KD_KELURAHAN` = b.`KD_KELURAHAN_BARU`,
    a.`KD_BLOK` = b.`KD_BLOK_BARU`,
    a.`NO_URUT` = b.`NO_URUT_BARU`,
    a.`KD_JNS_OP` = b.`KD_JNS_OP_BARU` 
  WHERE b.`PEMEKARAN_ID` = ID_PEMEKARAN ;
  UPDATE 
    pembayaran_sppt AS a 
    INNER JOIN pemekaran_detail AS b 
      ON a.`KD_PROPINSI` = b.`KD_PROPINSI_LAMA` 
      AND a.`KD_DATI2` = b.`KD_DATI2_LAMA` 
      AND a.`KD_KECAMATAN` = b.`KD_KECAMATAN_LAMA` 
      AND a.`KD_KELURAHAN` = b.`KD_KELURAHAN_LAMA` 
      AND a.`KD_BLOK` = b.`KD_BLOK_LAMA` 
      AND a.`NO_URUT` = b.`NO_URUT_LAMA` 
      AND a.`KD_JNS_OP` = b.`KD_JNS_OP_LAMA` SET a.`KD_PROPINSI` = b.`KD_PROPINSI_BARU`,
    a.`KD_DATI2` = b.`KD_DATI2_BARU`,
    a.`KD_KECAMATAN` = b.`KD_KECAMATAN_BARU`,
    a.`KD_KELURAHAN` = b.`KD_KELURAHAN_BARU`,
    a.`KD_BLOK` = b.`KD_BLOK_BARU`,
    a.`NO_URUT` = b.`NO_URUT_BARU`,
    a.`KD_JNS_OP` = b.`KD_JNS_OP_BARU` 
  WHERE b.`PEMEKARAN_ID` = ID_PEMEKARAN ;
  UPDATE 
    dhkp AS a 
    INNER JOIN pemekaran_detail AS b 
      ON a.`KD_PROPINSI` = b.`KD_PROPINSI_LAMA` 
      AND a.`KD_DATI2` = b.`KD_DATI2_LAMA` 
      AND a.`KD_KECAMATAN` = b.`KD_KECAMATAN_LAMA` 
      AND a.`KD_KELURAHAN` = b.`KD_KELURAHAN_LAMA` 
      AND a.`KD_BLOK` = b.`KD_BLOK_LAMA` 
      AND a.`NO_URUT` = b.`NO_URUT_LAMA` 
      AND a.`KD_JNS_OP` = b.`KD_JNS_OP_LAMA` SET a.`KD_PROPINSI` = b.`KD_PROPINSI_BARU`,
    a.`KD_DATI2` = b.`KD_DATI2_BARU`,
    a.`KD_KECAMATAN` = b.`KD_KECAMATAN_BARU`,
    a.`KD_KELURAHAN` = b.`KD_KELURAHAN_BARU`,
    a.`KD_BLOK` = b.`KD_BLOK_BARU`,
    a.`NO_URUT` = b.`NO_URUT_BARU`,
    a.`KD_JNS_OP` = b.`KD_JNS_OP_BARU` 
  WHERE b.`PEMEKARAN_ID` = ID_PEMEKARAN ;
  UPDATE 
    dat_fasilitas_bangunan AS a 
    INNER JOIN pemekaran_detail AS b 
      ON a.`KD_PROPINSI` = b.`KD_PROPINSI_LAMA` 
      AND a.`KD_DATI2` = b.`KD_DATI2_LAMA` 
      AND a.`KD_KECAMATAN` = b.`KD_KECAMATAN_LAMA` 
      AND a.`KD_KELURAHAN` = b.`KD_KELURAHAN_LAMA` 
      AND a.`KD_BLOK` = b.`KD_BLOK_LAMA` 
      AND a.`NO_URUT` = b.`NO_URUT_LAMA` 
      AND a.`KD_JNS_OP` = b.`KD_JNS_OP_LAMA` SET a.`KD_PROPINSI` = b.`KD_PROPINSI_BARU`,
    a.`KD_DATI2` = b.`KD_DATI2_BARU`,
    a.`KD_KECAMATAN` = b.`KD_KECAMATAN_BARU`,
    a.`KD_KELURAHAN` = b.`KD_KELURAHAN_BARU`,
    a.`KD_BLOK` = b.`KD_BLOK_BARU`,
    a.`NO_URUT` = b.`NO_URUT_BARU`,
    a.`KD_JNS_OP` = b.`KD_JNS_OP_BARU` 
  WHERE b.`PEMEKARAN_ID` = ID_PEMEKARAN ;
  UPDATE 
    histori_sppt AS a 
    INNER JOIN pemekaran_detail AS b 
      ON a.`KD_PROPINSI` = b.`KD_PROPINSI_LAMA` 
      AND a.`KD_DATI2` = b.`KD_DATI2_LAMA` 
      AND a.`KD_KECAMATAN` = b.`KD_KECAMATAN_LAMA` 
      AND a.`KD_KELURAHAN` = b.`KD_KELURAHAN_LAMA` 
      AND a.`KD_BLOK` = b.`KD_BLOK_LAMA` 
      AND a.`NO_URUT` = b.`NO_URUT_LAMA` 
      AND a.`KD_JNS_OP` = b.`KD_JNS_OP_LAMA` SET a.`KD_PROPINSI` = b.`KD_PROPINSI_BARU`,
    a.`KD_DATI2` = b.`KD_DATI2_BARU`,
    a.`KD_KECAMATAN` = b.`KD_KECAMATAN_BARU`,
    a.`KD_KELURAHAN` = b.`KD_KELURAHAN_BARU`,
    a.`KD_BLOK` = b.`KD_BLOK_BARU`,
    a.`NO_URUT` = b.`NO_URUT_BARU`,
    a.`KD_JNS_OP` = b.`KD_JNS_OP_BARU` 
  WHERE b.`PEMEKARAN_ID` = ID_PEMEKARAN ;
  UPDATE 
    log_spop AS a 
    INNER JOIN pemekaran_detail AS b 
      ON a.`KD_PROPINSI` = b.`KD_PROPINSI_LAMA` 
      AND a.`KD_DATI2` = b.`KD_DATI2_LAMA` 
      AND a.`KD_KECAMATAN` = b.`KD_KECAMATAN_LAMA` 
      AND a.`KD_KELURAHAN` = b.`KD_KELURAHAN_LAMA` 
      AND a.`KD_BLOK` = b.`KD_BLOK_LAMA` 
      AND a.`NO_URUT` = b.`NO_URUT_LAMA` 
      AND a.`KD_JNS_OP` = b.`KD_JNS_OP_LAMA` SET a.`KD_PROPINSI` = b.`KD_PROPINSI_BARU`,
    a.`KD_DATI2` = b.`KD_DATI2_BARU`,
    a.`KD_KECAMATAN` = b.`KD_KECAMATAN_BARU`,
    a.`KD_KELURAHAN` = b.`KD_KELURAHAN_BARU`,
    a.`KD_BLOK` = b.`KD_BLOK_BARU`,
    a.`NO_URUT` = b.`NO_URUT_BARU`,
    a.`KD_JNS_OP` = b.`KD_JNS_OP_BARU` 
  WHERE b.`PEMEKARAN_ID` = ID_PEMEKARAN ;
  UPDATE 
    log_lspop AS a 
    INNER JOIN pemekaran_detail AS b 
      ON a.`KD_PROPINSI` = b.`KD_PROPINSI_LAMA` 
      AND a.`KD_DATI2` = b.`KD_DATI2_LAMA` 
      AND a.`KD_KECAMATAN` = b.`KD_KECAMATAN_LAMA` 
      AND a.`KD_KELURAHAN` = b.`KD_KELURAHAN_LAMA` 
      AND a.`KD_BLOK` = b.`KD_BLOK_LAMA` 
      AND a.`NO_URUT` = b.`NO_URUT_LAMA` 
      AND a.`KD_JNS_OP` = b.`KD_JNS_OP_LAMA` SET a.`KD_PROPINSI` = b.`KD_PROPINSI_BARU`,
    a.`KD_DATI2` = b.`KD_DATI2_BARU`,
    a.`KD_KECAMATAN` = b.`KD_KECAMATAN_BARU`,
    a.`KD_KELURAHAN` = b.`KD_KELURAHAN_BARU`,
    a.`KD_BLOK` = b.`KD_BLOK_BARU`,
    a.`NO_URUT` = b.`NO_URUT_BARU`,
    a.`KD_JNS_OP` = b.`KD_JNS_OP_BARU` 
  WHERE b.`PEMEKARAN_ID` = ID_PEMEKARAN ;
  UPDATE 
    log_pengurangan AS a 
    INNER JOIN pemekaran_detail AS b 
      ON a.`KD_PROPINSI` = b.`KD_PROPINSI_LAMA` 
      AND a.`KD_DATI2` = b.`KD_DATI2_LAMA` 
      AND a.`KD_KECAMATAN` = b.`KD_KECAMATAN_LAMA` 
      AND a.`KD_KELURAHAN` = b.`KD_KELURAHAN_LAMA` 
      AND a.`KD_BLOK` = b.`KD_BLOK_LAMA` 
      AND a.`NO_URUT` = b.`NO_URUT_LAMA` 
      AND a.`KD_JNS_OP` = b.`KD_JNS_OP_LAMA` SET a.`KD_PROPINSI` = b.`KD_PROPINSI_BARU`,
    a.`KD_DATI2` = b.`KD_DATI2_BARU`,
    a.`KD_KECAMATAN` = b.`KD_KECAMATAN_BARU`,
    a.`KD_KELURAHAN` = b.`KD_KELURAHAN_BARU`,
    a.`KD_BLOK` = b.`KD_BLOK_BARU`,
    a.`NO_URUT` = b.`NO_URUT_BARU`,
    a.`KD_JNS_OP` = b.`KD_JNS_OP_BARU` 
  WHERE b.`PEMEKARAN_ID` = ID_PEMEKARAN ;
  UPDATE 
    log_perubahan_jthtempo_sppt AS a 
    INNER JOIN pemekaran_detail AS b 
      ON a.`KD_PROPINSI` = b.`KD_PROPINSI_LAMA` 
      AND a.`KD_DATI2` = b.`KD_DATI2_LAMA` 
      AND a.`KD_KECAMATAN` = b.`KD_KECAMATAN_LAMA` 
      AND a.`KD_KELURAHAN` = b.`KD_KELURAHAN_LAMA` 
      AND a.`KD_BLOK` = b.`KD_BLOK_LAMA` 
      AND a.`NO_URUT` = b.`NO_URUT_LAMA` 
      AND a.`KD_JNS_OP` = b.`KD_JNS_OP_LAMA` SET a.`KD_PROPINSI` = b.`KD_PROPINSI_BARU`,
    a.`KD_DATI2` = b.`KD_DATI2_BARU`,
    a.`KD_KECAMATAN` = b.`KD_KECAMATAN_BARU`,
    a.`KD_KELURAHAN` = b.`KD_KELURAHAN_BARU`,
    a.`KD_BLOK` = b.`KD_BLOK_BARU`,
    a.`NO_URUT` = b.`NO_URUT_BARU`,
    a.`KD_JNS_OP` = b.`KD_JNS_OP_BARU` 
  WHERE b.`PEMEKARAN_ID` = ID_PEMEKARAN ;
  UPDATE 
    log_spop_backup_ubah_kelas AS a 
    INNER JOIN pemekaran_detail AS b 
      ON a.`KD_PROPINSI` = b.`KD_PROPINSI_LAMA` 
      AND a.`KD_DATI2` = b.`KD_DATI2_LAMA` 
      AND a.`KD_KECAMATAN` = b.`KD_KECAMATAN_LAMA` 
      AND a.`KD_KELURAHAN` = b.`KD_KELURAHAN_LAMA` 
      AND a.`KD_BLOK` = b.`KD_BLOK_LAMA` 
      AND a.`NO_URUT` = b.`NO_URUT_LAMA` 
      AND a.`KD_JNS_OP` = b.`KD_JNS_OP_LAMA` SET a.`KD_PROPINSI` = b.`KD_PROPINSI_BARU`,
    a.`KD_DATI2` = b.`KD_DATI2_BARU`,
    a.`KD_KECAMATAN` = b.`KD_KECAMATAN_BARU`,
    a.`KD_KELURAHAN` = b.`KD_KELURAHAN_BARU`,
    a.`KD_BLOK` = b.`KD_BLOK_BARU`,
    a.`NO_URUT` = b.`NO_URUT_BARU`,
    a.`KD_JNS_OP` = b.`KD_JNS_OP_BARU` 
  WHERE b.`PEMEKARAN_ID` = ID_PEMEKARAN ;
  UPDATE 
    status_pbb AS a 
    INNER JOIN pemekaran_detail AS b 
      ON a.`KD_PROPINSI` = b.`KD_PROPINSI_LAMA` 
      AND a.`KD_DATI2` = b.`KD_DATI2_LAMA` 
      AND a.`KD_KECAMATAN` = b.`KD_KECAMATAN_LAMA` 
      AND a.`KD_KELURAHAN` = b.`KD_KELURAHAN_LAMA` 
      AND a.`KD_BLOK` = b.`KD_BLOK_LAMA` 
      AND a.`NO_URUT` = b.`NO_URUT_LAMA` 
      AND a.`KD_JNS_OP` = b.`KD_JNS_OP_LAMA` SET a.`KD_PROPINSI` = b.`KD_PROPINSI_BARU`,
    a.`KD_DATI2` = b.`KD_DATI2_BARU`,
    a.`KD_KECAMATAN` = b.`KD_KECAMATAN_BARU`,
    a.`KD_KELURAHAN` = b.`KD_KELURAHAN_BARU`,
    a.`KD_BLOK` = b.`KD_BLOK_BARU`,
    a.`NO_URUT` = b.`NO_URUT_BARU`,
    a.`KD_JNS_OP` = b.`KD_JNS_OP_BARU` 
  WHERE b.`PEMEKARAN_ID` = ID_PEMEKARAN ;
  UPDATE 
    sppt_pembatalan AS a 
    INNER JOIN pemekaran_detail AS b 
      ON a.`KD_PROPINSI` = b.`KD_PROPINSI_LAMA` 
      AND a.`KD_DATI2` = b.`KD_DATI2_LAMA` 
      AND a.`KD_KECAMATAN` = b.`KD_KECAMATAN_LAMA` 
      AND a.`KD_KELURAHAN` = b.`KD_KELURAHAN_LAMA` 
      AND a.`KD_BLOK` = b.`KD_BLOK_LAMA` 
      AND a.`NO_URUT` = b.`NO_URUT_LAMA` 
      AND a.`KD_JNS_OP` = b.`KD_JNS_OP_LAMA` SET a.`KD_PROPINSI` = b.`KD_PROPINSI_BARU`,
    a.`KD_DATI2` = b.`KD_DATI2_BARU`,
    a.`KD_KECAMATAN` = b.`KD_KECAMATAN_BARU`,
    a.`KD_KELURAHAN` = b.`KD_KELURAHAN_BARU`,
    a.`KD_BLOK` = b.`KD_BLOK_BARU`,
    a.`NO_URUT` = b.`NO_URUT_BARU`,
    a.`KD_JNS_OP` = b.`KD_JNS_OP_BARU` 
  WHERE b.`PEMEKARAN_ID` = ID_PEMEKARAN ;
END;
