CREATE PROCEDURE `PENILAIAN_BNG`(IN `vlc_kd_propinsi` CHAR(2), IN `vlc_kd_dati2` CHAR(2), IN `vlc_kd_kecamatan` CHAR(3), IN `vlc_kd_kelurahan` CHAR(3), IN `vlc_kd_blok` CHAR(3), IN `vlc_no_urut` CHAR(4), IN `vlc_kd_jns_op` CHAR(1), IN `vln_no_bng` SMALLINT, IN `vlc_kd_jpb` CHAR(2), IN `vln_luas_bng` BIGINT, IN `vln_jml_lantai_bng` SMALLINT, IN `vlc_tahun_pajak` CHAR(4), IN `vln_flag_update` INT, OUT `vln_nilai_bng` INT)
BEGIN
/*OLEH : MADE
TANGGAL     :
REVISI KE   : 2
DIREVISI    : TEGUH
TGL. REVISI : 10-10-2000
*/-- --------------
   IF (vlc_kd_jpb IN('02','04','05','07','09')) AND
((vln_luas_bng > 1000) OR (vln_jml_lantai_bng > 4)) THEN
      IF vlc_kd_jpb = '02' THEN
         CALL PENILAIAN_JPB2(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
         vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vlc_tahun_pajak,vln_nilai_bng);
      ELSEIF vlc_kd_jpb = '04' THEN
         CALL PENILAIAN_JPB4(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
         vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vlc_tahun_pajak,vln_nilai_bng);
      ELSEIF vlc_kd_jpb = '05' THEN
         CALL PENILAIAN_JPB5(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
         vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vlc_tahun_pajak,vln_nilai_bng);
      ELSEIF vlc_kd_jpb = '07' THEN
         CALL PENILAIAN_JPB7(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
         vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vlc_tahun_pajak,vln_nilai_bng);
      ELSEIF vlc_kd_jpb = '09' THEN
         CALL PENILAIAN_JPB9(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
         vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vlc_tahun_pajak,vln_nilai_bng);
      END IF;
   ELSEIF vlc_kd_jpb = '03' THEN
      CALL PENILAIAN_JPB3(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
      vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vlc_tahun_pajak,vln_nilai_bng);
   ELSEIF vlc_kd_jpb = '06' THEN
      CALL PENILAIAN_JPB6(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
      vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vlc_tahun_pajak,vln_nilai_bng);
   ELSEIF vlc_kd_jpb = '08' THEN
      CALL PENILAIAN_JPB8(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
      vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vlc_tahun_pajak,vln_nilai_bng);
   ELSEIF vlc_kd_jpb = '11' THEN
      SET vln_nilai_bng = 0;
   ELSEIF vlc_kd_jpb = '12' THEN
      CALL PENILAIAN_JPB12(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
      vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vlc_tahun_pajak,vln_nilai_bng);
   ELSEIF vlc_kd_jpb = '13' THEN
      CALL PENILAIAN_JPB13(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
      vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vlc_tahun_pajak,vln_nilai_bng);
   ELSEIF vlc_kd_jpb = '14' THEN
      CALL PENILAIAN_JPB14(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
      vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vlc_tahun_pajak,vln_nilai_bng);
   ELSEIF vlc_kd_jpb = '15' THEN
      CALL PENILAIAN_JPB15(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
      vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vlc_tahun_pajak,vln_nilai_bng);
   ELSEIF vlc_kd_jpb = '16' THEN
      CALL PENILAIAN_JPB16(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
      vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vlc_tahun_pajak,vln_nilai_bng);
   ELSE
      CALL PENILAIAN_STANDARD(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
      vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vlc_tahun_pajak,vln_nilai_bng);
   END IF;
   SET vln_nilai_bng = IFNULL(vln_nilai_bng,0);
   IF vln_flag_update = 1 THEN
      BEGIN
         DECLARE EXIT HANDLER FOR NOT FOUND,SQLEXCEPTION
         begin
            SET @SWV_Null_Var = 0;
         end;
         UPDATE dat_op_bangunan
         SET    nilai_sistem_bng = ROUND(vln_nilai_bng)
         WHERE  kd_propinsi  = vlc_kd_propinsi
         AND  kd_dati2     = vlc_kd_dati2
         AND  kd_kecamatan = vlc_kd_kecamatan
         AND  kd_kelurahan = vlc_kd_kelurahan
         AND  kd_blok      = vlc_kd_blok
         AND  no_urut      = vlc_no_urut
         AND  kd_jns_op    = vlc_kd_jns_op
         AND  no_bng       = vln_no_bng;
         COMMIT;
         
      END;
   END IF;
END;
--> statement-breakpoint

DROP PROCEDURE IF EXISTS `PENILAIAN_JPB12`;
--> statement-breakpoint
CREATE PROCEDURE `PENILAIAN_JPB12`(IN  vlc_kd_propinsi  VARCHAR(4000),
IN  vlc_kd_dati2 	 VARCHAR(4000),
IN  vlc_kd_kecamatan VARCHAR(4000),
IN  vlc_kd_kelurahan VARCHAR(4000),
IN  vlc_kd_blok 	 VARCHAR(4000),
IN  vlc_no_urut 	 VARCHAR(4000),
IN  vlc_kd_jns_op 	 VARCHAR(4000),
IN  vln_no_bng 		 INT,
IN  vlc_tahun 		 VARCHAR(4000),
OUT vln_nilai_jpb12  INT)
BEGIN
   DECLARE vlc_type_jpb12 CHAR(1);
   DECLARE vln_nilai_komponen_utama DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_luas_bng BIGINT DEFAULT 0;
   DECLARE vln_jml_lantai_bng SMALLINT DEFAULT 0;
   DECLARE vlc_tahun_dibangun CHAR(4);
   DECLARE vlc_tahun_renovasi CHAR(4);
   DECLARE vlc_kondisi_bng CHAR(1);
   DECLARE vlc_atap CHAR(1);
   DECLARE vlc_lantai CHAR(1);
   DECLARE vlc_langit_langit CHAR(1);
   DECLARE vln_nilai_atap DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_lantai DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_langit_langit DECIMAL(17,2) DEFAULT 0;
   DECLARE vlc_dinding CHAR(1);
   DECLARE vlc_cari_dinding CHAR(2);
   DECLARE vln_nilai_dinding_temp DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_dinding_plester DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_dinding_cat DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_dinding DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_material DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_fasilitas DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_total_per_m2 DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_total_kali_luas DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_fasilitas_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_sebelum_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_persentase_penyusutan DECIMAL(7,2) DEFAULT 0;
   DECLARE vln_nilai_setelah_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_fasilitas_tdk_susut DECIMAL(17,2) DEFAULT 0;
/*OLEH : MADE
TANGGAL     :
REVISI KE   : 1
DIREVISI    : TEGUH, RACHMAT
TGL. REVISI : 09-10-2000
*/-- ------------------
   BEGIN
      DECLARE EXIT HANDLER FOR NOT FOUND,SQLEXCEPTION
      begin
         SET vlc_type_jpb12 = null;
      end;
      SELECT type_jpb12
      INTO   vlc_type_jpb12
      FROM   dat_jpb12
      WHERE  kd_propinsi   = vlc_kd_propinsi
      AND  kd_dati2 	  = vlc_kd_dati2
      AND  kd_kecamatan  = vlc_kd_kecamatan
      AND  kd_kelurahan  = vlc_kd_kelurahan
      AND  kd_blok 	  = vlc_kd_blok
      AND  no_urut 	  = vlc_no_urut
      AND  kd_jns_op 	  = vlc_kd_jns_op
      AND  no_bng 	      = vln_no_bng;
   END;
   BEGIN
      DECLARE EXIT HANDLER FOR NOT FOUND,SQLEXCEPTION
      begin
         SET vln_nilai_komponen_utama = 0;
      end;
      SELECT IFNULL(nilai_dbkb_jpb12,0)
      INTO 	vln_nilai_komponen_utama
      FROM   dbkb_jpb12
      WHERE  kd_propinsi     = vlc_kd_propinsi
      AND  kd_dati2 		= vlc_kd_dati2
      AND  thn_dbkb_jpb12  = vlc_tahun
      AND  type_dbkb_jpb12 = vlc_type_jpb12;
   END;
   BEGIN
      DECLARE EXIT HANDLER FOR NOT FOUND,SQLEXCEPTION
      begin
         SET vln_luas_bng       = 0;
         SET vlc_tahun_dibangun = null;
         SET vlc_tahun_renovasi = null;
         SET vlc_kondisi_bng    = null;
         SET vln_jml_lantai_bng = 0;
      end;
      SELECT IFNULL(luas_bng,0),
thn_dibangun_bng,
thn_renovasi_bng,
kondisi_bng,
jml_lantai_bng
      INTO 	vln_luas_bng,vlc_tahun_dibangun,vlc_tahun_renovasi,vlc_kondisi_bng,vln_jml_lantai_bng
      FROM 	dat_op_bangunan
      WHERE  kd_propinsi  = vlc_kd_propinsi
      AND  kd_dati2 	 = vlc_kd_dati2
      AND  kd_kecamatan = vlc_kd_kecamatan
      AND  kd_kelurahan = vlc_kd_kelurahan
      AND  kd_blok 	 = vlc_kd_blok
      AND  no_urut 	 = vlc_no_urut
      AND  kd_jns_op 	 = vlc_kd_jns_op
      AND  no_bng 	  	 = vln_no_bng
      AND  kd_jpb 	  	 = '12';
   END;
   SET vln_nilai_fasilitas = 0;
   CALL FASILITAS_SUSUT_X_LUAS(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
   vlc_no_urut,vlc_kd_jns_op,vln_no_bng,'12',vlc_type_jpb12,vlc_tahun,
   vln_nilai_fasilitas);
   SET vln_nilai_total_per_m2 = vln_nilai_komponen_utama+vln_nilai_fasilitas;
   SET vln_nilai_total_kali_luas = vln_nilai_total_per_m2*vln_luas_bng;
   SET vln_nilai_fasilitas_susut = 0;
   CALL FASILITAS_SUSUT(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
   vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vln_jml_lantai_bng,vlc_tahun,
   vln_nilai_fasilitas_susut);
   SET vln_nilai_sebelum_susut = vln_nilai_total_kali_luas+vln_nilai_fasilitas_susut;
   SET vln_persentase_penyusutan = SUSUT(vlc_tahun,vlc_tahun_dibangun,vlc_tahun_renovasi,vlc_kondisi_bng,vln_nilai_sebelum_susut,
   vln_luas_bng,0);
   IF (vln_persentase_penyusutan IS NOT NULL) OR (vln_persentase_penyusutan = 0)  THEN
      SET vln_persentase_penyusutan  = round((vln_persentase_penyusutan/100),2);
      SET vln_nilai_setelah_susut    = vln_nilai_sebelum_susut -(vln_nilai_sebelum_susut*vln_persentase_penyusutan);
ELSE
      SET vln_nilai_setelah_susut    = vln_nilai_sebelum_susut;
   END IF;
   SET vln_nilai_fasilitas_tdk_susut = 0;
   CALL FASILITAS_TDK_SUSUT(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
   vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vlc_tahun,vln_nilai_fasilitas_tdk_susut);
   SET vln_nilai_jpb12 = vln_nilai_setelah_susut+vln_nilai_fasilitas_tdk_susut;
END;
