DROP PROCEDURE IF EXISTS `PENILAIAN_JPB13`;
--> statement-breakpoint
CREATE PROCEDURE `PENILAIAN_JPB13`(IN  vlc_kd_propinsi  CHAR(2),
IN  vlc_kd_dati2     CHAR(2),
IN  vlc_kd_kecamatan CHAR(3),
IN  vlc_kd_kelurahan CHAR(3),
IN  vlc_kd_blok      CHAR(3),
IN  vlc_no_urut      CHAR(4),
IN  vlc_kd_jns_op    CHAR(1),
IN  vln_no_bng       SMALLINT,
IN  vlc_tahun        CHAR(4),
OUT vln_nilai_jpb13  INT)
BEGIN
   DECLARE vln_penyusutan DECIMAL(17,2) DEFAULT 0; -- fas_tdk_susut
   DECLARE vlc_thn_dibangun_bng CHAR(4);
   DECLARE vlc_thn_renovasi_bng CHAR(4);
   DECLARE vln_luas_bng BIGINT;
   DECLARE vln_jml_lantai_bng SMALLINT;
   DECLARE vlc_kondisi_bng CHAR(1);
   DECLARE vln_nilai_dbkb_jpb13 DECIMAL(17,2) DEFAULT 0;
   DECLARE vlc_kls_jpb13 CHAR(1);
   DECLARE vln_jml_jpb13 DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_luas_jpb13 BIGINT;
   DECLARE vln_luas_jpb13_lain BIGINT;
   DECLARE vln_jml_satuan INT DEFAULT 0;
   DECLARE vlc_kd_fasilitas CHAR(2);
   DECLARE vlc_status_fasilitas CHAR(1);
   DECLARE vlc_ketergantungan CHAR(1);
   DECLARE vln_nilai_fasilitas DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_satuan DECIMAL(17,2) DEFAULT 0;
   DECLARE NO_DATA INT DEFAULT 0;
   DECLARE cur_fasilitas CURSOR FOR SELECT status_fasilitas,
kd_fasilitas,
ketergantungan
   FROM   fasilitas
   WHERE  status_fasilitas IN('0','1','2','3')
   ORDER  BY status_fasilitas,kd_fasilitas,ketergantungan;
   DECLARE CONTINUE HANDLER FOR NOT FOUND SET NO_DATA = -1;
/*OLEH : TEGUH
TANGGAL     :
REVISI KE   : 1
DIREVISI    : TEGUH, RACHMAT
TGL. REVISI : 09-10-2000
*/-- ------------------
   BEGIN
      DECLARE EXIT HANDLER FOR SQLEXCEPTION
      begin
         SET vlc_thn_dibangun_bng = null;
         SET vlc_thn_renovasi_bng = null;
         SET vln_luas_bng		   = 0;
         SET vln_jml_lantai_bng   = 0;
         SET vlc_kondisi_bng	   = null;
         SET vlc_kls_jpb13		   = null;
         SET vln_jml_jpb13		   = 0;
         SET vln_luas_jpb13	   = 0;
         SET vln_luas_jpb13_lain  = 0;
      end;
      SELECT a.thn_dibangun_bng,
a.thn_renovasi_bng,
IFNULL(a.luas_bng,0),
IFNULL(a.jml_lantai_bng,0),
a.kondisi_bng,
b.kls_jpb13,
IFNULL(b.jml_jpb13,0),
IFNULL(b.luas_jpb13_dgn_ac_sent,0),
IFNULL(b.luas_jpb13_lain_dgn_ac_sent,0)
      INTO   vlc_thn_dibangun_bng,vlc_thn_renovasi_bng,vln_luas_bng,vln_jml_lantai_bng,
      vlc_kondisi_bng,vlc_kls_jpb13,vln_jml_jpb13,vln_luas_jpb13,vln_luas_jpb13_lain
      FROM   dat_op_bangunan a LEFT OUTER JOIN dat_jpb13 b ON b.kd_propinsi   = a.kd_propinsi AND b.kd_dati2      = a.kd_dati2 AND b.kd_kecamatan  = a.kd_kecamatan AND b.kd_kelurahan  = a.kd_kelurahan AND b.kd_blok       = a.kd_blok AND b.no_urut       = a.no_urut AND b.kd_jns_op     = a.kd_jns_op AND b.no_bng        = a.no_bng
      WHERE  a.kd_propinsi      = vlc_kd_propinsi AND a.kd_dati2         = vlc_kd_dati2 AND a.kd_kecamatan     = vlc_kd_kecamatan AND a.kd_kelurahan     = vlc_kd_kelurahan AND a.kd_blok          = vlc_kd_blok AND a.no_urut          = vlc_no_urut AND a.kd_jns_op        = vlc_kd_jns_op AND a.no_bng           = vln_no_bng AND a.kd_jpb           = '13';
   END;
   BEGIN
      DECLARE EXIT HANDLER FOR SQLEXCEPTION
      begin
         SET vln_nilai_dbkb_jpb13 = 0;
      end;
      SELECT nilai_dbkb_jpb13 INTO vln_nilai_dbkb_jpb13
      FROM   dbkb_jpb13
      WHERE  kd_propinsi       = vlc_kd_propinsi     AND
      kd_dati2          = vlc_kd_dati2        AND
      thn_dbkb_jpb13    = vlc_tahun           AND
      kls_dbkb_jpb13    = vlc_kls_jpb13       AND
      lantai_min_jpb13 <= vln_jml_lantai_bng  AND
      lantai_max_jpb13 >= vln_jml_lantai_bng;
   END;
   SET vln_nilai_dbkb_jpb13 = vln_nilai_dbkb_jpb13*vln_luas_bng;
   -- NOT SUPPORTED PRINTCONCAT('nilai material * luas bng = ', vln_nilai_dbkb_jpb13)
SET vln_nilai_fasilitas = 0;
   OPEN  cur_fasilitas;
   SWL_Label:
   LOOP
      SET NO_DATA = 0;
      FETCH cur_fasilitas INTO vlc_status_fasilitas,vlc_kd_fasilitas,vlc_ketergantungan;
      IF NO_DATA <> 0 THEN
         LEAVE SWL_Label;
      END IF;
      BEGIN
         DECLARE EXIT HANDLER FOR NOT FOUND
         begin
            SET vln_jml_satuan = 0;
         end;
         SELECT IFNULL(jml_satuan,0) INTO vln_jml_satuan
         FROM   dat_fasilitas_bangunan
         WHERE  kd_propinsi  = vlc_kd_propinsi  AND
         kd_dati2     = vlc_kd_dati2	   AND
         kd_kecamatan = vlc_kd_kecamatan AND
         kd_kelurahan = vlc_kd_kelurahan AND
         kd_blok      = vlc_kd_blok      AND
         no_urut      = vlc_no_urut  	   AND
         kd_jns_op    = vlc_kd_jns_op    AND
         no_bng       = vln_no_bng       AND
         kd_fasilitas = vlc_kd_fasilitas;
      END;
      IF vlc_ketergantungan = '0' THEN
         BEGIN
            DECLARE EXIT HANDLER FOR NOT FOUND
            begin
               SET vln_nilai_satuan = 0;
            end;
            SELECT IFNULL(nilai_non_dep,0) INTO vln_nilai_satuan
            FROM   fas_non_dep
            WHERE  kd_propinsi  = vlc_kd_propinsi  AND
            kd_dati2     = vlc_kd_dati2     AND
            thn_non_dep  = vlc_tahun        AND
            kd_fasilitas = vlc_kd_fasilitas;
         END;
      ELSEIF vlc_ketergantungan = '1' THEN
         BEGIN
            DECLARE EXIT HANDLER FOR NOT FOUND
            begin
               SET vln_nilai_satuan = 0;
            end;
            SELECT IFNULL(nilai_dep_min_max,0) INTO vln_nilai_satuan
            FROM   fas_dep_min_max
            WHERE  kd_propinsi     = vlc_kd_propinsi  AND
            kd_dati2        = vlc_kd_dati2     AND
            thn_dep_min_max = vlc_tahun        AND
            kd_fasilitas    = vlc_kd_fasilitas AND
            kls_dep_min    <= vln_jml_satuan   AND
            kls_dep_max    >= vln_jml_satuan;
         END;
      ELSEIF vlc_ketergantungan = '2' THEN
         BEGIN
            DECLARE EXIT HANDLER FOR NOT FOUND
            begin
               SET vln_nilai_satuan = 0;
            end;
            SELECT IFNULL(nilai_fasilitas_kls_bintang,0) INTO vln_nilai_satuan
            FROM   fas_dep_jpb_kls_bintang
            WHERE  kd_propinsi     	   			= vlc_kd_propinsi   AND
            kd_dati2        	   			= vlc_kd_dati2      AND
            thn_dep_jpb_kls_bintang 		= vlc_tahun         AND
            kd_fasilitas    	   			= vlc_kd_fasilitas  AND
            kd_jpb		   				= '13'              AND
            kls_bintang    	   			= vlc_kls_jpb13;
         END;
      ELSE 
         SET vln_nilai_satuan = 0;
      END IF;
      -- NOT SUPPORTED PRINTCONCAT('kode fasilitas + nilai satuan = ',vlc_kd_fasilitas,' ', vln_nilai_satuan)
IF vlc_status_fasilitas = '0'  THEN
         SET vln_nilai_fasilitas = vln_nilai_fasilitas+(vln_nilai_satuan*vln_jml_satuan*vln_luas_bng);
      ELSEIF vlc_status_fasilitas = '1'  THEN
         SET vln_nilai_fasilitas = vln_nilai_fasilitas+(vln_nilai_satuan*vln_jml_jpb13);
      ELSEIF vlc_status_fasilitas = '2'  THEN
         SET vln_nilai_fasilitas = vln_nilai_fasilitas+(vln_nilai_satuan*vln_luas_jpb13);
      ELSEIF vlc_status_fasilitas = '3'  THEN
         SET vln_nilai_fasilitas = vln_nilai_fasilitas+(vln_nilai_satuan*vln_luas_jpb13_lain);
      ELSE 
         SET vln_nilai_fasilitas = vln_nilai_fasilitas;
      END IF;
   END LOOP;
   CLOSE cur_fasilitas;
   -- NOT SUPPORTED PRINTCONCAT('nilai fasilitas dip luas + selain fas lain = ', vln_nilai_fasilitas)
SET vln_nilai_jpb13     = vln_nilai_dbkb_jpb13+vln_nilai_fasilitas;
   -- NOT SUPPORTED PRINTCONCAT('komp utama + fasili = ', vln_nilai_jpb13)
CALL FASILITAS_SUSUT(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
   vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vln_jml_lantai_bng,vlc_tahun,
   vln_nilai_fasilitas);
   -- NOT SUPPORTED PRINTCONCAT('nilai fasilitas susut = ', vln_nilai_fasilitas)
SET vln_nilai_jpb13     = vln_nilai_jpb13+vln_nilai_fasilitas;
   -- NOT SUPPORTED PRINTCONCAT('nilai + fas susut = ', vln_nilai_jpb13)
SET vln_penyusutan     = SUSUT(vlc_tahun,vlc_thn_dibangun_bng,vlc_thn_renovasi_bng,vlc_kondisi_bng,vln_nilai_jpb13,
   vln_luas_bng,0);
   SET vln_penyusutan     = ROUND((vln_penyusutan*vln_nilai_jpb13)/100);
   SET vln_nilai_jpb13     = vln_nilai_jpb13 -vln_penyusutan;
   CALL FASILITAS_TDK_SUSUT(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
   vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vlc_tahun,vln_nilai_fasilitas);
   SET vln_nilai_jpb13     = vln_nilai_jpb13+vln_nilai_fasilitas;
END;
--> statement-breakpoint

DROP PROCEDURE IF EXISTS `PENILAIAN_JPB14`;
