CREATE PROCEDURE `PENILAIAN_JPB14`(IN  vlc_kd_propinsi  CHAR(2),
IN  vlc_kd_dati2     CHAR(2),
IN  vlc_kd_kecamatan CHAR(3),
IN  vlc_kd_kelurahan CHAR(3),
IN  vlc_kd_blok      CHAR(3),
IN  vlc_no_urut      CHAR(4),
IN  vlc_kd_jns_op    CHAR(1),
IN  vln_no_bng       SMALLINT,
IN  vlc_tahun        CHAR(4),
OUT vln_nilai_jpb14  INT)
BEGIN
   DECLARE vln_penyusutan DECIMAL(17,2) DEFAULT 0; -- fas_tdk_susut
   DECLARE vlc_thn_dibangun_bng CHAR(4);
   DECLARE vlc_thn_renovasi_bng CHAR(4);
   DECLARE vln_luas_bng BIGINT;
   DECLARE vln_jml_lantai_bng SMALLINT;
   DECLARE vlc_kondisi_bng CHAR(1);
   DECLARE vln_nilai_dbkb_jpb14 DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_fasilitas DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_fasilitas_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_fasilitas_tdk_susut DECIMAL(17,2) DEFAULT 0;
/*OLEH : TEGUH
TANGGAL     :
REVISI KE   : 1
DIREVISI    : TEGUH, RACHMAT
TGL. REVISI : 09-10-2000
*/-- ------------------
   BEGIN
      DECLARE EXIT HANDLER FOR NOT FOUND,SQLEXCEPTION
      begin
         SET vlc_thn_dibangun_bng = null;
         SET vlc_thn_renovasi_bng = null;
         SET vln_luas_bng		   = 0;
         SET vln_jml_lantai_bng   = 0;
         SET vlc_kondisi_bng	   = null;
      end;
      SELECT thn_dibangun_bng,
thn_renovasi_bng,
IFNULL(luas_bng,0),
IFNULL(jml_lantai_bng,0),
IFNULL(kondisi_bng,'4')
      INTO   vlc_thn_dibangun_bng,vlc_thn_renovasi_bng,vln_luas_bng,vln_jml_lantai_bng,
      vlc_kondisi_bng
      FROM   dat_op_bangunan
      WHERE  kd_propinsi      = vlc_kd_propinsi  AND
      kd_dati2         = vlc_kd_dati2     AND
      kd_kecamatan     = vlc_kd_kecamatan AND
      kd_kelurahan     = vlc_kd_kelurahan AND
      kd_blok          = vlc_kd_blok      AND
      no_urut          = vlc_no_urut      AND
      kd_jns_op        = vlc_kd_jns_op    AND
      no_bng           = vln_no_bng       AND
      kd_jpb           = '14';
   END;
   BEGIN
      DECLARE EXIT HANDLER FOR NOT FOUND,SQLEXCEPTION
      begin
         SET vln_nilai_dbkb_jpb14 = 0;
      end;
      SELECT nilai_dbkb_jpb14
      INTO   vln_nilai_dbkb_jpb14
      FROM   dbkb_jpb14
      WHERE  kd_propinsi       = vlc_kd_propinsi    AND
      kd_dati2          = vlc_kd_dati2       AND
      thn_dbkb_jpb14    = vlc_tahun;
   END;
   SET vln_nilai_jpb14 	   = vln_nilai_dbkb_jpb14*vln_luas_bng;
   SET vln_nilai_fasilitas  = 0;
   CALL FASILITAS_SUSUT(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
   vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vln_jml_lantai_bng,vlc_tahun,
   vln_nilai_fasilitas);
   SET vln_nilai_jpb14      = vln_nilai_jpb14+IFNULL(vln_nilai_fasilitas,0);
   SET vln_penyusutan       = SUSUT(vlc_tahun,vlc_thn_dibangun_bng,vlc_thn_renovasi_bng,vlc_kondisi_bng,vln_nilai_jpb14,
   vln_luas_bng,0);
   SET vln_penyusutan       = ROUND((vln_penyusutan*vln_nilai_jpb14)/100);
   SET vln_nilai_jpb14      = vln_nilai_jpb14 -vln_penyusutan;
   SET vln_nilai_fasilitas  = 0;
   CALL FASILITAS_TDK_SUSUT(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
   vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vlc_tahun,vln_nilai_fasilitas);
   SET vln_nilai_jpb14      = vln_nilai_jpb14+vln_nilai_fasilitas;
END;
