DROP PROCEDURE IF EXISTS `PENILAIAN_JPB15`;
--> statement-breakpoint
CREATE PROCEDURE `PENILAIAN_JPB15`(IN  vlc_kd_prop     CHAR(2),
IN  vlc_kd_dati2    CHAR(2),
IN  vlc_kd_kec 	   CHAR(3),
IN  vlc_kd_kel 	   CHAR(3),
IN  vlc_kd_blok 	   CHAR(3),
IN  vlc_no_urut 	   CHAR(4),
IN  vlc_kd_jns_op   CHAR(1),
IN  vln_no_bng 	   SMALLINT,
IN  vlc_tahun 	   CHAR(4),
OUT vln_nilai_jpb15 INT)
BEGIN
   DECLARE vln_luas_bng BIGINT;
   DECLARE vlc_kondisi_bng CHAR(1);
   DECLARE vln_jml_lantai_bng SMALLINT;
   DECLARE vlc_thn_dibangun CHAR(4);
   DECLARE vlc_thn_renovasi CHAR(4);
   DECLARE vln_besar_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_persen_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE vlc_letak_tangki_jpb15 CHAR(1);
   DECLARE vln_kapasitas_tangki DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_dbkb DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_tahun SMALLINT;
   DECLARE vln_tahun_dibangun SMALLINT;
   DECLARE vln_tahun_renovasi SMALLINT;
   DECLARE vln_umur_efektif INT;
   DECLARE EXIT HANDLER FOR NOT FOUND,SQLEXCEPTION
   begin
      SET vln_nilai_jpb15 = 0;
   end;
/*OLEH : SUNARYO
TANGGAL     :
REVISI KE   : 1
DIREVISI    : TEGUH, RACHMAT
TGL. REVISI : 09-10-2000
*/-- ------------------
   SELECT luas_bng,
thn_dibangun_bng,
thn_renovasi_bng,
kondisi_bng
   INTO   vln_luas_bng,vlc_thn_dibangun,vlc_thn_renovasi,vlc_kondisi_bng
   FROM   dat_op_bangunan
   WHERE  kd_propinsi   = vlc_kd_prop   AND
   kd_dati2 		= vlc_kd_dati2  AND
   kd_kecamatan  = vlc_kd_kec    AND
   kd_kelurahan  = vlc_kd_kel    AND
   kd_blok 		= vlc_kd_blok   AND
   no_urut 		= vlc_no_urut   AND
   kd_jns_op  	= vlc_kd_jns_op AND
   no_bng 		= vln_no_bng;
   IF ROW_COUNT() <> 0 THEN
      BEGIN
         DECLARE EXIT HANDLER FOR NOT FOUND,SQLEXCEPTION
         begin
            SET vlc_letak_tangki_jpb15 = null;
            SET vln_kapasitas_tangki   = 0;
         end;
         SELECT letak_tangki_jpb15,
kapasitas_tangki_jpb15
         INTO   vlc_letak_tangki_jpb15,vln_kapasitas_tangki
         FROM   dat_jpb15
         WHERE (kd_propinsi   = vlc_kd_prop   AND
         kd_dati2      = vlc_kd_dati2  AND
         kd_kecamatan  = vlc_kd_kec    AND
         kd_kelurahan  = vlc_kd_kel    AND
         kd_blok       = vlc_kd_blok   AND
         no_urut       = vlc_no_urut   AND
         kd_jns_op     = vlc_kd_jns_op AND
         no_bng        = vln_no_bng);
      END;
      SET vln_nilai_dbkb = 0;
      BEGIN
         DECLARE EXIT HANDLER FOR NOT FOUND,SQLEXCEPTION
         begin
            SET vln_nilai_dbkb = 0;
         end;
         SELECT nilai_dbkb_jpb15
         INTO   vln_nilai_dbkb
         FROM   dbkb_jpb15
         WHERE  kd_propinsi               = vlc_kd_prop            AND
         kd_dati2                  = vlc_kd_dati2 			 AND
         thn_dbkb_jpb15            = vlc_tahun 			 AND
         jns_tangki_dbkb_jpb15     = vlc_letak_tangki_jpb15 AND
         kapasitas_min_dbkb_jpb15 <= vln_kapasitas_tangki 	 AND
         kapasitas_max_dbkb_jpb15 >= vln_kapasitas_tangki;
      END;
      SET vln_tahun          = CAST(IFNULL(vlc_tahun,0) AS unsigned);
      SET vln_tahun_dibangun = CAST(IFNULL(vlc_thn_dibangun,0) AS unsigned);
      SET vln_tahun_renovasi = CAST(IFNULL(vlc_thn_renovasi,0) AS unsigned);
      IF vln_tahun_dibangun > 0 THEN
         IF vln_tahun_renovasi > 0 THEN
            IF(vln_tahun -vln_tahun_renovasi) > 10 THEN
               SET vln_umur_efektif = ROUND(((vln_tahun -vln_tahun_dibangun)+(2*10))/3);
            ELSEIF(vln_tahun -vln_tahun_renovasi) <= 10 THEN
               SET vln_umur_efektif = ROUND(((vln_tahun -vln_tahun_dibangun)+(2*(vln_tahun -vln_tahun_renovasi)))/3);
         ELSE
               SET vln_umur_efektif = 0;
            END IF;
      ELSE
            IF(vln_tahun -vln_tahun_dibangun) > 10 THEN
               SET vln_umur_efektif = ROUND(((vln_tahun -vln_tahun_dibangun)+(2*10))/3);
            ELSEIF(vln_tahun -vln_tahun_dibangun) <= 10 THEN
               SET vln_umur_efektif = vln_tahun -vln_tahun_dibangun;
         ELSE
               SET vln_umur_efektif = 0;
            END IF;
         END IF;
   ELSE
         SET vln_umur_efektif = 0;
      END IF;
      IF vln_umur_efektif > 40 THEN
         SET vln_umur_efektif = 40;
      END IF;
      SET vln_besar_susut = IFNULL(vln_umur_efektif,0)*5;
      IF (vln_besar_susut IS NOT NULL) OR (vln_besar_susut = 0) THEN
         IF vln_besar_susut > 50 THEN
            SET vln_besar_susut = 50;
         END IF;
         SET vln_persen_susut    = round((vln_besar_susut/100),2);
         SET vln_nilai_jpb15 	 =(vln_nilai_dbkb -(vln_nilai_dbkb*vln_persen_susut));
   ELSE
         SET vln_nilai_jpb15 	 = vln_nilai_dbkb;
      END IF;
ELSE
      SET vln_nilai_jpb15 = 0;
   END IF;
END;
--> statement-breakpoint

