CREATE PROCEDURE `PENILAIAN_JPB16`(IN  vlc_kd_prop     CHAR(2),
IN  vlc_kd_dati2    CHAR(2),
IN  vlc_kd_kec 	   CHAR(3),
IN  vlc_kd_kel 	   CHAR(3),
IN  vlc_kd_blok 	   CHAR(3),
IN  vlc_no_urut 	   CHAR(4),
IN  vlc_kd_jns_op   CHAR(1),
IN  vln_no_bng 	   SMALLINT,
IN  vlc_tahun 	   CHAR(4),
OUT vln_nilai_jpb16 INT)
BEGIN
   DECLARE vlc_kls_jpb16 CHAR(1);
   DECLARE vln_nilai_dbkb_jpb16 DECIMAL(17,2) DEFAULT 0;
   DECLARE vlc_kd_jpb CHAR(2);
   DECLARE vln_luas_bng BIGINT;
   DECLARE vlc_kondisi_bng CHAR(1);
   DECLARE vln_jml_lantai_bng SMALLINT;
   DECLARE vln_komp_utama DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_fas1 DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_fas2 DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_fas3 DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai1 DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_sbl_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_stl_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE vlc_thn_dibangun CHAR(4);
   DECLARE vlc_thn_renovasi CHAR(4);
   DECLARE vln_besar_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_persen_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE EXIT HANDLER FOR NOT FOUND
   begin
      SET vln_nilai_jpb16 = 0;
   end;
/*OLEH : SUNARYO
TANGGAL     :
REVISI KE   : 1
DIREVISI    : TEGUH, RACHMAT
TGL. REVISI : 09-10-2000
*/-- ------------------
   SELECT kd_jpb,
luas_bng,
thn_dibangun_bng,
thn_renovasi_bng,
kondisi_bng,
jml_lantai_bng
   INTO   vlc_kd_jpb,vln_luas_bng,vlc_thn_dibangun,vlc_thn_renovasi,vlc_kondisi_bng,
   vln_jml_lantai_bng
   FROM   dat_op_bangunan
   WHERE  kd_propinsi   = vlc_kd_prop    AND
   kd_dati2 	    = vlc_kd_dati2   AND
   kd_kecamatan  = vlc_kd_kec     AND
   kd_kelurahan  = vlc_kd_kel     AND
   kd_blok 	    = vlc_kd_blok    AND
   no_urut 	    = vlc_no_urut    AND
   kd_jns_op  	= vlc_kd_jns_op  AND
   no_bng 		= vln_no_bng;
   IF ROW_COUNT() <> 0 THEN
      BEGIN
         DECLARE EXIT HANDLER FOR NOT FOUND
         begin
            SET vlc_kls_jpb16 = null;
         end;
         SELECT kls_jpb16
         INTO   vlc_kls_jpb16
         FROM   dat_jpb16
         WHERE  kd_propinsi   = vlc_kd_prop    AND
         kd_dati2 	   = vlc_kd_dati2   AND
         kd_kecamatan  = vlc_kd_kec     AND
         kd_kelurahan  = vlc_kd_kel     AND
         kd_blok 	   = vlc_kd_blok    AND
         no_urut 	   = vlc_no_urut    AND
         kd_jns_op     = vlc_kd_jns_op  AND
         no_bng 	   = vln_no_bng;
      END;
      BEGIN
         DECLARE EXIT HANDLER FOR NOT FOUND
         begin
            SET vln_nilai_dbkb_jpb16 = 0;
         end;
         SELECT nilai_dbkb_jpb16
         INTO   vln_nilai_dbkb_jpb16
         FROM   dbkb_jpb16
         WHERE  kd_propinsi      = vlc_kd_prop        AND
         kd_dati2         = vlc_kd_dati2 	   AND
         thn_dbkb_jpb16    = vlc_tahun 	  	   AND
         kls_dbkb_jpb16    = vlc_kls_jpb16       AND
         lantai_min_jpb16 <= vln_jml_lantai_bng AND
         lantai_max_jpb16 >= vln_jml_lantai_bng;
      END;
      SET vln_komp_utama = vln_nilai_dbkb_jpb16;
      CALL FASILITAS_SUSUT_X_LUAS(vlc_kd_prop,vlc_kd_dati2,vlc_kd_kec,vlc_kd_kel,vlc_kd_blok,vlc_no_urut,
      vlc_kd_jns_op,vln_no_bng,vlc_kd_jpb,vlc_kls_jpb16,vlc_tahun,vln_nilai_fas1);
      SET vln_nilai1 =(IFNULL(vln_komp_utama,0)+IFNULL(vln_nilai_fas1,0))*IFNULL(vln_luas_bng,0);
      CALL FASILITAS_SUSUT(vlc_kd_prop,vlc_kd_dati2,vlc_kd_kec,vlc_kd_kel,vlc_kd_blok,vlc_no_urut,
      vlc_kd_jns_op,vln_no_bng,vln_jml_lantai_bng,vlc_tahun,vln_nilai_fas2);
      SET vln_nilai_sbl_susut = IFNULL(vln_nilai1,0)+IFNULL(vln_nilai_fas2,0);
      SET vln_besar_susut = SUSUT(vlc_tahun,vlc_thn_dibangun,vlc_thn_renovasi,vlc_kondisi_bng,vln_nilai_sbl_susut,
      vln_luas_bng,0);
      IF (vln_besar_susut IS NOT NULL) OR (vln_besar_susut = 0) THEN
         SET vln_persen_susut    = round(vln_besar_susut/100,2);
         SET vln_nilai_stl_susut =(vln_nilai_sbl_susut -(vln_nilai_sbl_susut*vln_persen_susut));
   ELSE
         SET vln_nilai_stl_susut = vln_nilai_sbl_susut;
      END IF;
      CALL FASILITAS_TDK_SUSUT(vlc_kd_prop,vlc_kd_dati2,vlc_kd_kec,vlc_kd_kel,vlc_kd_blok,vlc_no_urut,
      vlc_kd_jns_op,vln_no_bng,vlc_tahun,vln_nilai_fas3);
      SET vln_nilai_jpb16 = vln_nilai_stl_susut+IFNULL(vln_nilai_fas3,0);
ELSE
      SET vln_nilai_jpb16 = 0;
   END IF;
END;
--> statement-breakpoint

DROP PROCEDURE IF EXISTS `PENILAIAN_JPB2`;
