DROP PROCEDURE IF EXISTS `PENILAIAN_JPB7`;
--> statement-breakpoint
CREATE PROCEDURE `PENILAIAN_JPB7`(IN  vlc_kd_propinsi  CHAR(2),
IN  vlc_kd_dati2     CHAR(2),
IN  vlc_kd_kecamatan CHAR(3),
IN  vlc_kd_kelurahan CHAR(3),
IN  vlc_kd_blok      CHAR(3),
IN  vlc_no_urut      CHAR(4),
IN  vlc_kd_jns_op    CHAR(1),
IN  vln_no_bng       SMALLINT,
IN  vlc_tahun        CHAR(4),
OUT vln_nilai_jpb7   INT)
BEGIN
   DECLARE vln_penyusutan DECIMAL(17,2) DEFAULT 0; -- fas_tdk_susut
   DECLARE vlc_thn_dibangun_bng CHAR(4);
   DECLARE vlc_thn_renovasi_bng CHAR(4);
   DECLARE vln_luas_bng BIGINT;
   DECLARE vln_jml_lantai_bng SMALLINT;
   DECLARE vlc_kondisi_bng CHAR(1);
   DECLARE vln_nilai_dbkb_jpb7 DECIMAL(17,2) DEFAULT 0;
   DECLARE vlc_jns_jpb7 CHAR(1);
   DECLARE vlc_bintang_jpb7 CHAR(1);
   DECLARE vln_jml_kmr_jpb7 SMALLINT DEFAULT 0;
   DECLARE vln_luas_jpb7 BIGINT;
   DECLARE vln_luas_jpb7_lain BIGINT DEFAULT 0;
   DECLARE vln_jml_satuan INT DEFAULT 0;
   DECLARE vlc_kd_fasilitas CHAR(2);
   DECLARE vlc_status_fasilitas CHAR(1);
   DECLARE vlc_ketergantungan CHAR(1);
   DECLARE vln_nilai_fasilitas DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_fasilitas_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_fasilitas_tdk_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_satuan DECIMAL(17,2) DEFAULT 0;
   DECLARE NO_DATA INT DEFAULT 0;
   DECLARE cur_fasilitas CURSOR FOR SELECT status_fasilitas, kd_fasilitas, ketergantungan
   FROM   fasilitas
   WHERE  status_fasilitas IN('0','1','2','3')
   ORDER  BY status_fasilitas,kd_fasilitas,ketergantungan;
   DECLARE CONTINUE HANDLER FOR NOT FOUND SET NO_DATA = -1;
/*OLEH : TEGUH
TANGGAL     :
REVISI KE   : 1
DIREVISI    : TEGUH, RACHMAT
TGL. REVISI : 09-10-2000
*/-- ------------------
   BEGIN
      DECLARE EXIT HANDLER FOR SQLEXCEPTION
      begin
         SET vlc_thn_dibangun_bng = null;
         SET vlc_thn_renovasi_bng = null;
         SET vln_luas_bng		   = 0;
         SET vln_jml_lantai_bng   = 0;
         SET vlc_kondisi_bng	   = null;
         SET vlc_jns_jpb7		   = null;
         SET vlc_bintang_jpb7	   = null;
         SET vln_jml_kmr_jpb7	   = null;
         SET vln_luas_jpb7		   = 0;
         SET vln_luas_jpb7_lain   = 0;
      end;
      SELECT a.thn_dibangun_bng,
a.thn_renovasi_bng,
IFNULL(a.luas_bng,0),
IFNULL(a.jml_lantai_bng,0),
a.kondisi_bng,
b.jns_jpb7,
b.bintang_jpb7,
IFNULL(b.jml_kmr_jpb7,0),
IFNULL(b.luas_kmr_jpb7_dgn_ac_sent,0),
IFNULL(b.luas_kmr_lain_jpb7_dgn_ac_sent,0)
      INTO   vlc_thn_dibangun_bng,vlc_thn_renovasi_bng,vln_luas_bng,vln_jml_lantai_bng,
      vlc_kondisi_bng,vlc_jns_jpb7,vlc_bintang_jpb7,vln_jml_kmr_jpb7,vln_luas_jpb7,
      vln_luas_jpb7_lain
      FROM   dat_op_bangunan a LEFT OUTER JOIN dat_jpb7 b ON b.kd_propinsi   = a.kd_propinsi AND b.kd_dati2      = a.kd_dati2 AND b.kd_kecamatan  = a.kd_kecamatan AND b.kd_kelurahan  = a.kd_kelurahan AND b.kd_blok       = a.kd_blok AND b.no_urut       = a.no_urut AND b.kd_jns_op     = a.kd_jns_op AND b.no_bng        = a.no_bng
      WHERE  a.kd_propinsi      = vlc_kd_propinsi AND a.kd_dati2         = vlc_kd_dati2 AND a.kd_kecamatan     = vlc_kd_kecamatan AND a.kd_kelurahan     = vlc_kd_kelurahan AND a.kd_blok          = vlc_kd_blok AND a.no_urut          = vlc_no_urut AND a.kd_jns_op        = vlc_kd_jns_op AND a.no_bng           = vln_no_bng AND a.kd_jpb           = '07';
   END;
   IF vlc_bintang_jpb7 = '0' THEN
      SET vlc_bintang_jpb7 = '5';
   END IF;
   BEGIN
      DECLARE EXIT HANDLER FOR SQLEXCEPTION
      begin
         SET vln_nilai_dbkb_jpb7 = 0;
      end;
      SELECT nilai_dbkb_jpb7
      INTO   vln_nilai_dbkb_jpb7
      FROM   dbkb_jpb7
      WHERE  kd_propinsi       = vlc_kd_propinsi     AND
      kd_dati2          = vlc_kd_dati2        AND
      thn_dbkb_jpb7     = vlc_tahun           AND
      jns_dbkb_jpb7 	= vlc_jns_jpb7    	  AND
      bintang_dbkb_jpb7 = vlc_bintang_jpb7    AND
      lantai_min_jpb7  <= vln_jml_lantai_bng  AND
      lantai_max_jpb7  >= vln_jml_lantai_bng;
   END;
   SET vln_nilai_dbkb_jpb7 = vln_nilai_dbkb_jpb7*vln_luas_bng;
   SET vln_nilai_fasilitas = 0;
   OPEN  cur_fasilitas;
   SWL_Label3:
   LOOP
      SET NO_DATA = 0;
      FETCH cur_fasilitas
      INTO  vlc_status_fasilitas,vlc_kd_fasilitas,vlc_ketergantungan;
      IF NO_DATA <> 0 THEN
         LEAVE SWL_Label3;
      END IF;
      BEGIN
         DECLARE EXIT HANDLER FOR NOT FOUND
         begin
            SET vln_jml_satuan = 0;
         end;
         SELECT IFNULL(jml_satuan,0)
         INTO   vln_jml_satuan
         FROM   dat_fasilitas_bangunan
         WHERE  kd_propinsi  = vlc_kd_propinsi  AND
         kd_dati2     = vlc_kd_dati2	   AND
         kd_kecamatan = vlc_kd_kecamatan AND
         kd_kelurahan = vlc_kd_kelurahan AND
         kd_blok      = vlc_kd_blok      AND
         no_urut      = vlc_no_urut  	   AND
         kd_jns_op    = vlc_kd_jns_op    AND
         no_bng       = vln_no_bng       AND
         kd_fasilitas = vlc_kd_fasilitas;
      END;
      IF vlc_ketergantungan = '0' THEN
         BEGIN
            DECLARE EXIT HANDLER FOR NOT FOUND
            begin
               SET vln_nilai_satuan = 0;
            end;
            SELECT IFNULL(nilai_non_dep,0)
            INTO 	vln_nilai_satuan
            FROM   fas_non_dep
            WHERE  kd_propinsi  = vlc_kd_propinsi  AND
            kd_dati2     = vlc_kd_dati2     AND
            thn_non_dep  = vlc_tahun        AND
            kd_fasilitas = vlc_kd_fasilitas;
         END;
      ELSEIF vlc_ketergantungan = '1' THEN
         BEGIN
            DECLARE EXIT HANDLER FOR NOT FOUND
            begin
               SET vln_nilai_satuan = 0;
            end;
            SELECT IFNULL(nilai_dep_min_max,0)
            INTO   vln_nilai_satuan
            FROM   fas_dep_min_max
            WHERE  kd_propinsi     = vlc_kd_propinsi  AND
            kd_dati2        = vlc_kd_dati2     AND
            thn_dep_min_max = vlc_tahun        AND
            kd_fasilitas    = vlc_kd_fasilitas AND
            kls_dep_min    <= vln_jml_satuan   AND
            kls_dep_max    >= vln_jml_satuan;
         END;
      ELSEIF vlc_ketergantungan = '2' THEN
         BEGIN
            DECLARE EXIT HANDLER FOR NOT FOUND
            begin
               SET vln_nilai_satuan = 0;
            end;
            SELECT IFNULL(nilai_fasilitas_kls_bintang,0)
            INTO   vln_nilai_satuan
            FROM   fas_dep_jpb_kls_bintang
            WHERE  kd_propinsi     	   		= vlc_kd_propinsi   AND
            kd_dati2        	   		= vlc_kd_dati2      AND
            thn_dep_jpb_kls_bintang 	= vlc_tahun         AND
            kd_fasilitas    	   		= vlc_kd_fasilitas  AND
            kd_jpb		   			= '07'              AND
            kls_bintang    	   		= vlc_bintang_jpb7;
         END;
      ELSE 
         SET vln_nilai_satuan = 0;
      END IF;
      IF vlc_status_fasilitas = '0'  THEN
         SET vln_nilai_fasilitas = vln_nilai_fasilitas+(vln_nilai_satuan*vln_jml_satuan*vln_luas_bng);
      ELSEIF vlc_status_fasilitas = '1'  THEN
         SET vln_nilai_fasilitas = vln_nilai_fasilitas+(vln_nilai_satuan*vln_jml_kmr_jpb7);
      ELSEIF vlc_status_fasilitas = '2'  THEN
         SET vln_nilai_fasilitas = vln_nilai_fasilitas+(vln_nilai_satuan*vln_luas_jpb7);
      ELSEIF vlc_status_fasilitas = '3'  THEN
         SET vln_nilai_fasilitas = vln_nilai_fasilitas+(vln_nilai_satuan*vln_luas_jpb7_lain);
      ELSE 
         SET vln_nilai_fasilitas = vln_nilai_fasilitas;
      END IF;
   END LOOP;
   CLOSE cur_fasilitas;
   SET vln_nilai_jpb7      = vln_nilai_dbkb_jpb7+vln_nilai_fasilitas;
   CALL FASILITAS_SUSUT(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
   vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vln_jml_lantai_bng,vlc_tahun,
   vln_fasilitas_susut);
   SET vln_nilai_jpb7      = vln_nilai_jpb7+IFNULL(vln_fasilitas_susut,0);
   SET vln_penyusutan     = SUSUT(vlc_tahun,vlc_thn_dibangun_bng,vlc_thn_renovasi_bng,vlc_kondisi_bng,vln_nilai_jpb7,
   vln_luas_bng,0);
   SET vln_penyusutan     = ROUND((vln_penyusutan*vln_nilai_jpb7)/100);
   SET vln_nilai_jpb7      = vln_nilai_jpb7 -vln_penyusutan;
   CALL FASILITAS_TDK_SUSUT(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
   vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vlc_tahun,vln_fasilitas_tdk_susut);
   SET vln_nilai_jpb7      = vln_nilai_jpb7+vln_fasilitas_tdk_susut;
END;
--> statement-breakpoint

DROP PROCEDURE IF EXISTS `PENILAIAN_JPB8`;
--> statement-breakpoint
CREATE PROCEDURE `PENILAIAN_JPB8`(IN  vlc_kd_propinsi  VARCHAR(4000),
IN  vlc_kd_dati2 	 VARCHAR(4000),
IN  vlc_kd_kecamatan VARCHAR(4000),
IN  vlc_kd_kelurahan VARCHAR(4000),
IN  vlc_kd_blok 	 VARCHAR(4000),
IN  vlc_no_urut 	 VARCHAR(4000),
IN  vlc_kd_jns_op 	 VARCHAR(4000),
IN  vln_no_bng 		 INT,
IN  vlc_tahun 		 VARCHAR(4000),
OUT vln_njop_jpb8 	 INT)
BEGIN
   DECLARE vln_tinggi_kolom SMALLINT DEFAULT 0;
   DECLARE vln_lebar_bentang SMALLINT DEFAULT 0;
   DECLARE vln_nilai_komponen_utama DECIMAL(17,2) DEFAULT 0;
   DECLARE vlc_atap CHAR(1);
   DECLARE vlc_lantai CHAR(1);
   DECLARE vlc_langit_langit CHAR(1);
   DECLARE vlc_dinding CHAR(1);
   DECLARE vln_jml_lantai_bng SMALLINT DEFAULT 0;
   DECLARE vln_nilai_atap DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_lantai DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_langit_langit DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_material DECIMAL(17,2) DEFAULT 0;
   DECLARE vlc_type_konstruksi CHAR(1);
   DECLARE vlc_cari_dinding CHAR(2);
   DECLARE vln_nilai_dinding DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_daya_dukung DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_fasilitas DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_total_per_m2 DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_luas_bng BIGINT DEFAULT 0;
   DECLARE vln_nilai_total_kali_luas DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_keliling_dinding DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_total_nilai_dinding DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_luas_mezzanine SMALLINT DEFAULT 0;
   DECLARE vln_nilai_mezzanine DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_total_mezzanine DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_fasilitas_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_sebelum_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE vlc_tahun_dibangun CHAR(4);
   DECLARE vlc_tahun_renovasi CHAR(4);
   DECLARE vln_umur_efektif SMALLINT DEFAULT 0;
   DECLARE vln_biaya_pengganti_baru DECIMAL(17,2) DEFAULT 0;
   DECLARE vlc_kondisi_bng CHAR(1);
   DECLARE vln_persentase_penyusutan DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_setelah_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_fasilitas_tdk_susut DECIMAL(17,2) DEFAULT 0;
/*OLEH : MADE
TANGGAL     :
REVISI KE   : 1
DIREVISI    : TEGUH, RACHMAT
TGL. REVISI : 09-10-2000
*/-- ------------------
   BEGIN
      DECLARE EXIT HANDLER FOR NOT FOUND,SQLEXCEPTION
      begin
         SET vln_tinggi_kolom	  = 0;
         SET vln_lebar_bentang	  = 0;
         SET vln_keliling_dinding = 0;
         SET vln_luas_mezzanine	  = 0;
         SET vlc_type_konstruksi  = null;
      end;
      SELECT IFNULL(ting_kolom_jpb8,0),
IFNULL(lbr_bent_jpb8,0),
IFNULL(keliling_dinding_jpb8,0),
IFNULL(luas_mezzanine_jpb8,0),
type_konstruksi
      INTO   vln_tinggi_kolom,vln_lebar_bentang,vln_keliling_dinding,vln_luas_mezzanine,
      vlc_type_konstruksi
      FROM   dat_jpb8
      WHERE  kd_propinsi  = vlc_kd_propinsi
      AND  kd_dati2     = vlc_kd_dati2
      AND  kd_kecamatan = vlc_kd_kecamatan
      AND  kd_kelurahan = vlc_kd_kelurahan
      AND  kd_blok 	  = vlc_kd_blok
      AND  no_urut 	  = vlc_no_urut
      AND  kd_jns_op 	  = vlc_kd_jns_op
      AND  no_bng 	  = vln_no_bng;
   END;
   BEGIN
      DECLARE EXIT HANDLER FOR NOT FOUND,SQLEXCEPTION
      begin
         SET vln_nilai_komponen_utama = 0;
      end;
      SELECT IFNULL(nilai_dbkb_jpb8,0)
      INTO 	 vln_nilai_komponen_utama
      FROM 	 dbkb_jpb8
      WHERE  kd_propinsi               = vlc_kd_propinsi
      AND  kd_dati2 				   = vlc_kd_dati2
      AND  thn_dbkb_jpb8 			   = vlc_tahun
      AND  lbr_bent_min_dbkb_jpb8   <= vln_lebar_bentang
      AND  lbr_bent_max_dbkb_jpb8   >= vln_lebar_bentang
      AND  ting_kolom_min_dbkb_jpb8 <= vln_tinggi_kolom
      AND  ting_kolom_max_dbkb_jpb8 >= vln_tinggi_kolom;
   END;
   BEGIN
      DECLARE EXIT HANDLER FOR NOT FOUND,SQLEXCEPTION
      begin
         SET vlc_atap	  		 = null;
         SET vlc_lantai			 = null;
         SET vlc_langit_langit	 = null;
         SET vln_luas_bng		 = 0;
         SET vlc_tahun_dibangun	 = null;
         SET vlc_tahun_renovasi	 = null;
         SET vlc_kondisi_bng	 = null;
         SET vlc_dinding		 = null;
         SET vln_jml_lantai_bng	 = 0;
      end;
      SELECT jns_atap_bng,
kd_lantai,
kd_langit_langit,
IFNULL(luas_bng,0),
thn_dibangun_bng,
thn_renovasi_bng,
kondisi_bng,
kd_dinding,
jml_lantai_bng
      INTO   vlc_atap,vlc_lantai,vlc_langit_langit,vln_luas_bng,vlc_tahun_dibangun,
      vlc_tahun_renovasi,vlc_kondisi_bng,vlc_dinding,vln_jml_lantai_bng
      FROM   dat_op_bangunan
      WHERE  kd_propinsi  = vlc_kd_propinsi
      AND  kd_dati2     = vlc_kd_dati2
      AND  kd_kecamatan = vlc_kd_kecamatan
      AND  kd_kelurahan = vlc_kd_kelurahan
      AND  kd_blok 	  = vlc_kd_blok
      AND  no_urut 	  = vlc_no_urut
      AND  kd_jns_op 	  = vlc_kd_jns_op
      AND  no_bng 	  = vln_no_bng
      AND  kd_jpb 	  = '08';
   END;
   BEGIN
      DECLARE EXIT HANDLER FOR NOT FOUND,SQLEXCEPTION
      begin
         SET vln_nilai_atap = 0;
      end;
      SELECT IFNULL(nilai_dbkb_material,0)
      INTO 	 vln_nilai_atap
      FROM 	 dbkb_material
      WHERE  kd_propinsi       = vlc_kd_propinsi
      AND  kd_dati2 		   = vlc_kd_dati2
      AND  thn_dbkb_material = vlc_tahun
      AND  kd_pekerjaan 	   = '23'
      AND  kd_kegiatan 	   = CONCAT('0',vlc_atap);
   END;
   SET vln_nilai_atap = vln_nilai_atap/IFNULL(vln_jml_lantai_bng,1);
   BEGIN
      DECLARE EXIT HANDLER FOR NOT FOUND,SQLEXCEPTION
      begin
         SET vln_nilai_lantai = 0;
      end;
      SELECT IFNULL(nilai_dbkb_material,0)
      INTO 	 vln_nilai_lantai
      FROM 	 dbkb_material
      WHERE  kd_propinsi       = vlc_kd_propinsi
      AND  kd_dati2 		   = vlc_kd_dati2
      AND  thn_dbkb_material = vlc_tahun
      AND  kd_pekerjaan 	   = '22'
      AND  kd_kegiatan 	   = CONCAT('0',vlc_lantai);
   END;
   BEGIN
      DECLARE EXIT HANDLER FOR NOT FOUND,SQLEXCEPTION
      begin
         SET vln_nilai_langit_langit = 0;
      end;
      SELECT IFNULL(nilai_dbkb_material,0)
      INTO 	 vln_nilai_langit_langit
      FROM 	 dbkb_material
      WHERE  kd_propinsi       = vlc_kd_propinsi
      AND  kd_dati2          = vlc_kd_dati2
      AND  thn_dbkb_material = vlc_tahun
      AND  kd_pekerjaan      = '24'
      AND  kd_kegiatan       = CONCAT('0',vlc_langit_langit);
   END;
   SET vln_nilai_material =(vln_nilai_atap+vln_nilai_lantai+vln_nilai_langit_langit);
   BEGIN
      DECLARE EXIT HANDLER FOR NOT FOUND,SQLEXCEPTION
      begin
         SET vln_nilai_daya_dukung = 0;
      end;
      SELECT IFNULL(nilai_dbkb_daya_dukung,0)
      INTO   vln_nilai_daya_dukung
      FROM 	 dbkb_daya_dukung
      WHERE  kd_propinsi          = vlc_kd_propinsi
      AND  kd_dati2             = vlc_kd_dati2
      AND  thn_dbkb_daya_dukung = vlc_tahun
      AND  type_konstruksi      = vlc_type_konstruksi;
   END;
   SET vln_nilai_fasilitas = 0;
   CALL FASILITAS_SUSUT_X_LUAS(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
   vlc_no_urut,vlc_kd_jns_op,vln_no_bng,'08',NULL,vlc_tahun,vln_nilai_fasilitas);
   SET vln_nilai_total_per_m2 = vln_nilai_komponen_utama+vln_nilai_material+vln_nilai_daya_dukung+vln_nilai_fasilitas;
   SET vln_nilai_total_kali_luas = vln_nilai_total_per_m2*vln_luas_bng;
   IF    vlc_dinding = '1' THEN 
      SET vlc_cari_dinding = '09'; -- bukan '01';
   ELSEIF vlc_dinding = '2' THEN 
      SET vlc_cari_dinding = '02';
   ELSEIF vlc_dinding = '3' THEN 
      SET vlc_cari_dinding = '03';
   ELSEIF vlc_dinding = '4' THEN 
      SET vlc_cari_dinding = '07';
   ELSEIF vlc_dinding = '5' THEN 
      SET vlc_cari_dinding = '08';
   ELSEIF vlc_dinding = '6' THEN 
      SET vlc_cari_dinding = null;
   END IF;
   BEGIN
      DECLARE EXIT HANDLER FOR NOT FOUND,SQLEXCEPTION
      begin
         SET vln_nilai_dinding = 0;
      end;
      SELECT IFNULL(nilai_dbkb_material,0)
      INTO   vln_nilai_dinding
      FROM   dbkb_material
      WHERE  kd_propinsi       = vlc_kd_propinsi
      AND  kd_dati2          = vlc_kd_dati2
      AND  thn_dbkb_material = vlc_tahun
      AND  kd_pekerjaan      = '21'
      AND  kd_kegiatan       = vlc_cari_dinding;
   END;
   SET vln_total_nilai_dinding =(vln_keliling_dinding*vln_tinggi_kolom*(10/6)*vln_nilai_dinding);
   BEGIN
      DECLARE EXIT HANDLER FOR NOT FOUND,SQLEXCEPTION
      begin
         SET vln_nilai_mezzanine = 0;
      end;
      SELECT IFNULL(nilai_dbkb_mezanin,0)
      INTO   vln_nilai_mezzanine
      FROM   dbkb_mezanin
      WHERE  kd_propinsi      = vlc_kd_propinsi
      AND  kd_dati2         = vlc_kd_dati2
      AND  thn_dbkb_mezanin = vlc_tahun;
   END;
   SET vln_nilai_total_mezzanine = vln_luas_mezzanine*vln_nilai_mezzanine;
   SET vln_nilai_fasilitas_susut = 0;
   CALL FASILITAS_SUSUT(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
   vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vln_jml_lantai_bng,vlc_tahun,
   vln_nilai_fasilitas_susut);
   SET vln_nilai_sebelum_susut = vln_nilai_total_kali_luas+vln_total_nilai_dinding+vln_nilai_total_mezzanine+vln_nilai_fasilitas_susut;
   SET vln_persentase_penyusutan = SUSUT(vlc_tahun,vlc_tahun_dibangun,vlc_tahun_renovasi,vlc_kondisi_bng,vln_nilai_sebelum_susut,
   vln_luas_bng,0);
   IF (vln_persentase_penyusutan IS NOT NULL) OR (vln_persentase_penyusutan = 0)  THEN
      SET vln_persentase_penyusutan  = round((vln_persentase_penyusutan/100),2);
      SET vln_nilai_setelah_susut    = vln_nilai_sebelum_susut -(vln_nilai_sebelum_susut*vln_persentase_penyusutan);
ELSE
      SET vln_nilai_setelah_susut    = vln_nilai_sebelum_susut;
   END IF;
   SET vln_nilai_fasilitas_tdk_susut = 0;
   CALL FASILITAS_TDK_SUSUT(vlc_kd_propinsi,vlc_kd_dati2,vlc_kd_kecamatan,vlc_kd_kelurahan,vlc_kd_blok,
   vlc_no_urut,vlc_kd_jns_op,vln_no_bng,vlc_tahun,vln_nilai_fasilitas_tdk_susut);
   SET vln_njop_jpb8 = vln_nilai_setelah_susut+vln_nilai_fasilitas_tdk_susut;
END;
--> statement-breakpoint

DROP PROCEDURE IF EXISTS `PENILAIAN_JPB9`;
--> statement-breakpoint
CREATE PROCEDURE `PENILAIAN_JPB9`(IN  vlc_kd_prop    CHAR(2),
IN  vlc_kd_dati2   CHAR(2),
IN  vlc_kd_kec 	  CHAR(3),
IN  vlc_kd_kel 	  CHAR(3),
IN  vlc_kd_blok 	  CHAR(3),
IN  vlc_no_urut 	  CHAR(4),
IN  vlc_kd_jns_op  CHAR(1),
IN  vln_no_bng 	  SMALLINT,
IN  vlc_tahun 	  CHAR(4),
OUT vln_nilai_jpb9 INT)
BEGIN
   DECLARE vlc_kls_jpb9 CHAR(1);
   DECLARE vln_nilai_dbkb_jpb9 DECIMAL(17,2) DEFAULT 0;
   DECLARE vlc_kd_jpb CHAR(2);
   DECLARE vln_luas_bng BIGINT;
   DECLARE vlc_kondisi_bng CHAR(1);
   DECLARE vln_jml_lantai_bng SMALLINT;
   DECLARE vln_komp_utama DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_fas1 DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_fas2 DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_fas3 DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai1 DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_sbl_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_stl_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE vlc_thn_dibangun CHAR(4);
   DECLARE vlc_thn_renovasi CHAR(4);
   DECLARE vln_besar_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_persen_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE EXIT HANDLER FOR NOT FOUND
   begin
      SET vln_nilai_jpb9 = 0;
   end;
/*OLEH : SUNARYO
TANGGAL     :
REVISI KE   : 1
DIREVISI    : TEGUH, RACHMAT
TGL. REVISI : 09-10-2000
*/-- ------------------
   SELECT kd_jpb,
luas_bng,
thn_dibangun_bng,
thn_renovasi_bng,
kondisi_bng,
jml_lantai_bng
   INTO   vlc_kd_jpb,vln_luas_bng,vlc_thn_dibangun,vlc_thn_renovasi,vlc_kondisi_bng,
   vln_jml_lantai_bng
   FROM   dat_op_bangunan
   WHERE  kd_propinsi   = vlc_kd_prop    AND
   kd_dati2 	    = vlc_kd_dati2   AND
   kd_kecamatan  = vlc_kd_kec     AND
   kd_kelurahan  = vlc_kd_kel     AND
   kd_blok 	    = vlc_kd_blok    AND
   no_urut 	    = vlc_no_urut    AND
   kd_jns_op  	= vlc_kd_jns_op  AND
   no_bng 		= vln_no_bng;
   IF ROW_COUNT() <> 0 THEN
      BEGIN
         DECLARE EXIT HANDLER FOR NOT FOUND,SQLEXCEPTION
         begin
            SET vlc_kls_jpb9 = null;
         end;
         SELECT kls_jpb9
         INTO   vlc_kls_jpb9
         FROM   dat_jpb9
         WHERE  kd_propinsi   = vlc_kd_prop    AND
         kd_dati2 	   = vlc_kd_dati2   AND
         kd_kecamatan  = vlc_kd_kec     AND
         kd_kelurahan  = vlc_kd_kel     AND
         kd_blok 	   = vlc_kd_blok    AND
         no_urut 	   = vlc_no_urut    AND
         kd_jns_op     = vlc_kd_jns_op  AND
         no_bng 	   = vln_no_bng;
      END;
      BEGIN
         DECLARE EXIT HANDLER FOR NOT FOUND,SQLEXCEPTION
         begin
            SET vln_nilai_dbkb_jpb9 = 0;
         end;
         SELECT nilai_dbkb_jpb9
         INTO   vln_nilai_dbkb_jpb9
         FROM   dbkb_jpb9
         WHERE  kd_propinsi      = vlc_kd_prop        AND
         kd_dati2         = vlc_kd_dati2 	   AND
         thn_dbkb_jpb9    = vlc_tahun 	  	   AND
         kls_dbkb_jpb9    = vlc_kls_jpb9       AND
         lantai_min_jpb9 <= vln_jml_lantai_bng AND
         lantai_max_jpb9 >= vln_jml_lantai_bng;
      END;
      SET vln_komp_utama = vln_nilai_dbkb_jpb9;
      CALL FASILITAS_SUSUT_X_LUAS(vlc_kd_prop,vlc_kd_dati2,vlc_kd_kec,vlc_kd_kel,vlc_kd_blok,vlc_no_urut,
      vlc_kd_jns_op,vln_no_bng,vlc_kd_jpb,vlc_kls_jpb9,vlc_tahun,vln_nilai_fas1);
      SET vln_nilai1 =(IFNULL(vln_komp_utama,0)+IFNULL(vln_nilai_fas1,0))*IFNULL(vln_luas_bng,0);
      CALL FASILITAS_SUSUT(vlc_kd_prop,vlc_kd_dati2,vlc_kd_kec,vlc_kd_kel,vlc_kd_blok,vlc_no_urut,
      vlc_kd_jns_op,vln_no_bng,vln_jml_lantai_bng,vlc_tahun,vln_nilai_fas2);
      SET vln_nilai_sbl_susut = IFNULL(vln_nilai1,0)+IFNULL(vln_nilai_fas2,0);
      SET vln_besar_susut = SUSUT(vlc_tahun,vlc_thn_dibangun,vlc_thn_renovasi,vlc_kondisi_bng,vln_nilai_sbl_susut,
      vln_luas_bng,0);
      IF (vln_besar_susut IS NOT NULL) OR (vln_besar_susut = 0) THEN
         SET vln_persen_susut    = round(vln_besar_susut/100,2);
         SET vln_nilai_stl_susut =(vln_nilai_sbl_susut -(vln_nilai_sbl_susut*vln_persen_susut));
   ELSE
         SET vln_nilai_stl_susut = vln_nilai_sbl_susut;
      END IF;
      CALL FASILITAS_TDK_SUSUT(vlc_kd_prop,vlc_kd_dati2,vlc_kd_kec,vlc_kd_kel,vlc_kd_blok,vlc_no_urut,
      vlc_kd_jns_op,vln_no_bng,vlc_tahun,vln_nilai_fas3);
      SET vln_nilai_jpb9 = vln_nilai_stl_susut+IFNULL(vln_nilai_fas3,0);
ELSE
      SET vln_nilai_jpb9 = 0;
   END IF;
 -- NULL;
END;
--> statement-breakpoint

DROP PROCEDURE IF EXISTS `PENILAIAN_STANDARD`;
--> statement-breakpoint
CREATE PROCEDURE `PENILAIAN_STANDARD`(IN `vlc_kd_prop` CHAR(2), IN `vlc_kd_dati2` CHAR(2), IN `vlc_kd_kec` CHAR(3), IN `vlc_kd_kel` CHAR(3), IN `vlc_kd_blok` CHAR(3), IN `vlc_no_urut` CHAR(4), IN `vlc_kd_jns_op` CHAR(1), IN `vln_no_bng` SMALLINT, IN `vlc_tahun` CHAR(4), OUT `vln_nilai_standard` INT)
BEGIN
   DECLARE vlc_kd_jpb CHAR(2);
   DECLARE vln_luas_bng BIGINT;
   DECLARE vlc_kondisi_bng CHAR(1);
   DECLARE vln_jml_lantai_bng SMALLINT;
   DECLARE vlc_jns_konstruksi_bng CHAR(1);
   DECLARE vln_komp_utama DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_komp_material DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_fasilitas_x_luas DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_fasilitas_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_fasilitas_tdk_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai1 DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_sbl_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_nilai_stl_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE vlc_thn_dibangun CHAR(4);
   DECLARE vlc_thn_renovasi CHAR(4);
   DECLARE vln_besar_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE vln_persen_susut DECIMAL(17,2) DEFAULT 0;
   DECLARE EXIT HANDLER FOR NOT FOUND
   begin
      SET vln_nilai_standard = 0;
   end;
/*OLEH : SUNARYO
TANGGAL     :
REVISI KE   : 2
DIREVISI    : TEGUH, RACHMAT, RUSLAN
TGL. REVISI : 05-10-2000
*/-- ------------------------
   SELECT kd_jpb,
luas_bng,
thn_dibangun_bng,
thn_renovasi_bng,
kondisi_bng,
jml_lantai_bng,
jns_konstruksi_bng
   INTO   vlc_kd_jpb,vln_luas_bng,vlc_thn_dibangun,vlc_thn_renovasi,vlc_kondisi_bng,
   vln_jml_lantai_bng,vlc_jns_konstruksi_bng
   FROM   dat_op_bangunan
   WHERE  kd_propinsi   = vlc_kd_prop   AND
   kd_dati2 	    = vlc_kd_dati2  AND
   kd_kecamatan  = vlc_kd_kec    AND
   kd_kelurahan  = vlc_kd_kel    AND
   kd_blok 		= vlc_kd_blok   AND
   no_urut 		= vlc_no_urut   AND
   kd_jns_op  	= vlc_kd_jns_op AND
   no_bng 		= vln_no_bng;
   IF ROW_COUNT() <> 0 THEN
      IF vlc_kd_jpb IN('01','10','11') THEN
         SET vlc_kd_jpb = '01';
      ELSEIF vlc_kd_jpb IN('02','04','07','09') THEN
         SET vlc_kd_jpb = '02';
      END IF;
      IF vlc_thn_renovasi IS NULL OR vlc_thn_renovasi = ' ' THEN
         SET vlc_thn_renovasi = '0';
      END IF;
      CALL KOMP_UTAMA_STD(vlc_kd_prop,vlc_kd_dati2,vlc_kd_kec,vlc_kd_kel,vlc_kd_blok,vlc_no_urut,
      vlc_kd_jns_op,vln_no_bng,vlc_tahun,vlc_kd_jpb,vln_luas_bng,vln_jml_lantai_bng,
      vlc_jns_konstruksi_bng,vln_komp_utama);
      CALL KOMP_MATERIAL(vlc_kd_prop,vlc_kd_dati2,vlc_kd_kec,vlc_kd_kel,vlc_kd_blok,vlc_no_urut,
      vlc_kd_jns_op,vln_no_bng,vlc_tahun,vln_komp_material);
      CALL FASILITAS_SUSUT_X_LUAS(vlc_kd_prop,vlc_kd_dati2,vlc_kd_kec,vlc_kd_kel,vlc_kd_blok,vlc_no_urut,
      vlc_kd_jns_op,vln_no_bng,vlc_kd_jpb,'0',vlc_tahun,vln_fasilitas_x_luas);
      SET vln_nilai1 =(IFNULL(vln_komp_utama,0)+IFNULL(vln_komp_material,0)+IFNULL(vln_fasilitas_x_luas,0))*IFNULL(vln_luas_bng,0);
      CALL FASILITAS_SUSUT(vlc_kd_prop,vlc_kd_dati2,vlc_kd_kec,vlc_kd_kel,vlc_kd_blok,vlc_no_urut,
      vlc_kd_jns_op,vln_no_bng,vln_jml_lantai_bng,vlc_tahun,vln_fasilitas_susut);
      SET vln_nilai_sbl_susut = vln_nilai1+IFNULL(vln_fasilitas_susut,0);
      SET vln_besar_susut = SUSUT(vlc_tahun,vlc_thn_dibangun,vlc_thn_renovasi,vlc_kondisi_bng,vln_nilai_sbl_susut,
      vln_luas_bng,1);
      IF vln_besar_susut IS NOT NULL OR vln_besar_susut = 0  THEN
         SET vln_persen_susut 	  = round((vln_besar_susut/100),2);
         SET vln_nilai_stl_susut =(vln_nilai_sbl_susut -(vln_nilai_sbl_susut*vln_persen_susut));
   ELSE
         SET vln_nilai_stl_susut = vln_nilai_sbl_susut;
      END IF;
      CALL FASILITAS_TDK_SUSUT(vlc_kd_prop,vlc_kd_dati2,vlc_kd_kec,vlc_kd_kel,vlc_kd_blok,vlc_no_urut,
      vlc_kd_jns_op,vln_no_bng,vlc_tahun,vln_fasilitas_tdk_susut);
      SET vln_nilai_standard = vln_nilai_stl_susut+IFNULL(vln_fasilitas_tdk_susut,0);
ELSE
      SET vln_nilai_standard = 0;
   END IF;
 -- null;
END;
--> statement-breakpoint

DROP PROCEDURE IF EXISTS `peta_info`;
--> statement-breakpoint
CREATE PROCEDURE `peta_info`(
	IN `NOP` CHAR(18)
)
BEGIN
SELECT * FROM (
SELECT 
	CONCAT(KD_PROPINSI, KD_DATI2, KD_KECAMATAN, KD_KELURAHAN, KD_BLOK, NO_URUT, KD_JNS_OP) AS NOP,
	IF(JNS_TRANSAKSI_OP = '1', 'Perekaman Data', IF(JNS_TRANSAKSI_OP = '2', 'Pemutakhiran Data', 'Penghapusan Data')) AS JNS_TRANSAKSI_OP, 
	LUAS_BUMI, 
	KD_ZNT, 
	IF(JNS_BUMI = '1', 'Tanah + Bangunan', IF(JNS_BUMI = '2', 'Kavling siap bangunn', IF(JNS_BUMI = '3', 'Tanah kosong', 'Fasilitas umum'))) AS JNS_BUMI,
	JALAN_OP, IF(KD_STATUS_WP = '1', 'Pemilik', IF(KD_STATUS_WP = '2', 'Penyewa', 
	IF(KD_STATUS_WP = '3', 'Pengelola', IF(KD_STATUS_WP = '4', 'Pemakai', 'Sengketa')))) AS KD_STATUS_WP, 
	KELAS_BUMI, 
	NJOP_BUMI * 1000 AS NJOP_BUMI, 
	IFNULL(NIT, 0) NIT, 
	NM_WP
FROM
spop LEFT JOIN
kelas_bumi ON (spop.NILAI_SISTEM_BUMI / spop.LUAS_BUMI BETWEEN kelas_bumi.NILAI_MINIMUM AND kelas_bumi.NILAI_MAKSIMUM) LEFT JOIN
dat_nit USING(KD_PROPINSI,KD_DATI2,KD_KECAMATAN,KD_KELURAHAN,KD_BLOK,NO_URUT,KD_JNS_OP) LEFT JOIN
dat_subjek_pajak USING(SUBJEK_PAJAK_ID)
WHERE 
(KD_PROPINSI LIKE CONCAT('%', SUBSTRING(NOP, 1, 2), '%')) AND 
(KD_DATI2 LIKE CONCAT('%', SUBSTRING(NOP, 3, 2), '%')) AND 
(KD_KECAMATAN LIKE CONCAT('%', SUBSTRING(NOP, 5, 3), '%')) AND 
(KD_KELURAHAN LIKE CONCAT('%', SUBSTRING(NOP, 8, 3), '%')) AND 
(KD_BLOK LIKE CONCAT('%', SUBSTRING(NOP, 11, 3), '%')) AND 
(NO_URUT LIKE CONCAT('%', SUBSTRING(NOP, 14, 4), '%')) AND 
(KD_JNS_OP LIKE CONCAT('%', SUBSTRING(NOP, 18, 1), '%'))
) AS t1;
END;
--> statement-breakpoint

DROP PROCEDURE IF EXISTS `rekap_pembayaran_sppt`;
--> statement-breakpoint
CREATE PROCEDURE `rekap_pembayaran_sppt`(
	IN `_KD_PROPINSI` VARCHAR(50),
	IN `_KD_DATI2` VARCHAR(50),
	IN `_KD_KECAMATAN` VARCHAR(50),
	IN `_KD_KELURAHAN` VARCHAR(50),
	IN `_KD_BLOK` VARCHAR(50),
	IN `_NO_URUT` VARCHAR(50),
	IN `_KD_JNS_OP` VARCHAR(50),
	IN `_THN_PAJAK_SPPT` VARCHAR(4),
	IN `_JENIS_SPPT` VARCHAR(50),
	IN `_TERHUTANG_MIN` BIGINT,
	IN `_TERHUTANG_MAX` BIGINT,
	IN `_INDEX` INT,
	IN `_TOTALPAGE` INT
)
BEGIN
SELECT sppt.KD_PROPINSI, sppt.KD_DATI2, sppt.KD_KECAMATAN, sppt.KD_KELURAHAN, sppt.KD_BLOK, sppt.NO_URUT, sppt.KD_JNS_OP, sppt.THN_PAJAK_SPPT, sppt.SIKLUS_SPPT, sppt.KD_KANWIL_BANK, 
 sppt.KD_KPPBB_BANK, sppt.KD_BANK_TUNGGAL, sppt.KD_BANK_PERSEPSI, sppt.KD_TP, sppt.NM_WP_SPPT, sppt.JLN_WP_SPPT, sppt.BLOK_KAV_NO_WP_SPPT, sppt.RW_WP_SPPT, sppt.RT_WP_SPPT, 
 sppt.KELURAHAN_WP_SPPT, sppt.KOTA_WP_SPPT, sppt.KD_POS_WP_SPPT, sppt.NPWP_SPPT, sppt.NO_PERSIL_SPPT, sppt.KD_KLS_TANAH, sppt.THN_AWAL_KLS_TANAH, sppt.KD_KLS_BNG, sppt.THN_AWAL_KLS_BNG, 
 sppt.TGL_JATUH_TEMPO_SPPT, sppt.LUAS_BUMI_SPPT, sppt.LUAS_BNG_SPPT, sppt.NJOP_BUMI_SPPT, sppt.NJOP_BNG_SPPT, sppt.NJOP_SPPT, sppt.NJOPTKP_SPPT, sppt.NJKP_SPPT, sppt.PBB_TERHUTANG_SPPT, 
 sppt.FAKTOR_PENGURANG_SPPT, sppt.PBB_YG_HARUS_DIBAYAR_SPPT, sppt.STATUS_PEMBAYARAN_SPPT, sppt.STATUS_TAGIHAN_SPPT, sppt.STATUS_CETAK_SPPT, sppt.TGL_TERBIT_SPPT, sppt.TGL_CETAK_SPPT, 
 sppt.NIP_PENCETAK_SPPT, pembayaran_sppt.TGL_PEMBAYARAN_SPPT TANGGAL_BAYAR, status_pbb.PERMOHONAN_PENGURANGAN, status_pbb.ALASAN_PENGURANGAN, status_pbb.ALASAN_KEBERATAN, spop.SUBJEK_PAJAK_ID, spop.JALAN_OP, 
 spop.BLOK_KAV_NO_OP, spop.KELURAHAN_OP, spop.RW_OP, spop.RT_OP, spop.NO_FORMULIR_SPOP, spop.KD_ZNT, lspop.KD_JPB, dat_legalitas_bumi.NO_LEGALITAS_TANAH, pembayaran_sppt.DENDA_SPPT, pembayaran_sppt.JML_SPPT_YG_DIBAYAR, bri_briva.ID BRIVA_ID,
 sppt_op_bersama.KD_KLS_TANAH KD_KLS_TANAH_BEBAN,
 sppt_op_bersama.LUAS_BUMI_BEBAN_SPPT,
 sppt_op_bersama.NJOP_BUMI_BEBAN_SPPT,
 sppt_op_bersama.KD_KLS_BNG KD_KLS_BNG_BEBAN,
 sppt_op_bersama.LUAS_BNG_BEBAN_SPPT,
 sppt_op_bersama.NJOP_BNG_BEBAN_SPPT
FROM sppt LEFT JOIN sppt_op_bersama USING(KD_PROPINSI, KD_DATI2, KD_KECAMATAN, KD_KELURAHAN, KD_BLOK, NO_URUT, KD_JNS_OP, THN_PAJAK_SPPT)
LEFT OUTER 
JOIN
 dat_legalitas_bumi ON dat_legalitas_bumi.KD_PROPINSI = sppt.KD_PROPINSI AND dat_legalitas_bumi.KD_DATI2 = sppt.KD_DATI2 AND dat_legalitas_bumi.KD_KECAMATAN = sppt.KD_KECAMATAN AND 
 dat_legalitas_bumi.KD_KELURAHAN = sppt.KD_KELURAHAN AND dat_legalitas_bumi.KD_BLOK = sppt.KD_BLOK AND dat_legalitas_bumi.NO_URUT = sppt.NO_URUT AND 
 dat_legalitas_bumi.KD_JNS_OP = sppt.KD_JNS_OP
LEFT OUTER
JOIN
 status_pbb ON sppt.KD_PROPINSI = status_pbb.KD_PROPINSI AND sppt.KD_DATI2 = status_pbb.KD_DATI2 AND sppt.KD_KECAMATAN = status_pbb.KD_KECAMATAN AND 
 sppt.KD_KELURAHAN = status_pbb.KD_KELURAHAN AND sppt.KD_BLOK = status_pbb.KD_BLOK AND sppt.NO_URUT = status_pbb.NO_URUT AND sppt.KD_JNS_OP = status_pbb.KD_JNS_OP AND 
 sppt.`THN_PAJAK_SPPT` = status_pbb.`TAHUN_PBB`
LEFT OUTER
JOIN
 spop ON sppt.KD_PROPINSI = spop.KD_PROPINSI AND sppt.KD_DATI2 = spop.KD_DATI2 AND sppt.KD_KECAMATAN = spop.KD_KECAMATAN AND sppt.KD_KELURAHAN = spop.KD_KELURAHAN AND 
 sppt.KD_BLOK = spop.KD_BLOK AND sppt.NO_URUT = spop.NO_URUT AND sppt.KD_JNS_OP = spop.KD_JNS_OP
LEFT OUTER
JOIN
 lspop ON sppt.`KD_PROPINSI` = lspop.`KD_PROPINSI` AND sppt.`KD_DATI2` = lspop.`KD_DATI2` AND sppt.`KD_KECAMATAN` = lspop.`KD_KECAMATAN` AND sppt.`KD_KELURAHAN` = lspop.`KD_KELURAHAN` AND 
 sppt.`KD_BLOK` = lspop.`KD_BLOK` AND sppt.`NO_URUT` = lspop.`NO_URUT` AND sppt.`KD_JNS_OP` = lspop.`KD_JNS_OP` AND lspop.`NO_BNG` = 1
LEFT OUTER
JOIN
 pembayaran_sppt  ON sppt.`KD_PROPINSI` = pembayaran_sppt.`KD_PROPINSI` AND sppt.`KD_DATI2` = pembayaran_sppt.`KD_DATI2` AND sppt.`KD_KECAMATAN` = pembayaran_sppt.`KD_KECAMATAN` AND sppt.`KD_KELURAHAN` = pembayaran_sppt.`KD_KELURAHAN` AND 
 sppt.`KD_BLOK` = pembayaran_sppt.`KD_BLOK` AND sppt.`NO_URUT` = pembayaran_sppt.`NO_URUT` AND sppt.`KD_JNS_OP` = pembayaran_sppt.`KD_JNS_OP` AND sppt.`THN_PAJAK_SPPT` = pembayaran_sppt.`THN_PAJAK_SPPT`
LEFT OUTER
JOIN
 bri_briva ON sppt.`KD_PROPINSI` = bri_briva.`KD_PROPINSI` AND sppt.`KD_DATI2` = bri_briva.`KD_DATI2` AND sppt.`KD_KECAMATAN` = bri_briva.`KD_KECAMATAN` AND sppt.`KD_KELURAHAN` = bri_briva.`KD_KELURAHAN` AND 
 sppt.`KD_BLOK` = bri_briva.`KD_BLOK` AND sppt.`NO_URUT` = bri_briva.`NO_URUT` AND sppt.`KD_JNS_OP` = bri_briva.`KD_JNS_OP` AND sppt.`THN_PAJAK_SPPT` = bri_briva.`THN_PAJAK_SPPT`
LEFT OUTER
JOIN
 sppt_khusus  ON sppt.`KD_PROPINSI` = sppt_khusus.`KD_PROPINSI` AND sppt.`KD_DATI2` = sppt_khusus.`KD_DATI2` AND sppt.`KD_KECAMATAN` = sppt_khusus.`KD_KECAMATAN` AND sppt.`KD_KELURAHAN` = sppt_khusus.`KD_KELURAHAN` AND 
 sppt.`KD_BLOK` = sppt_khusus.`KD_BLOK` AND sppt.`NO_URUT` = sppt_khusus.`NO_URUT` AND sppt.`KD_JNS_OP` = sppt_khusus.`KD_JNS_OP`
WHERE        
(sppt.KD_PROPINSI = _KD_PROPINSI) AND 
(sppt.KD_DATI2 = _KD_DATI2) AND 
(sppt.KD_KECAMATAN = _KD_KECAMATAN) AND 
(sppt.KD_KELURAHAN = _KD_KELURAHAN) AND 
(sppt.KD_BLOK LIKE CONCAT('%',_KD_BLOK,'%')) AND 
(sppt.NO_URUT LIKE CONCAT('%',_NO_URUT,'%')) AND 
(sppt.KD_JNS_OP LIKE CONCAT('%',_KD_JNS_OP,'%')) AND 
(sppt.THN_PAJAK_SPPT = _THN_PAJAK_SPPT) AND 
(LOCATE(IFNULL(sppt_khusus.JENIS_SPPT, '3'), IFNULL(_JENIS_SPPT, '')) > 0) AND
(sppt.PBB_TERHUTANG_SPPT BETWEEN IF(IFNULL(_TERHUTANG_MIN,0) <= 0, -999999999999, _TERHUTANG_MIN) AND IFNULL(_TERHUTANG_MAX, 999999999999))
ORDER BY sppt.KD_PROPINSI, sppt.KD_DATI2, sppt.KD_KECAMATAN, sppt.KD_KELURAHAN, sppt.KD_BLOK, sppt.NO_URUT, sppt.KD_JNS_OP LIMIT _INDEX, _TOTALPAGE;
END;
--> statement-breakpoint

DROP PROCEDURE IF EXISTS `rekap_tunggakan`;
--> statement-breakpoint
CREATE PROCEDURE `rekap_tunggakan`(IN `valKD_PROPINSI` VARCHAR(2), IN `valKD_DATI2` VARCHAR(2), IN `valKD_KECAMATAN` VARCHAR(3), IN `valKD_KELURAHAN` VARCHAR(3), IN `valTHN_PAJAK_SPPT_START` VARCHAR(4), IN `valTHN_PAJAK_SPPT_END` VARCHAR(4))
BEGIN
SELECT 
  spop.JALAN_OP,
  spop.BLOK_KAV_NO_OP,
  spop.RT_OP,
  spop.RW_OP,
  sppt.KD_PROPINSI,
  sppt.KD_DATI2,
  sppt.KD_KECAMATAN,
  sppt.KD_KELURAHAN,
  sppt.KD_BLOK,
  sppt.NO_URUT,
  sppt.KD_JNS_OP,
  sppt.THN_PAJAK_SPPT,
  sppt.NM_WP_SPPT,
  sppt.JLN_WP_SPPT,
  sppt.BLOK_KAV_NO_WP_SPPT,
  sppt.RW_WP_SPPT,
  sppt.RT_WP_SPPT,
  sppt.KELURAHAN_WP_SPPT,
  sppt.KOTA_WP_SPPT,
  sppt.KD_POS_WP_SPPT,
  sppt.PBB_YG_HARUS_DIBAYAR_SPPT AS PBB_YG_HARUS_DIBAYAR_SPPT,
  hitungDenda (
    sppt.PBB_YG_HARUS_DIBAYAR_SPPT,
    sppt.TGL_JATUH_TEMPO_SPPT
  ) AS DENDA,
  ref_kecamatan.NM_KECAMATAN,
  ref_kelurahan.NM_KELURAHAN,
  (PBB_YG_HARUS_DIBAYAR_SPPT + DENDA) AS TAGIHAN
FROM
  sppt 
  LEFT OUTER JOIN spop 
    ON sppt.KD_PROPINSI = spop.KD_PROPINSI 
    AND sppt.KD_DATI2 = spop.KD_DATI2 
    AND sppt.KD_KECAMATAN = spop.KD_KECAMATAN 
    AND sppt.KD_KELURAHAN = spop.KD_KELURAHAN 
    AND sppt.KD_BLOK = spop.KD_BLOK 
    AND sppt.NO_URUT = spop.NO_URUT 
    AND sppt.KD_JNS_OP = spop.KD_JNS_OP 
  LEFT OUTER JOIN ref_kecamatan 
    ON sppt.KD_KECAMATAN = ref_kecamatan.KD_KECAMATAN 
  LEFT OUTER JOIN ref_kelurahan 
    ON sppt.KD_KECAMATAN = ref_kelurahan.KD_KECAMATAN 
    AND sppt.KD_KELURAHAN = ref_kelurahan.KD_KELURAHAN 
  LEFT OUTER JOIN pembayaran_sppt 
    ON sppt.KD_PROPINSI = pembayaran_sppt.KD_PROPINSI 
    AND sppt.KD_DATI2 = pembayaran_sppt.KD_DATI2 
    AND sppt.KD_KECAMATAN = pembayaran_sppt.KD_KECAMATAN 
    AND sppt.KD_KELURAHAN = pembayaran_sppt.KD_KELURAHAN 
    AND sppt.KD_BLOK = pembayaran_sppt.KD_BLOK 
    AND sppt.NO_URUT = pembayaran_sppt.NO_URUT 
    AND sppt.KD_JNS_OP = pembayaran_sppt.KD_JNS_OP 
    AND sppt.THN_PAJAK_SPPT = pembayaran_sppt.THN_PAJAK_SPPT 
WHERE (sppt.STATUS_PEMBAYARAN_SPPT = 0) 
  AND (sppt.KD_PROPINSI = valKD_PROPINSI) 
  AND (sppt.KD_DATI2 = valKD_DATI2) 
  AND (
    sppt.KD_KECAMATAN LIKE valKD_KECAMATAN
  ) 
  AND (
    sppt.KD_KELURAHAN LIKE valKD_KELURAHAN
  ) 
  AND (
    sppt.THN_PAJAK_SPPT BETWEEN valTHN_PAJAK_SPPT_START
    AND valTHN_PAJAK_SPPT_END
  ) 
GROUP BY sppt.KD_PROPINSI,
  sppt.KD_DATI2,
  sppt.KD_KECAMATAN,
  sppt.KD_KELURAHAN,
  sppt.KD_BLOK,
  sppt.NO_URUT,
  sppt.KD_JNS_OP,
  sppt.THN_PAJAK_SPPT
 ORDER BY sppt.KD_PROPINSI,
  sppt.KD_DATI2,
  sppt.KD_KECAMATAN,
  sppt.KD_KELURAHAN,
  sppt.KD_BLOK,
  sppt.NO_URUT,
  sppt.KD_JNS_OP,
  sppt.THN_PAJAK_SPPT;
END;
--> statement-breakpoint

DROP PROCEDURE IF EXISTS `SPPTWithLimit`;
--> statement-breakpoint
CREATE PROCEDURE `SPPTWithLimit`(IN KD_PROPINSI VARCHAR(2),IN KD_DATI2 VARCHAR(2),IN KD_KECAMATAN VARCHAR(3),IN KD_KELURAHAN VARCHAR(3),IN THN_PAJAK_SPPT VARCHAR(4),IN STATUS_PEMBAYARAN_SPPT VARCHAR(1),IN TERHUTANG_MIN INT,IN TERHUTANG_MAX INT,IN ROWSTART INT,IN ROWCOUNT INT)
BEGIN
SELECT                   sppt.KD_PROPINSI, sppt.KD_DATI2, sppt.KD_KECAMATAN, sppt.KD_KELURAHAN, sppt.KD_BLOK, sppt.NO_URUT, sppt.KD_JNS_OP, sppt.THN_PAJAK_SPPT, 
                         sppt.SIKLUS_SPPT, sppt.KD_KANWIL_BANK, sppt.KD_KPPBB_BANK, sppt.KD_BANK_TUNGGAL, sppt.KD_BANK_PERSEPSI, sppt.KD_TP, sppt.NM_WP_SPPT, 
                         sppt.JLN_WP_SPPT, sppt.BLOK_KAV_NO_WP_SPPT, sppt.RW_WP_SPPT, sppt.RT_WP_SPPT, sppt.KELURAHAN_WP_SPPT, sppt.KOTA_WP_SPPT, 
                         sppt.KD_POS_WP_SPPT, sppt.NPWP_SPPT, sppt.NO_PERSIL_SPPT, sppt.KD_KLS_TANAH, sppt.THN_AWAL_KLS_TANAH, sppt.KD_KLS_BNG, 
                         sppt.THN_AWAL_KLS_BNG, sppt.TGL_JATUH_TEMPO_SPPT, sppt.LUAS_BUMI_SPPT, sppt.LUAS_BNG_SPPT, sppt.NJOP_BUMI_SPPT, sppt.NJOP_BNG_SPPT, 
                         sppt.NJOP_SPPT, sppt.NJOPTKP_SPPT, sppt.NJKP_SPPT, sppt.PBB_TERHUTANG_SPPT, sppt.FAKTOR_PENGURANG_SPPT, 
                         sppt.PBB_YG_HARUS_DIBAYAR_SPPT, sppt.STATUS_PEMBAYARAN_SPPT, sppt.STATUS_TAGIHAN_SPPT, sppt.STATUS_CETAK_SPPT, sppt.TGL_TERBIT_SPPT, 
                         sppt.TGL_CETAK_SPPT, sppt.NIP_PENCETAK_SPPT, status_pbb.TANGGAL_BAYAR, status_pbb.PERMOHONAN_PENGURANGAN, 
                         status_pbb.ALASAN_PENGURANGAN, status_pbb.ALASAN_KEBERATAN, spop.SUBJEK_PAJAK_ID, spop.JALAN_OP, spop.BLOK_KAV_NO_OP, spop.KELURAHAN_OP, 
                         spop.RW_OP, spop.RT_OP
FROM            sppt LEFT OUTER JOIN
                         status_pbb ON sppt.KD_PROPINSI = status_pbb.KD_PROPINSI AND sppt.KD_DATI2 = status_pbb.KD_DATI2 AND 
                         sppt.KD_KECAMATAN = status_pbb.KD_KECAMATAN AND sppt.KD_KELURAHAN = status_pbb.KD_KELURAHAN AND sppt.KD_BLOK = status_pbb.KD_BLOK AND 
                         sppt.NO_URUT = status_pbb.NO_URUT AND sppt.KD_JNS_OP = status_pbb.KD_JNS_OP LEFT OUTER JOIN
                         spop ON sppt.KD_PROPINSI = spop.KD_PROPINSI AND sppt.KD_DATI2 = spop.KD_DATI2 AND sppt.KD_KECAMATAN = spop.KD_KECAMATAN AND 
                         sppt.KD_KELURAHAN = spop.KD_KELURAHAN AND sppt.KD_BLOK = spop.KD_BLOK AND sppt.NO_URUT = spop.NO_URUT AND 
                         sppt.KD_JNS_OP = spop.KD_JNS_OP
WHERE        (sppt.KD_PROPINSI = KD_PROPINSI) AND (sppt.KD_DATI2 = KD_DATI2) AND (sppt.KD_KECAMATAN = KD_KECAMATAN) AND 
                         (sppt.KD_KELURAHAN = KD_KELURAHAN) AND (sppt.THN_PAJAK_SPPT = THN_PAJAK_SPPT) AND 
                         (sppt.STATUS_PEMBAYARAN_SPPT = STATUS_PEMBAYARAN_SPPT) AND (sppt.PBB_TERHUTANG_SPPT BETWEEN TERHUTANG_MIN AND 
                         TERHUTANG_MAX) LIMIT ROWSTART, ROWCOUNT;
END;
--> statement-breakpoint

DROP PROCEDURE IF EXISTS `totalKurangBayar`;
--> statement-breakpoint
CREATE PROCEDURE `totalKurangBayar`(IN NOP VARCHAR(18),IN THN_AWAL YEAR,IN THN_AKHIR YEAR)
BEGIN
	SELECT 
	  SUM(KURANG_BAYAR) AS POKOK,
	  SUM(DENDA) AS DENDA 
	FROM
	  (SELECT 
	    sppt.PBB_YG_HARUS_DIBAYAR_SPPT - SUM(
	      IFNULL(
		pembayaran_sppt.JML_SPPT_YG_DIBAYAR,
		0
	      ) - IFNULL(pembayaran_sppt.DENDA_SPPT, 0)
	    ) AS KURANG_BAYAR,
	    hitungDenda (
	      sppt.PBB_YG_HARUS_DIBAYAR_SPPT - SUM(
		IFNULL(
		  pembayaran_sppt.JML_SPPT_YG_DIBAYAR,
		  0
		) - IFNULL(pembayaran_sppt.DENDA_SPPT, 0)
	      ),
	      sppt.TGL_JATUH_TEMPO_SPPT
	    ) AS DENDA 
	  FROM
	    sppt 
	    LEFT OUTER JOIN pembayaran_sppt 
	      ON sppt.KD_PROPINSI = pembayaran_sppt.KD_PROPINSI 
	      AND sppt.KD_DATI2 = pembayaran_sppt.KD_DATI2 
	      AND sppt.KD_KECAMATAN = pembayaran_sppt.KD_KECAMATAN 
	      AND sppt.KD_KELURAHAN = pembayaran_sppt.KD_KELURAHAN 
	      AND sppt.KD_BLOK = pembayaran_sppt.KD_BLOK 
	      AND sppt.NO_URUT = pembayaran_sppt.NO_URUT 
	      AND sppt.KD_JNS_OP = pembayaran_sppt.KD_JNS_OP 
	      AND sppt.THN_PAJAK_SPPT = pembayaran_sppt.THN_PAJAK_SPPT 
	  WHERE (
	      sppt.KD_PROPINSI = SUBSTRING(NOP, 1, 2)
	    ) 
	    AND (
	      sppt.KD_DATI2 = SUBSTRING(NOP, 3, 2)
	    ) 
	    AND (
	      sppt.KD_KECAMATAN = SUBSTRING(NOP, 5, 3)
	    ) 
	    AND (
	      sppt.KD_KELURAHAN = SUBSTRING(NOP, 8, 3)
	    ) 
	    AND (
	      sppt.KD_BLOK = SUBSTRING(NOP, 11, 3)
	    ) 
	    AND (
	      sppt.NO_URUT = SUBSTRING(NOP, 14, 4)
	    ) 
	    AND (
	      sppt.KD_JNS_OP = SUBSTRING(NOP, 18, 1)
	    ) 
	    AND (
	      sppt.THN_PAJAK_SPPT BETWEEN THN_AWAL 
	      AND THN_AKHIR
	    ) 
	    AND sppt.`STATUS_PEMBAYARAN_SPPT` = 0 
	  GROUP BY sppt.`KD_PROPINSI`,
	    sppt.`KD_DATI2`,
	    sppt.`KD_KECAMATAN`,
	    sppt.`KD_KELURAHAN`,
	    sppt.`KD_BLOK`,
	    sppt.`NO_URUT`,
	    sppt.`KD_JNS_OP`,
	    sppt.`THN_PAJAK_SPPT`) AS a ;
    END;
--> statement-breakpoint

DROP PROCEDURE IF EXISTS `tunggakan`;
--> statement-breakpoint
CREATE PROCEDURE `tunggakan`(IN `NOP` VARCHAR(18))
BEGIN
SELECT 
CONCAT(KD_PROPINSI,'.',KD_DATI2,'.',KD_KECAMATAN,'.',KD_KELURAHAN,'.',KD_BLOK,'.',NO_URUT,'-',KD_JNS_OP) AS NOP,
pembayaran_sppt.THN_PAJAK_SPPT,
TGL_JATUH_TEMPO_SPPT,
NM_WP_SPPT,
LUAS_BUMI_SPPT,
NJOP_BUMI_SPPT,LUAS_BNG_SPPT,NJOP_BNG_SPPT
DENDA_SPPT,
JML_SPPT_YG_DIBAYAR,
JML_SPPT_YG_DIBAYAR,
TGL_PEMBAYARAN_SPPT
FROM pembayaran_sppt LEFT JOIN sppt
using(KD_PROPINSI,KD_DATI2,KD_KECAMATAN,KD_KELURAHAN,KD_BLOK,NO_URUT,KD_JNS_OP,THN_PAJAK_SPPT)
WHERE 
		(KD_PROPINSI LIKE CONCAT('%', SUBSTRING(NOP, 1, 2), '%')) AND 
		(KD_DATI2 LIKE CONCAT('%', SUBSTRING(NOP, 3, 2), '%')) AND 
		(KD_KECAMATAN LIKE CONCAT('%', SUBSTRING(NOP, 5, 3), '%')) AND 
		(KD_KELURAHAN LIKE CONCAT('%', SUBSTRING(NOP, 8, 3), '%')) AND 
		(KD_BLOK LIKE CONCAT('%', SUBSTRING(NOP, 11, 3), '%')) AND 
		(NO_URUT LIKE CONCAT('%', SUBSTRING(NOP, 14, 4), '%')) AND 
		(KD_JNS_OP LIKE CONCAT('%', SUBSTRING(NOP, 18, 1), '%'))
ORDER BY THN_PAJAK_SPPT ASC;
END;
--> statement-breakpoint

DROP PROCEDURE IF EXISTS `updatePenghapusanNOP`;
--> statement-breakpoint
CREATE PROCEDURE `updatePenghapusanNOP`()
BEGIN
		DECLARE a VARCHAR(255);
		DECLARE _output TEXT DEFAULT '';
		
		DECLARE done INT DEFAULT FALSE;
		DECLARE cur1 CURSOR FOR SELECT nop FROM temp_sppt_nop_dihapuskan_desember_2022;
		
		DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
		
		OPEN cur1;
		
		read_loop: LOOP
		
			FETCH cur1 INTO a;
			
			IF done THEN
				LEAVE read_loop;
			END IF;	
			
			UPDATE sppt SET 
				STATUS_PEMBAYARAN_SPPT='5'
			WHERE STATUS_PEMBAYARAN_SPPT='0'
			AND KD_PROPINSI=SUBSTRING(a, 1, 2)
			AND KD_DATI2=SUBSTRING(a, 3, 2)
			AND KD_KECAMATAN=SUBSTRING(a, 5, 3)
			AND KD_KELURAHAN=SUBSTRING(a, 8, 3)
			AND KD_BLOK=SUBSTRING(a, 11, 3)
			AND NO_URUT=SUBSTRING(a, 14, 4)
			AND KD_JNS_OP=SUBSTRING(a, 18, 1);

		END LOOP;
		
		CLOSE cur1;
	END;
--> statement-breakpoint

DROP PROCEDURE IF EXISTS `update_database`;
--> statement-breakpoint
CREATE PROCEDURE `update_database`()
BEGIN
DECLARE VERSI INT(11); 
/* VERSI 1 */
IF (SELECT NILAI FROM konfigurasi WHERE NAMA='VERSI') IS NULL THEN
	INSERT INTO konfigurasi VALUES('VERSI', 1);
	
	CREATE TABLE IF NOT EXISTS `akses` (
	  `AKSES` varchar(50) NOT NULL,
	  `AKTIF` tinyint(1) DEFAULT '0',
	  PRIMARY KEY (`AKSES`)
