	ALTER TABLE `group`
		DROP COLUMN `OBJEK_PAJAK`,
		DROP COLUMN `LAYANAN`,
		DROP COLUMN `PEMBAYARAN`,
		DROP COLUMN `CETAK`,
		DROP COLUMN `LAPORAN`,
		DROP COLUMN `DATA_REFERENSI`,
		DROP COLUMN `BUMI`,
		DROP COLUMN `PEMBARUAN_DATA`,
		DROP COLUMN `AKSES`,
		DROP COLUMN `INFO_OP`;
		
	ALTER TABLE `group`
		ADD COLUMN `KETERANGAN` VARCHAR(50) NULL AFTER `HAK_AKSES`;
	
	CREATE TABLE `group_akses` (
		`HAK_AKSES` VARCHAR(20) NOT NULL,
		`AKSES` VARCHAR(50) NOT NULL,
		PRIMARY KEY (`HAK_AKSES`, `AKSES`)
	)
	COLLATE='utf8_general_ci'
	ENGINE=MyISAM;
	
	UPDATE konfigurasi SET NILAI = 1 WHERE NAMA='VERSI';
END IF;
END;
