DROP PROCEDURE IF EXISTS `update_masal_bangunan`;
--> statement-breakpoint
CREATE PROCEDURE `update_masal_bangunan`(IN `RG` DOUBLE, IN `NIP` VARCHAR(30), IN `NAMA` VARCHAR(200))
BEGIN
IF (SELECT MAX(`TAHUN`) FROM `dat_material_bangunan`) < YEAR(CURDATE()) THEN
	START TRANSACTION;
		INSERT INTO dat_material_bangunan
			(SELECT ref_material_bangunan.`KODE_MATERIAL`, YEAR(CURDATE()), ROUND(`HARGA` * ((100 + 5)/100)) 
			FROM `ref_material_bangunan` JOIN dat_material_bangunan
			ON ref_material_bangunan.KODE_MATERIAL = dat_material_bangunan.KODE_MATERIAL
			WHERE TAHUN=(SELECT MAX(TAHUN) FROM dat_material_bangunan));
		UPDATE ref_kategori SET NILAI = ROUND(NILAI * ((100 + RG)/100)) WHERE NILAI > 10;
		UPDATE ref_kategori_bersyarat SET NILAI = ROUND(NILAI * ((100 + RG)/100)) WHERE NILAI > 10;
		UPDATE fasilitas SET NILAI_FASILITAS = ROUND(NILAI_FASILITAS * ((100 + RG)/100)) WHERE NILAI_FASILITAS > 0;
		UPDATE lspop SET NILAI_FORMULA = NILAI_FORMULA * ((100 + RG)/100);
		INSERT INTO `riwayat_update_masal`(`NIP_PENDATA`, `NAMA_PENDATA`, `RG`, `JENIS_UPDATE`) 
			VALUES (NIP, NAMA, RG, 'BANGUNAN');
	COMMIT;
END IF;
END;
--> statement-breakpoint

DROP PROCEDURE IF EXISTS `update_masal_bumi`;
--> statement-breakpoint
CREATE PROCEDURE `update_masal_bumi`(IN `RG` DOUBLE, IN `NIP` VARCHAR(30), IN `NAMA` VARCHAR(200), IN `DAERAH` VARCHAR(13))
BEGIN
START TRANSACTION;
		UPDATE spop SET NILAI_SISTEM_BUMI = ROUND(NILAI_SISTEM_BUMI * ((100 + RG)/100))
		WHERE        
			(spop.KD_PROPINSI = SUBSTRING(DAERAH, 1, 2)) AND 
			(spop.KD_DATI2 = SUBSTRING(DAERAH, 3, 2)) AND 
			(spop.KD_KECAMATAN = SUBSTRING(DAERAH, 5, 3)) AND 
			(spop.KD_KELURAHAN = SUBSTRING(DAERAH, 8, 3));
		INSERT INTO `riwayat_update_masal`(`NIP_PENDATA`, `NAMA_PENDATA`, `RG`, `JENIS_UPDATE`) 
			VALUES (NIP, NAMA, RG, 'BUMI');
COMMIT;
END;
