DROP FUNCTION IF EXISTS `create_no_pelayanan`;
--> statement-breakpoint
CREATE FUNCTION `create_no_pelayanan`() RETURNS varchar(13) CHARSET latin1
    DETERMINISTIC
BEGIN
DECLARE NOPELAYANAN VARCHAR(13);
DECLARE TAHUN VARCHAR(13);
DECLARE COUNTER1 VARCHAR(4);
DECLARE COUNTER2 VARCHAR(3);
SELECT MAX(NO_PELAYANAN) FROM pelayanan INTO NOPELAYANAN;
SELECT SUBSTR(NOPELAYANAN,1,4), SUBSTR(NOPELAYANAN,6,9), SUBSTR(NOPELAYANAN,11,13) INTO TAHUN, COUNTER1, COUNTER2;
IF(YEAR(NOW()) = TAHUN) THEN
	SELECT IF(COUNTER2 < 200, COUNTER1, COUNTER1 + 1), IF(COUNTER2 < 200, COUNTER2 + 1, 1) INTO COUNTER1, COUNTER2;
ELSE
	SELECT YEAR(NOW()), 1, 1 INTO TAHUN, COUNTER1, COUNTER2;
END IF;
RETURN CONCAT(TAHUN, '.', LPAD(COUNTER1,4,0), '.', LPAD(COUNTER2,3,0));
END;
