		SET bulan_max = 15;	
	ELSE
		SET bulan_max = 24;	
	END IF;
	
	-- Tentukan nilai denda berdasarkan KD_PROPINSI dan KD_DATI2
	IF DATEDIFF(tgl_bayar, tgl_jatuh_tempo) > 0 THEN
		IF (SELECT CONCAT(KD_PROPINSI, KD_DATI2) FROM ref_dati2) IN ('5102', '5171') AND YEAR(tgl_jatuh_tempo) >= 2024 THEN
			SET denda = 0.01;
		ELSE
			SET denda = 0.02;
		END IF;
	ELSE
		SET denda = 0;
	END IF;
	
	SELECT IF(selisih_bulan > bulan_max, bulan_max, selisih_bulan) INTO bulan_denda;	
	IF (denda * bulan_denda) * pbb < 0 THEN
	   RETURN 0;
	ELSE
      RETURN (denda * bulan_denda) * pbb;
	END IF;
END;
