DROP FUNCTION IF EXISTS `jumlah_sppt_dicetak`;
--> statement-breakpoint
CREATE FUNCTION `jumlah_sppt_dicetak`(`NOP` VARCHAR(18)) RETURNS bigint(20)
    DETERMINISTIC
BEGIN
RETURN
(SELECT COUNT(*) FROM
(SELECT dat_subjek_pajak.*, KD_PROPINSI, KD_DATI2, KD_KECAMATAN, KD_KELURAHAN, KD_BLOK, NO_URUT, KD_JNS_OP, LUAS_BUMI, NILAI_SISTEM_BUMI, LUAS_BNG, NILAI_SISTEM_BNG 
	FROM spop LEFT OUTER JOIN 
		dat_subjek_pajak USING(SUBJEK_PAJAK_ID) LEFT OUTER JOIN
		(SELECT KD_PROPINSI, KD_DATI2, KD_KECAMATAN, KD_KELURAHAN, KD_BLOK, NO_URUT, KD_JNS_OP, SUM(lspop.LUAS_BNG) AS LUAS_BNG, SUM(lspop.NILAI_SISTEM_BNG) AS NILAI_SISTEM_BNG
			FROM lspop WHERE lspop.AKTIF = TRUE) sumlspop USING(KD_PROPINSI, KD_DATI2, KD_KECAMATAN, KD_KELURAHAN, KD_BLOK, NO_URUT, KD_JNS_OP) 
	WHERE JNS_TRANSAKSI_OP <> 3 AND 
		JNS_BUMI <> 4 AND
		(KD_PROPINSI LIKE CONCAT('%', SUBSTRING(NOP, 1, 2), '%')) AND 
		(KD_DATI2 LIKE CONCAT('%', SUBSTRING(NOP, 3, 2), '%')) AND 
		(KD_KECAMATAN LIKE CONCAT('%', SUBSTRING(NOP, 5, 3), '%')) AND 
		(KD_KELURAHAN LIKE CONCAT('%', SUBSTRING(NOP, 8, 3), '%')) AND 
		(KD_BLOK LIKE CONCAT('%', SUBSTRING(NOP, 11, 3), '%')) AND 
		(NO_URUT LIKE CONCAT('%', SUBSTRING(NOP, 14, 4), '%')) AND 
		(KD_JNS_OP LIKE CONCAT('%', SUBSTRING(NOP, 18, 1), '%'))
	GROUP BY KD_PROPINSI, KD_DATI2, KD_KECAMATAN, KD_KELURAHAN, KD_BLOK, NO_URUT, KD_JNS_OP) t);
END;
