DROP FUNCTION IF EXISTS `SUSUT`;
--> statement-breakpoint
CREATE FUNCTION `SUSUT`(vlc_tahun 	  	   VARCHAR(4000) ,
vlc_tahun_dibangun VARCHAR(4000) ,
vlc_tahun_renovasi VARCHAR(4000) ,
vlc_kondisi_bng    VARCHAR(4000) ,
vln_nilai 		   INT ,
vln_luas_bng 	   INT ,
vln_flag_standard  INT) RETURNS int(11)
    DETERMINISTIC
BEGIN
   DECLARE VLN_LUAS_BANGUNAN BIGINT;
   DECLARE vln_umur_efektif SMALLINT;
   DECLARE vln_biaya_pengganti_baru BIGINT;
   DECLARE vln_persentase_susut TINYINT;
   DECLARE vln_tahun SMALLINT DEFAULT IFNULL(CAST(vlc_tahun AS unsigned),0);
   DECLARE vln_tahun_dibangun SMALLINT DEFAULT IFNULL(CAST(vlc_tahun_dibangun AS unsigned),0);
   DECLARE vln_tahun_renovasi SMALLINT DEFAULT IFNULL(CAST(vlc_tahun_renovasi AS unsigned),0);
   DECLARE vlc_kd_range_penyusutan CHAR(1);
/*OLEH : MADE
TANGGAL     :
REVISI KE   : 2
DIREVISI    : TEGUH, RAHMAT, RUSLAN
TGL. REVISI : 19-10-2000
*/-- --------------
   IF vln_flag_standard = 0 THEN
      IF vln_tahun_dibangun > 0 THEN
         IF vln_tahun_renovasi > 0 THEN
            IF(vln_tahun -vln_tahun_renovasi) > 10 THEN
               SET vln_umur_efektif = ROUND(((vln_tahun -vln_tahun_dibangun)+(2*10))/3);
         ELSE
               SET vln_umur_efektif = ROUND(((vln_tahun -vln_tahun_dibangun)+(2*(vln_tahun -vln_tahun_renovasi)))/3);
            END IF;
      ELSE
            IF(vln_tahun -vln_tahun_dibangun) > 10 THEN
               SET vln_umur_efektif = ROUND(((vln_tahun -vln_tahun_dibangun)+(2*10))/3);
         ELSE
               SET vln_umur_efektif = vln_tahun -vln_tahun_dibangun;
            END IF;
         END IF;
   ELSE
         RETURN 0;
      END IF;
ELSE
      IF vln_tahun_renovasi > 0 THEN
         SET vln_umur_efektif = vln_tahun -vln_tahun_renovasi;
   ELSE
         SET vln_umur_efektif = vln_tahun -vln_tahun_dibangun;
      END IF;
   END IF;
   IF vln_umur_efektif > 40 THEN
      SET vln_umur_efektif = 40;
   END IF;
   IF vln_luas_bng = 0 THEN
      SET VLN_LUAS_BANGUNAN = 1;
ELSE
      SET VLN_LUAS_BANGUNAN = vln_luas_bng;
   END IF;
   SET vln_biaya_pengganti_baru =(IFNULL(vln_nilai,0)*1000)/VLN_LUAS_BANGUNAN;
   BEGIN
      DECLARE EXIT HANDLER FOR NOT FOUND,SQLEXCEPTION
      begin
         RETURN 0;
      end;
      SELECT kd_range_penyusutan
      INTO   vlc_kd_range_penyusutan
      FROM   range_penyusutan
      WHERE  nilai_min_penyusutan <  vln_biaya_pengganti_baru AND
      nilai_max_penyusutan >= vln_biaya_pengganti_baru;
   END;
   BEGIN
      DECLARE EXIT HANDLER FOR NOT FOUND,SQLEXCEPTION
      begin
         RETURN 0;
      end;
      SELECT IFNULL(nilai_penyusutan,0)
      INTO 	vln_persentase_susut
      FROM 	penyusutan
      WHERE  umur_efektif        = vln_umur_efektif        AND
      kd_range_penyusutan = vlc_kd_range_penyusutan AND
      kondisi_bng_susut   = vlc_kondisi_bng;
   END;
   RETURN vln_persentase_susut;
END;
