CREATE FUNCTION `test_hitung`(`vlc_kd_propinsi` CHAR(2), `vlc_kd_dati2` CHAR(2), `vlc_kd_kecamatan` CHAR(3), `vlc_kd_kelurahan` CHAR(3), `vlc_kd_blok` CHAR(3), `vlc_no_urut` CHAR(4), `vlc_kd_jns_op` CHAR(1), `vln_no_bng` SMALLINT, `vlc_kd_jpb` CHAR(2), `vln_luas_bng` BIGINT, `vln_jml_lantai_bng` SMALLINT, `vlc_tahun_pajak` CHAR(4)) RETURNS int(11)
    DETERMINISTIC
BEGIN
 DECLARE nilai INT default 0;
 CALL PENILAIAN_BNG( vlc_kd_propinsi, vlc_kd_dati2, vlc_kd_kecamatan, vlc_kd_kelurahan, vlc_kd_blok, vlc_no_urut, vlc_kd_jns_op, vln_no_bng, vlc_kd_jpb, vln_luas_bng, vln_jml_lantai_bng, vlc_tahun_pajak
 , '0', niai);
return nilai;
END;
